fn manual_rescan_origin_matches_probe_target(
    origin: &str,
    target_node_ids: &BTreeSet<String>,
) -> bool {
    target_node_ids.is_empty()
        || target_node_ids
            .iter()
            .any(|target| runtime_node_identity_matches(origin, target))
}

fn filter_manual_rescan_source_status_origin_snapshots_to_probe_targets(
    origin_snapshots: Vec<(String, SourceObservabilitySnapshot)>,
    target_node_ids: &BTreeSet<String>,
) -> Vec<(String, SourceObservabilitySnapshot)> {
    origin_snapshots
        .into_iter()
        .filter(|(origin, _)| manual_rescan_origin_matches_probe_target(origin, target_node_ids))
        .collect()
}

fn runtime_node_identity_matches_any_target(
    node_id: &str,
    target_node_ids: &BTreeSet<String>,
) -> bool {
    target_node_ids
        .iter()
        .any(|target_node_id| runtime_node_identity_matches(node_id, target_node_id))
}

fn source_object_ref_matches_any_target_node(
    object_ref: &str,
    grants: &[GrantedMountRoot],
    target_node_ids: &BTreeSet<String>,
) -> bool {
    source_primary_runtime_node_id_from_ref(object_ref, grants).is_some_and(|primary_node_id| {
        runtime_node_identity_matches_any_target(&primary_node_id, target_node_ids)
    })
}

fn retain_node_keyed_source_map_to_targets<T>(
    map: &mut BTreeMap<String, T>,
    target_node_ids: &BTreeSet<String>,
) {
    map.retain(|node_id, _| runtime_node_identity_matches_any_target(node_id, target_node_ids));
}

fn retain_manual_rescan_source_snapshot_to_probe_targets(
    snapshot: &mut SourceObservabilitySnapshot,
    target_node_ids: &BTreeSet<String>,
) {
    if target_node_ids.is_empty() {
        return;
    }
    let grants = snapshot.grants.clone();
    snapshot.status.concrete_roots.retain(|root| {
        source_object_ref_matches_any_target_node(&root.object_ref, &grants, target_node_ids)
    });
    snapshot.source_primary_by_group.retain(|_, object_ref| {
        source_object_ref_matches_any_target_node(object_ref, &grants, target_node_ids)
    });
    retain_node_keyed_source_map_to_targets(
        &mut snapshot.scheduled_source_groups_by_node,
        target_node_ids,
    );
    retain_node_keyed_source_map_to_targets(
        &mut snapshot.scheduled_scan_groups_by_node,
        target_node_ids,
    );
    retain_node_keyed_source_map_to_targets(
        &mut snapshot.last_control_frame_signals_by_node,
        target_node_ids,
    );
    retain_node_keyed_source_map_to_targets(
        &mut snapshot.published_batches_by_node,
        target_node_ids,
    );
    retain_node_keyed_source_map_to_targets(
        &mut snapshot.published_events_by_node,
        target_node_ids,
    );
    retain_node_keyed_source_map_to_targets(
        &mut snapshot.published_control_events_by_node,
        target_node_ids,
    );
    retain_node_keyed_source_map_to_targets(
        &mut snapshot.published_data_events_by_node,
        target_node_ids,
    );
    retain_node_keyed_source_map_to_targets(
        &mut snapshot.last_published_at_us_by_node,
        target_node_ids,
    );
    retain_node_keyed_source_map_to_targets(
        &mut snapshot.last_published_origins_by_node,
        target_node_ids,
    );
    retain_node_keyed_source_map_to_targets(
        &mut snapshot.published_origin_counts_by_node,
        target_node_ids,
    );
    retain_node_keyed_source_map_to_targets(
        &mut snapshot.enqueued_path_origin_counts_by_node,
        target_node_ids,
    );
    retain_node_keyed_source_map_to_targets(
        &mut snapshot.pending_path_origin_counts_by_node,
        target_node_ids,
    );
    retain_node_keyed_source_map_to_targets(
        &mut snapshot.yielded_path_origin_counts_by_node,
        target_node_ids,
    );
    retain_node_keyed_source_map_to_targets(
        &mut snapshot.summarized_path_origin_counts_by_node,
        target_node_ids,
    );
    retain_node_keyed_source_map_to_targets(
        &mut snapshot.published_path_origin_counts_by_node,
        target_node_ids,
    );
}

fn retain_accumulated_manual_rescan_source_status_to_probe_targets(
    accumulated: &mut BTreeMap<String, SourceObservabilitySnapshot>,
    target_node_ids: &BTreeSet<String>,
) {
    if target_node_ids.is_empty() {
        return;
    }
    for snapshot in accumulated.values_mut() {
        retain_manual_rescan_source_snapshot_to_probe_targets(snapshot, target_node_ids);
    }
}

fn manual_rescan_discovery_source_snapshot_from_origin_snapshots(
    roots: &[RootSpec],
    origin_snapshots: &[(String, SourceObservabilitySnapshot)],
) -> SourceObservabilitySnapshot {
    source_snapshot_without_stale_runtime_scope_generation(merge_source_observability_snapshots(
        origin_snapshots
            .iter()
            .map(|(_, snapshot)| {
                manual_rescan_project_source_snapshot_to_requested_roots(roots, snapshot.clone())
            })
            .collect(),
    ))
}

fn merge_manual_rescan_discovery_source_snapshot(
    roots: &[RootSpec],
    observed: &mut Option<SourceObservabilitySnapshot>,
    snapshot: SourceObservabilitySnapshot,
) {
    let snapshot = source_snapshot_without_stale_runtime_scope_generation(
        manual_rescan_project_source_snapshot_to_requested_roots(roots, snapshot),
    );
    *observed = Some(match observed.take() {
        Some(previous) => source_snapshot_without_stale_runtime_scope_generation(
            merge_source_observability_snapshots(vec![previous, snapshot]),
        ),
        None => snapshot,
    });
}

async fn collect_manual_rescan_source_status_origin_snapshots(
    boundary: std::sync::Arc<dyn ChannelIoSubset>,
    origin_id: NodeId,
    timeout: Duration,
    idle_after_first: Duration,
) -> Result<Vec<(String, SourceObservabilitySnapshot)>, CnxError> {
    let events = collect_internal_source_status_events(
        boundary,
        origin_id,
        timeout.min(MANUAL_RESCAN_SOURCE_STATUS_ROUTE_TIMEOUT),
        idle_after_first,
        &[
            execution_units::QUERY_RUNTIME_UNIT_ID,
            execution_units::QUERY_PEER_RUNTIME_UNIT_ID,
        ],
        manual_rescan_source_status_request_payload(),
        None,
        None,
    )
    .await?;
    events
        .into_iter()
        .map(|event| {
            let origin = event.metadata().origin_id.0.clone();
            let snapshot =
                rmp_serde::from_slice::<SourceObservabilitySnapshot>(event.payload_bytes())
                    .map_err(|err| {
                        CnxError::Internal(format!("decode source observability failed: {err}"))
                    })?;
            Ok::<_, CnxError>((origin, snapshot))
        })
        .collect()
}

async fn collect_node_scoped_manual_rescan_source_status_origin_snapshot(
    boundary: std::sync::Arc<dyn ChannelIoSubset>,
    origin_id: NodeId,
    timeout: Duration,
    node_id: &str,
) -> Result<Vec<(String, SourceObservabilitySnapshot)>, CnxError> {
    let requested_node_id = node_id.to_string();
    let attempt_timeout = scoped_manual_rescan_source_status_attempt_timeout(timeout);
    let adapter = exchange_host_adapter(
        boundary,
        origin_id,
        source_status_route_bindings_for(node_id),
    );
    let events = adapter
        .call_collect(
            ROUTE_TOKEN_FS_META_INTERNAL,
            METHOD_SOURCE_STATUS,
            manual_rescan_source_status_request_payload_with_live_probe_timeout(timeout),
            attempt_timeout,
            Duration::ZERO,
        )
        .await?;
    events
        .into_iter()
        .map(|event| {
            let snapshot =
                rmp_serde::from_slice::<SourceObservabilitySnapshot>(event.payload_bytes())
                    .map_err(|err| {
                        CnxError::Internal(format!("decode source observability failed: {err}"))
                    })?;
            Ok::<_, CnxError>((requested_node_id.clone(), snapshot))
        })
        .collect()
}

fn scoped_manual_rescan_source_status_attempt_timeout(remaining: Duration) -> Duration {
    remaining.min(MANUAL_RESCAN_SCOPED_SOURCE_STATUS_ATTEMPT_TIMEOUT)
}

fn manual_rescan_targeted_source_status_complete_after_events(
    target_node_ids: &BTreeSet<String>,
) -> Option<usize> {
    (!target_node_ids.is_empty()).then_some(target_node_ids.len())
}

async fn collect_node_scoped_status_source_observability_origin_snapshot(
    boundary: std::sync::Arc<dyn ChannelIoSubset>,
    origin_id: NodeId,
    timeout: Duration,
    node_id: &str,
) -> Result<Vec<(String, SourceObservabilitySnapshot)>, CnxError> {
    let adapter = exchange_host_adapter(
        boundary,
        origin_id,
        source_status_route_bindings_for(node_id),
    );
    let events = adapter
        .call_collect(
            ROUTE_TOKEN_FS_META_INTERNAL,
            METHOD_SOURCE_STATUS,
            current_owner_health_source_status_request_payload_with_live_probe_timeout(timeout),
            timeout,
            Duration::ZERO,
        )
        .await?;
    events
        .into_iter()
        .map(|event| {
            let origin = event.metadata().origin_id.0.clone();
            let snapshot =
                rmp_serde::from_slice::<SourceObservabilitySnapshot>(event.payload_bytes())
                    .map_err(|err| {
                        CnxError::Internal(format!("decode source observability failed: {err}"))
                    })?;
            Ok::<_, CnxError>((origin, snapshot))
        })
        .collect()
}

async fn collect_node_scoped_status_sink_snapshot(
    boundary: std::sync::Arc<dyn ChannelIoSubset>,
    origin_id: NodeId,
    timeout: Duration,
    node_id: &str,
) -> Result<SinkStatusSnapshot, CnxError> {
    let adapter =
        exchange_host_adapter(boundary, origin_id, sink_status_route_bindings_for(node_id));
    let events = adapter
        .call_collect(
            ROUTE_TOKEN_FS_META_INTERNAL,
            METHOD_SINK_STATUS,
            internal_status_request_payload_with_live_probe_timeout(timeout),
            timeout,
            STATUS_ROUTE_COLLECT_IDLE_GRACE.min(timeout),
        )
        .await?;
    let snapshots = events
        .into_iter()
        .map(|event| {
            rmp_serde::from_slice::<SinkStatusSnapshot>(event.payload_bytes()).map_err(|err| {
                CnxError::Internal(format!("decode sink status snapshot failed: {err}"))
            })
        })
        .collect::<Result<Vec<_>, _>>()?;
    Ok(merge_sink_status_snapshots(snapshots))
}

