async fn observe_local_source_with_budget<LocalObservation, LocalObservationFuture>(
    local_observation: &LocalObservation,
    budget: Option<Duration>,
) -> Option<SourceObservabilitySnapshot>
where
    LocalObservation: Fn(Option<Duration>) -> LocalObservationFuture,
    LocalObservationFuture: Future<Output = Option<SourceObservabilitySnapshot>>,
{
    let future = local_observation(budget);
    match budget {
        Some(budget) if budget.is_zero() => None,
        Some(budget) => tokio::time::timeout(budget, future).await.unwrap_or(None),
        None => future.await,
    }
}

async fn merge_roots_put_source_snapshot_with_local_observation<
    LocalObservation,
    LocalObservationFuture,
>(
    source_snapshot: SourceObservabilitySnapshot,
    local_observation: &LocalObservation,
    local_observation_budget: Option<Duration>,
) -> SourceObservabilitySnapshot
where
    LocalObservation: Fn(Option<Duration>) -> LocalObservationFuture,
    LocalObservationFuture: Future<Output = Option<SourceObservabilitySnapshot>>,
{
    let source_snapshot =
        source_snapshot_without_degraded_worker_runtime_scope_evidence(source_snapshot);
    match observe_local_source_with_budget(local_observation, local_observation_budget).await {
        Some(local_source) => merge_source_observability(
            local_source_snapshot_without_unavailable_worker_runtime_scope_evidence(local_source),
            source_snapshot,
        ),
        None => source_snapshot,
    }
}

fn source_snapshot_without_degraded_worker_runtime_scope_evidence(
    mut snapshot: SourceObservabilitySnapshot,
) -> SourceObservabilitySnapshot {
    if source_observability_snapshot_is_degraded_worker_cache(&snapshot) {
        snapshot.lifecycle_state = "unknown".to_string();
        snapshot.status.current_stream_generation = None;
        snapshot.status.logical_roots.clear();
        snapshot.status.concrete_roots.clear();
        snapshot.status.degraded_roots.retain(|(root_key, reason)| {
            !(root_key == "source-worker" && reason.starts_with("source worker"))
        });
        snapshot.source_primary_by_group.clear();
        snapshot.last_force_find_runner_by_group.clear();
        snapshot.force_find_inflight_groups.clear();
        snapshot.scheduled_source_groups_by_node.clear();
        snapshot.scheduled_scan_groups_by_node.clear();
        snapshot.last_control_frame_signals_by_node.clear();
        snapshot.published_batches_by_node.clear();
        snapshot.published_events_by_node.clear();
        snapshot.published_control_events_by_node.clear();
        snapshot.published_data_events_by_node.clear();
        snapshot.last_published_at_us_by_node.clear();
        snapshot.last_published_origins_by_node.clear();
        snapshot.published_origin_counts_by_node.clear();
        snapshot.published_path_capture_target = None;
        snapshot.enqueued_path_origin_counts_by_node.clear();
        snapshot.pending_path_origin_counts_by_node.clear();
        snapshot.yielded_path_origin_counts_by_node.clear();
        snapshot.summarized_path_origin_counts_by_node.clear();
        snapshot.published_path_origin_counts_by_node.clear();
        return snapshot;
    }
    source_snapshot_without_stale_runtime_scope_generation(snapshot)
}

fn local_source_snapshot_without_unavailable_worker_runtime_scope_evidence(
    snapshot: SourceObservabilitySnapshot,
) -> SourceObservabilitySnapshot {
    if source_observability_snapshot_is_degraded_worker_cache(&snapshot)
        && !degraded_worker_snapshot_has_current_source_scope_evidence(&snapshot)
    {
        source_snapshot_without_degraded_worker_runtime_scope_evidence(snapshot)
    } else {
        source_snapshot_without_stale_runtime_scope_generation(snapshot)
    }
}

fn degraded_worker_snapshot_has_current_source_scope_evidence(
    snapshot: &SourceObservabilitySnapshot,
) -> bool {
    !snapshot.logical_roots.is_empty()
        && !snapshot.scheduled_source_groups_by_node.is_empty()
        && !snapshot.scheduled_scan_groups_by_node.is_empty()
        && !snapshot.last_control_frame_signals_by_node.is_empty()
        && snapshot.status.logical_roots.iter().any(|root| {
            root.matched_grants > 0
                && root.active_members > 0
                && !root.status.starts_with("waiting_for_root:")
        })
}

fn source_snapshot_has_current_root_health_evidence(
    roots: &[RootSpec],
    snapshot: &SourceObservabilitySnapshot,
) -> bool {
    roots.iter().all(|root| {
        snapshot.status.logical_roots.iter().any(|health| {
            health.root_id == root.id
                && health.matched_grants > 0
                && health.active_members > 0
                && !health.status.starts_with("waiting_for_root:")
        })
    })
}

fn source_snapshot_declares_only_current_logical_roots(
    roots: &[RootSpec],
    snapshot: &SourceObservabilitySnapshot,
) -> bool {
    let expected_root_ids = roots
        .iter()
        .map(|root| root.id.clone())
        .collect::<BTreeSet<_>>();
    let declared_root_ids = snapshot
        .logical_roots
        .iter()
        .map(|root| root.id.clone())
        .collect::<BTreeSet<_>>();
    !declared_root_ids.is_empty()
        && declared_root_ids
            .iter()
            .all(|root_id| expected_root_ids.contains(root_id))
}

fn source_snapshot_without_stale_runtime_scope_generation(
    mut snapshot: SourceObservabilitySnapshot,
) -> SourceObservabilitySnapshot {
    let candidate_groups = source_runtime_scope_candidate_groups(&snapshot);
    let latest_generation_by_group =
        source_latest_control_generation_by_group(&snapshot, &candidate_groups);
    if latest_generation_by_group.is_empty() {
        return snapshot;
    }
    let generation_by_node_group =
        source_control_generation_by_node_group(&snapshot, &candidate_groups);
    retain_current_generation_runtime_scope_groups(
        &mut snapshot.scheduled_source_groups_by_node,
        &generation_by_node_group,
        &latest_generation_by_group,
    );
    retain_current_generation_runtime_scope_groups(
        &mut snapshot.scheduled_scan_groups_by_node,
        &generation_by_node_group,
        &latest_generation_by_group,
    );
    snapshot
}

fn source_runtime_scope_candidate_groups(source: &SourceObservabilitySnapshot) -> BTreeSet<String> {
    let mut groups = source
        .logical_roots
        .iter()
        .map(|root| root.id.clone())
        .collect::<BTreeSet<_>>();
    groups.extend(
        source
            .status
            .logical_roots
            .iter()
            .map(|root| root.root_id.clone()),
    );
    groups.extend(
        source
            .scheduled_source_groups_by_node
            .values()
            .flatten()
            .cloned(),
    );
    groups.extend(
        source
            .scheduled_scan_groups_by_node
            .values()
            .flatten()
            .cloned(),
    );
    groups
}

fn source_control_generation_by_node_group(
    source: &SourceObservabilitySnapshot,
    candidate_groups: &BTreeSet<String>,
) -> BTreeMap<(String, String), Option<u64>> {
    let mut node_ids = source
        .scheduled_source_groups_by_node
        .keys()
        .chain(source.scheduled_scan_groups_by_node.keys())
        .chain(source.last_control_frame_signals_by_node.keys())
        .cloned()
        .collect::<BTreeSet<_>>();
    let mut generation_by_node_group = BTreeMap::new();
    for node_id in std::mem::take(&mut node_ids) {
        for group_id in candidate_groups {
            generation_by_node_group.insert(
                (node_id.clone(), group_id.clone()),
                source_owner_scope_control_generation_for_group_node(source, group_id, &node_id),
            );
        }
    }
    generation_by_node_group
}

fn source_latest_control_generation_by_group(
    source: &SourceObservabilitySnapshot,
    candidate_groups: &BTreeSet<String>,
) -> BTreeMap<String, u64> {
    let mut latest_generation_by_group: BTreeMap<String, u64> = BTreeMap::new();
    for group_id in candidate_groups {
        for node_id in source_runtime_scope_nodes_for_group(source, group_id) {
            if let Some(generation) =
                source_owner_scope_control_generation_for_group_node(source, group_id, &node_id)
            {
                latest_generation_by_group
                    .entry(group_id.clone())
                    .and_modify(|latest| *latest = (*latest).max(generation))
                    .or_insert(generation);
            }
        }
    }
    latest_generation_by_group
}

fn retain_current_generation_runtime_scope_groups(
    groups_by_node: &mut BTreeMap<String, Vec<String>>,
    generation_by_node_group: &BTreeMap<(String, String), Option<u64>>,
    latest_generation_by_group: &BTreeMap<String, u64>,
) {
    groups_by_node.retain(|node_id, groups| {
        groups.retain(|group_id| match latest_generation_by_group.get(group_id) {
            Some(latest_generation) => generation_by_node_group
                .get(&(node_id.clone(), group_id.clone()))
                .copied()
                .flatten()
                .is_some_and(|generation| generation == *latest_generation),
            None => true,
        });
        !groups.is_empty()
    });
}

async fn local_source_runtime_scope_ready<LocalObservation, LocalObservationFuture>(
    roots: &[RootSpec],
    expected_groups: &RootsPutSecondWaveExpectedGroups,
    local_observation: &LocalObservation,
    local_observation_budget: Option<Duration>,
    requires_delivery_evidence: bool,
) -> Option<SourceObservabilitySnapshot>
where
    LocalObservation: Fn(Option<Duration>) -> LocalObservationFuture,
    LocalObservationFuture: Future<Output = Option<SourceObservabilitySnapshot>>,
{
    let source_snapshot = local_source_snapshot_without_unavailable_worker_runtime_scope_evidence(
        observe_local_source_with_budget(local_observation, local_observation_budget).await?,
    );
    if requires_delivery_evidence {
        manual_rescan_source_snapshot_ready_for_delivery(expected_groups, roots, &source_snapshot)
            .then_some(source_snapshot)
    } else {
        roots_put_second_wave_source_runtime_scope_ready(expected_groups, &source_snapshot)
            .then_some(source_snapshot)
    }
}

async fn wait_roots_put_second_wave_readiness_with_optional_local_source<
    LocalFastObservation,
    LocalFastObservationFuture,
    LocalMergeObservation,
    LocalMergeObservationFuture,
>(
    context: &RootsPutSecondWaveFollowupContext,
    roots: &[RootSpec],
    initial_target_node_ids: BTreeSet<String>,
    require_sink_scope: bool,
    local_fast_observation: LocalFastObservation,
    local_merge_observation: LocalMergeObservation,
    control_replay_policy: RootsPutControlReplayPolicy,
    source_status_payload: bytes::Bytes,
    local_fast_observation_covers_current_roots: bool,
) -> Result<Option<SourceObservabilitySnapshot>, ApiError>
where
    LocalFastObservation: Fn(Option<Duration>) -> LocalFastObservationFuture,
    LocalFastObservationFuture: Future<Output = Option<SourceObservabilitySnapshot>>,
    LocalMergeObservation: Fn(Option<Duration>) -> LocalMergeObservationFuture,
    LocalMergeObservationFuture: Future<Output = Option<SourceObservabilitySnapshot>>,
{
    let source_status_probe_seed_node_ids = initial_target_node_ids.clone();
    wait_roots_put_second_wave_readiness_evidence_with_optional_local_source(
        context,
        roots,
        initial_target_node_ids,
        source_status_probe_seed_node_ids,
        false,
        require_sink_scope,
        local_fast_observation,
        local_merge_observation,
        control_replay_policy,
        source_status_payload,
        local_fast_observation_covers_current_roots,
    )
    .await
    .map(|readiness| readiness.map(|readiness| readiness.source_snapshot))
}

async fn wait_roots_put_second_wave_readiness_evidence_with_optional_local_source<
    LocalFastObservation,
    LocalFastObservationFuture,
    LocalMergeObservation,
    LocalMergeObservationFuture,
>(
    context: &RootsPutSecondWaveFollowupContext,
    roots: &[RootSpec],
    initial_target_node_ids: BTreeSet<String>,
    source_status_probe_seed_node_ids: BTreeSet<String>,
    source_status_probe_seed_is_discovery: bool,
    require_sink_scope: bool,
    local_fast_observation: LocalFastObservation,
    local_merge_observation: LocalMergeObservation,
    control_replay_policy: RootsPutControlReplayPolicy,
    source_status_payload: bytes::Bytes,
    _local_fast_observation_covers_current_roots: bool,
) -> Result<Option<SourceRuntimeScopeReadinessEvidence>, ApiError>
where
    LocalFastObservation: Fn(Option<Duration>) -> LocalFastObservationFuture,
    LocalFastObservationFuture: Future<Output = Option<SourceObservabilitySnapshot>>,
    LocalMergeObservation: Fn(Option<Duration>) -> LocalMergeObservationFuture,
    LocalMergeObservationFuture: Future<Output = Option<SourceObservabilitySnapshot>>,
{
    let Some(boundary) = context
        .query_runtime_boundary
        .clone()
        .or_else(|| context.runtime_boundary.clone())
    else {
        return Ok(None);
    };
    let expected_groups = roots_put_second_wave_expected_groups(roots);
    if expected_groups.sink_groups.is_empty() {
        return Ok(None);
    }

    let requires_manual_rescan_delivery_evidence =
        source_status_request_requires_manual_rescan_delivery_evidence(&source_status_payload);
    let source_only_manual_rescan = !require_sink_scope && requires_manual_rescan_delivery_evidence;
    let convergence_timeout = if !require_sink_scope && requires_manual_rescan_delivery_evidence {
        MANUAL_RESCAN_SOURCE_SECOND_WAVE_TIMEOUT
    } else {
        ROOTS_PUT_SOURCE_SECOND_WAVE_TIMEOUT
    };
    let status_route_timeout = if !require_sink_scope && requires_manual_rescan_delivery_evidence {
        MANUAL_RESCAN_SOURCE_STATUS_ROUTE_TIMEOUT
    } else {
        STATUS_ROUTE_TIMEOUT
    };

    let deadline = tokio::time::Instant::now() + convergence_timeout;
    let mut last_err = None::<CnxError>;
    let mut last_summary = None::<String>;
    let mut last_per_origin = None::<String>;
    let mut last_runtime_scope = None::<String>;
    let mut last_manual_rescan_current_roots_readiness =
        None::<SourceRuntimeScopeReadinessEvidence>;
    let allow_control_resend =
        control_replay_policy == RootsPutControlReplayPolicy::AllowSingleRetry;
    // roots_put and manual-rescan publish the initial logical-roots control wave
    // before entering followup convergence. Delay the first resend so peer
    // source/sink runtimes can materialize once before we consider another
    // control replay. Keep this to a single retry: repeated full-wave
    // logical-roots replays reset live peer source/sink realization and can
    // prevent materialization from ever settling.
    let mut next_resend_at =
        tokio::time::Instant::now() + ROOTS_PUT_SOURCE_SECOND_WAVE_RESEND_INTERVAL;
    let mut resent_once = false;
    let mut control_target_node_ids = initial_target_node_ids.clone();
    let authoritative_source_status_probe_node_ids = source_status_probe_seed_node_ids.clone();
    let mut source_status_probe_node_ids = if source_only_manual_rescan {
        source_status_probe_seed_node_ids.clone()
    } else {
        BTreeSet::new()
    };
    let mut accumulated_manual_rescan_source_status =
        BTreeMap::<String, SourceObservabilitySnapshot>::new();
    let mut source_status_probe_targets_are_discovery_seed = source_only_manual_rescan
        && source_status_probe_seed_is_discovery
        && source_status_probe_node_ids.len() > 1;
    let mut prefer_scoped_source_probe =
        source_only_manual_rescan && !source_status_probe_node_ids.is_empty();
    let mut allow_local_scoped_source_probe = false;

    loop {
        let remaining = deadline.saturating_duration_since(tokio::time::Instant::now());
        if remaining.is_zero() {
            if let Some(readiness) = last_manual_rescan_current_roots_readiness {
                return Ok(Some(readiness));
            }
            let last_err = last_err
                .map(|err| err.to_string())
                .unwrap_or_else(|| "none".to_string());
            let last_summary = last_summary.unwrap_or_else(|| "none".to_string());
            let last_per_origin = last_per_origin.unwrap_or_else(|| "none".to_string());
            let last_runtime_scope = last_runtime_scope.unwrap_or_else(|| "none".to_string());
            let sink_requirement = if require_sink_scope {
                format!("{:?}", expected_groups.sink_groups)
            } else {
                "not-required".to_string()
            };
            return Err(ApiError::service_unavailable(format!(
                "roots update applied locally but peer runtime-scope second-wave convergence did not settle before followup exhausted: expected_source={:?} expected_scan={:?} expected_sink={} source_status_probe_targets={:?} authoritative_source_status_probe_targets={:?} last_err={last_err} last_source={last_summary} last_source_per_origin={last_per_origin} last_runtime_scope={last_runtime_scope}",
                expected_groups.source_groups,
                expected_groups.scan_groups,
                sink_requirement,
                source_status_probe_node_ids,
                authoritative_source_status_probe_node_ids,
            )));
        }

        if require_sink_scope {
            match collect_roots_put_second_wave_status_snapshot(
                boundary.clone(),
                context.node_id.clone(),
                remaining.min(status_route_timeout),
                STATUS_ROUTE_COLLECT_IDLE_GRACE,
            )
            .await
            {
                Ok((source_snapshot, sink_snapshot, per_origin, _runtime_scope)) => {
                    let source_snapshot = merge_roots_put_source_snapshot_with_local_observation(
                        source_snapshot,
                        &local_merge_observation,
                        None,
                    )
                    .await;
                    let runtime_scope = summarize_roots_put_second_wave_runtime_scope(
                        &source_snapshot,
                        &sink_snapshot,
                    );
                    if roots_put_second_wave_runtime_scope_ready(
                        &expected_groups,
                        &source_snapshot,
                        &sink_snapshot,
                    ) {
                        return Ok(Some(SourceRuntimeScopeReadinessEvidence::source(
                            source_snapshot,
                        )));
                    }
                    last_err = None;
                    last_summary = Some(summarize_source_status_route_snapshot(&source_snapshot));
                    last_per_origin = Some(if per_origin.is_empty() {
                        "none".to_string()
                    } else {
                        per_origin.join(" || ")
                    });
                    last_runtime_scope = Some(runtime_scope);
                }
                Err(err) => {
                    last_err = Some(err);
                    last_summary = None;
                    last_per_origin = None;
                    last_runtime_scope = None;
                }
            }
        } else {
            let local_first_budget = if source_only_manual_rescan {
                Some(remaining.min(status_route_timeout))
            } else {
                None
            };
            if !source_only_manual_rescan
                && let Some(local_source) = local_source_runtime_scope_ready(
                    roots,
                    &expected_groups,
                    &local_fast_observation,
                    local_first_budget,
                    false,
                )
                .await
            {
                return Ok(Some(SourceRuntimeScopeReadinessEvidence::source(
                    local_source,
                )));
            }
            let mut route_budget = remaining.min(status_route_timeout);
            if allow_control_resend && !resent_once {
                route_budget = route_budget
                    .min(next_resend_at.saturating_duration_since(tokio::time::Instant::now()));
            }
            if source_only_manual_rescan {
                let local_source_budget = remaining.min(status_route_timeout);
                let scoped_target_node_ids = source_status_probe_node_ids
                    .iter()
                    .filter(|node_id| {
                        allow_local_scoped_source_probe
                            || !runtime_node_identity_matches(node_id, &context.node_id.0)
                    })
                    .cloned()
                    .collect::<Vec<_>>();
                let scoped_probe_due =
                    prefer_scoped_source_probe || !source_status_probe_node_ids.is_empty();
                let run_scoped_source_collect =
                    scoped_probe_due && !scoped_target_node_ids.is_empty();
                let run_generic_source_collect = source_status_probe_targets_are_discovery_seed
                    || source_status_probe_node_ids.is_empty()
                    || (allow_local_scoped_source_probe && !scoped_target_node_ids.is_empty());
                let source_collect_probe_node_ids =
                    if source_status_probe_targets_are_discovery_seed {
                        BTreeSet::new()
                    } else {
                        source_status_probe_node_ids.clone()
                    };
                let generic_complete_after_events =
                    manual_rescan_targeted_source_status_complete_after_events(
                        &source_collect_probe_node_ids,
                    );
                let source_collect_is_discovery_seed =
                    source_status_probe_targets_are_discovery_seed;
                let source_collect_discovery_seed_node_ids = source_status_probe_node_ids.clone();
                let mut scoped_source_collects = FuturesUnordered::new();
                if run_scoped_source_collect {
                    prefer_scoped_source_probe = true;
                    for node_id in scoped_target_node_ids {
                        let boundary = boundary.clone();
                        let origin_id = context.node_id.clone();
                        scoped_source_collects.push(async move {
                            let result =
                                collect_node_scoped_manual_rescan_source_status_origin_snapshot(
                                    boundary,
                                    origin_id,
                                    route_budget,
                                    &node_id,
                                )
                                .await;
                            (node_id, result)
                        });
                    }
                }
                let source_collect = async {
                    if run_generic_source_collect {
                        let generic_source_status_payload =
                            manual_rescan_source_status_request_payload();
                        let result = if source_collect_is_discovery_seed {
                            collect_roots_put_source_second_wave_status_snapshot_until_manual_rescan_discovery(
                                boundary.clone(),
                                context.node_id.clone(),
                                route_budget,
                                STATUS_ROUTE_COLLECT_IDLE_GRACE,
                                generic_source_status_payload,
                                roots,
                                &source_collect_discovery_seed_node_ids,
                            )
                            .await
                        } else {
                            collect_roots_put_source_second_wave_status_snapshot_until_manual_rescan_targets(
                                boundary.clone(),
                                context.node_id.clone(),
                                route_budget,
                                STATUS_ROUTE_COLLECT_IDLE_GRACE,
                                generic_source_status_payload,
                                generic_complete_after_events,
                                roots,
                                &source_collect_probe_node_ids,
                            )
                            .await
                        };
                        Some(result)
                    } else {
                        None
                    }
                };
                let local_source = observe_local_source_with_budget(
                    &local_merge_observation,
                    Some(local_source_budget),
                );
                tokio::pin!(source_collect);
                tokio::pin!(local_source);

                let mut source_collect_done = !run_generic_source_collect;
                let mut scoped_source_collect_done = scoped_source_collects.is_empty();
                let mut local_source_done = false;
                let mut observed_source_snapshot = None::<SourceObservabilitySnapshot>;
                let mut observed_discovery_source_snapshot = None::<SourceObservabilitySnapshot>;
                let mut observed_generic_discovery_source_snapshot =
                    None::<SourceObservabilitySnapshot>;
                let mut observed_per_origin = Vec::<String>::new();
                let mut observed_err = None::<CnxError>;
                let mut local_scoped_source_probe_unblocked = false;

                while !(source_collect_done && scoped_source_collect_done && local_source_done) {
                    if source_status_probe_targets_are_discovery_seed
                        && observed_source_snapshot.is_some()
                        && scoped_source_collect_done
                        && local_source_done
                        && !source_collect_done
                        && manual_rescan_delivery_target_node_ids_from_accumulated_source_status(
                            roots,
                            &accumulated_manual_rescan_source_status,
                        )
                        .is_some()
                    {
                        source_collect_done = true;
                        continue;
                    }
                    tokio::select! {
                        biased;
                        result = scoped_source_collects.next(), if !scoped_source_collect_done => {
                            match result {
                                Some((_node_id, Ok(origin_snapshots))) => {
                                    observed_per_origin.extend(origin_snapshots.iter().map(|(origin, snapshot)| {
                                        format!(
                                            "{origin}=>{}",
                                            summarize_source_status_route_snapshot(snapshot)
                                        )
                                    }));
                                    if source_status_probe_targets_are_discovery_seed {
                                        let discovery_source =
                                            manual_rescan_discovery_source_snapshot_from_origin_snapshots(
                                                roots,
                                                &origin_snapshots,
                                            );
                                        merge_manual_rescan_discovery_source_snapshot(
                                            roots,
                                            &mut observed_discovery_source_snapshot,
                                            discovery_source,
                                        );
                                    }
                                    let merged = merge_manual_rescan_source_status_origin_snapshots(
                                        roots,
                                        &mut accumulated_manual_rescan_source_status,
                                        origin_snapshots,
                                    );
                                    if !source_status_probe_targets_are_discovery_seed
                                        && let Some(target_node_ids) =
                                        manual_rescan_delivery_target_node_ids_from_accumulated_source_status(
                                            roots,
                                            &accumulated_manual_rescan_source_status,
                                        )
                                    {
                                        return Ok(Some(
                                            SourceRuntimeScopeReadinessEvidence::manual_rescan_from_origin_targets(
                                                merged,
                                                target_node_ids,
                                            ),
                                        ));
                                    }
                                    observed_source_snapshot = Some(merged);
                                }
                                Some((node_id, Err(err))) => {
                                    if !source_status_probe_targets_are_discovery_seed
                                        && observed_err.is_none()
                                    {
                                        observed_err = Some(CnxError::Internal(format!(
                                            "node-scoped source-status probe failed for {node_id}: {err}"
                                        )));
                                    }
                                }
                                None => scoped_source_collect_done = true,
                            }
                            if scoped_source_collects.is_empty() {
                                scoped_source_collect_done = true;
                            }
                        }
                        result = &mut source_collect, if !source_collect_done => {
                            source_collect_done = true;
                            if let Some(result) = result {
                                match result {
                                    Ok((_source_snapshot, origin_snapshots, _per_origin, _runtime_scope)) => {
                                        let origin_snapshots =
                                            filter_manual_rescan_source_status_origin_snapshots_to_probe_targets(
                                                origin_snapshots,
                                                &source_status_probe_node_ids,
                                            );
                                        observed_per_origin.extend(origin_snapshots.iter().map(|(origin, snapshot)| {
                                            format!(
                                                "{origin}=>{}",
                                                summarize_source_status_route_snapshot(snapshot)
                                            )
                                        }));
                                    if origin_snapshots.is_empty() {
                                        continue;
                                    }
                                    if source_status_probe_targets_are_discovery_seed {
                                        let discovery_source =
                                            manual_rescan_discovery_source_snapshot_from_origin_snapshots(
                                                roots,
                                                &origin_snapshots,
                                            );
                                        merge_manual_rescan_discovery_source_snapshot(
                                            roots,
                                            &mut observed_generic_discovery_source_snapshot,
                                            discovery_source.clone(),
                                        );
                                        merge_manual_rescan_discovery_source_snapshot(
                                            roots,
                                            &mut observed_discovery_source_snapshot,
                                            discovery_source,
                                        );
                                    }
                                    let merged = merge_manual_rescan_source_status_origin_snapshots(
                                        roots,
                                        &mut accumulated_manual_rescan_source_status,
                                            origin_snapshots,
                                        );
                                        if !source_status_probe_targets_are_discovery_seed
                                            && let Some(target_node_ids) =
                                            manual_rescan_delivery_target_node_ids_from_accumulated_source_status(
                                                roots,
                                                &accumulated_manual_rescan_source_status,
                                            )
                                        {
                                            return Ok(Some(
                                                SourceRuntimeScopeReadinessEvidence::manual_rescan_from_origin_targets(
                                                    merged,
                                                    target_node_ids,
                                                ),
                                            ));
                                        }
                                        observed_source_snapshot = Some(merged);
                                    }
                                    Err(err) => observed_err = Some(err),
                                }
                            }
                        }
                        local = &mut local_source, if !local_source_done => {
                            local_source_done = true;
                            if let Some(local_source) = local {
                                observed_per_origin.push(format!(
                                    "{}=>{}",
                                    context.node_id.0,
                                    summarize_source_status_route_snapshot(&local_source)
                                ));
                                if source_status_probe_targets_are_discovery_seed {
                                    merge_manual_rescan_discovery_source_snapshot(
                                        roots,
                                        &mut observed_discovery_source_snapshot,
                                        local_source.clone(),
                                    );
                                }
                                let merged = merge_manual_rescan_source_status_origin_snapshots(
                                    roots,
                                    &mut accumulated_manual_rescan_source_status,
                                    [(context.node_id.0.clone(), local_source)],
                                );
                                if !source_status_probe_targets_are_discovery_seed
                                    && let Some(target_node_ids) =
                                    manual_rescan_delivery_target_node_ids_from_accumulated_source_status(
                                        roots,
                                        &accumulated_manual_rescan_source_status,
                                    )
                                {
                                    return Ok(Some(
                                        SourceRuntimeScopeReadinessEvidence::manual_rescan_from_origin_targets(
                                            merged,
                                            target_node_ids,
                                        ),
                                    ));
                                }
                                if !source_status_probe_targets_are_discovery_seed
                                    && source_status_probe_node_ids
                                        .iter()
                                        .any(|node_id| runtime_node_identity_matches(node_id, &context.node_id.0))
                                    && !manual_rescan_accumulated_source_status_has_delivery_target_node_id(
                                        roots,
                                        &accumulated_manual_rescan_source_status,
                                        &context.node_id.0,
                                    )
                                {
                                    allow_local_scoped_source_probe = true;
                                    prefer_scoped_source_probe = true;
                                    local_scoped_source_probe_unblocked = true;
                                    source_collect_done = true;
                                }
                                observed_source_snapshot = Some(merged);
                            } else if !source_status_probe_targets_are_discovery_seed
                                && source_status_probe_node_ids
                                .iter()
                                .any(|node_id| runtime_node_identity_matches(node_id, &context.node_id.0))
                            {
                                allow_local_scoped_source_probe = true;
                                prefer_scoped_source_probe = true;
                                local_scoped_source_probe_unblocked = true;
                                source_collect_done = true;
                            }
                        }
                    }
                }

                if local_scoped_source_probe_unblocked {
                    continue;
                }

                if observed_source_snapshot.is_none()
                    && !source_status_probe_node_ids.is_empty()
                    && !run_generic_source_collect
                {
                    let mut fallback_budget = deadline
                        .saturating_duration_since(tokio::time::Instant::now())
                        .min(status_route_timeout);
                    if allow_control_resend && !resent_once {
                        fallback_budget = fallback_budget.min(
                            next_resend_at.saturating_duration_since(tokio::time::Instant::now()),
                        );
                    }
                    if !fallback_budget.is_zero() {
                        match collect_roots_put_source_second_wave_status_snapshot_until_manual_rescan_targets(
                            boundary.clone(),
                            context.node_id.clone(),
                            fallback_budget,
                            STATUS_ROUTE_COLLECT_IDLE_GRACE,
                            manual_rescan_source_status_request_payload(),
                            manual_rescan_targeted_source_status_complete_after_events(
                                &source_status_probe_node_ids,
                            ),
                            roots,
                            &source_status_probe_node_ids,
                        )
                        .await
                        {
                            Ok((
                                _source_snapshot,
                                origin_snapshots,
                                _per_origin,
                                _runtime_scope,
                            )) => {
                                let origin_snapshots =
                                    filter_manual_rescan_source_status_origin_snapshots_to_probe_targets(
                                        origin_snapshots,
                                        &source_status_probe_node_ids,
                                    );
                                observed_per_origin.extend(origin_snapshots.iter().map(
                                    |(origin, snapshot)| {
                                        format!(
                                            "{origin}=>{}",
                                            summarize_source_status_route_snapshot(snapshot)
                                        )
                                    },
                                ));
                                if !origin_snapshots.is_empty() {
                                    if source_status_probe_targets_are_discovery_seed {
                                        merge_manual_rescan_discovery_source_snapshot(
                                            roots,
                                            &mut observed_discovery_source_snapshot,
                                            manual_rescan_discovery_source_snapshot_from_origin_snapshots(
                                                roots,
                                                &origin_snapshots,
                                            ),
                                        );
                                    }
                                    let merged = merge_manual_rescan_source_status_origin_snapshots(
                                        roots,
                                        &mut accumulated_manual_rescan_source_status,
                                        origin_snapshots,
                                    );
                                    if !source_status_probe_targets_are_discovery_seed
                                        && let Some(target_node_ids) =
                                        manual_rescan_delivery_target_node_ids_from_accumulated_source_status(
                                            roots,
                                            &accumulated_manual_rescan_source_status,
                                        )
                                    {
                                        return Ok(Some(
                                            SourceRuntimeScopeReadinessEvidence::manual_rescan_from_origin_targets(
                                                merged,
                                                target_node_ids,
                                            ),
                                        ));
                                    }
                                    observed_source_snapshot = Some(merged);
                                }
                            }
                            Err(err) => {
                                if observed_err.is_none() {
                                    observed_err = Some(err);
                                }
                            }
                        }
                    }
                }

                if let Some(mut source_snapshot) = observed_source_snapshot {
                    if source_status_probe_targets_are_discovery_seed {
                        let generic_discovery_source_snapshot =
                            observed_generic_discovery_source_snapshot
                                .as_ref()
                                .filter(|source| {
                                    manual_rescan_discovered_source_status_probe_target_node_ids(
                                        roots, source,
                                    )
                                    .is_some()
                                });
                        let discovery_source_snapshot = generic_discovery_source_snapshot
                            .or(observed_discovery_source_snapshot.as_ref())
                            .unwrap_or(&source_snapshot);
                        if let Some(discovered_probe_node_ids) =
                            manual_rescan_discovered_source_status_probe_target_node_ids(
                                roots,
                                discovery_source_snapshot,
                            )
                        {
                            source_status_probe_node_ids = discovered_probe_node_ids;
                            source_status_probe_targets_are_discovery_seed = false;
                            prefer_scoped_source_probe = true;
                            retain_accumulated_manual_rescan_source_status_to_probe_targets(
                                &mut accumulated_manual_rescan_source_status,
                                &source_status_probe_node_ids,
                            );
                            source_snapshot =
                                source_snapshot_without_stale_runtime_scope_generation(
                                    merge_source_observability_snapshots(
                                        accumulated_manual_rescan_source_status
                                            .values()
                                            .cloned()
                                            .collect(),
                                    ),
                                );
                            if let Some(target_node_ids) =
                                manual_rescan_delivery_target_node_ids_from_accumulated_source_status(
                                    roots,
                                    &accumulated_manual_rescan_source_status,
                                )
                            {
                                return Ok(Some(
                                    SourceRuntimeScopeReadinessEvidence::manual_rescan_from_origin_targets(
                                        source_snapshot,
                                        target_node_ids,
                                    ),
                                ));
                            }
                        } else {
                            prefer_scoped_source_probe = false;
                        }
                    } else {
                        source_status_probe_node_ids =
                            manual_rescan_source_status_probe_target_node_ids(
                                roots,
                                &source_snapshot,
                                &authoritative_source_status_probe_node_ids,
                            );
                        if !source_status_probe_node_ids.is_empty() {
                            prefer_scoped_source_probe = true;
                        }
                    }
                    if source_status_probe_node_ids
                        .iter()
                        .any(|node_id| runtime_node_identity_matches(node_id, &context.node_id.0))
                        && !manual_rescan_accumulated_source_status_has_delivery_target_node_id(
                            roots,
                            &accumulated_manual_rescan_source_status,
                            &context.node_id.0,
                        )
                    {
                        allow_local_scoped_source_probe = true;
                        prefer_scoped_source_probe = true;
                    }
                    if let Some(readiness) = manual_rescan_readiness_from_origin_fan_in_snapshot(
                        &expected_groups,
                        roots,
                        source_snapshot.clone(),
                        &source_status_probe_node_ids,
                    ) {
                        if readiness.manual_rescan_delivery_target_node_ids.is_some()
                            || source_status_probe_node_ids.is_empty()
                        {
                            return Ok(Some(readiness));
                        }
                        last_manual_rescan_current_roots_readiness = Some(readiness);
                    }
                    last_err = None;
                    last_summary = Some(summarize_source_status_route_snapshot(&source_snapshot));
                    last_per_origin = Some(if observed_per_origin.is_empty() {
                        "none".to_string()
                    } else {
                        observed_per_origin.join(" || ")
                    });
                    last_runtime_scope =
                        Some(summarize_roots_put_source_runtime_scope(&source_snapshot));
                } else {
                    if !source_status_probe_targets_are_discovery_seed
                        && !source_status_probe_node_ids.is_empty()
                    {
                        prefer_scoped_source_probe = true;
                    }
                    if observed_err.is_some() {
                        last_err = observed_err;
                    }
                }
            } else {
                match collect_roots_put_source_second_wave_status_snapshot(
                    boundary.clone(),
                    context.node_id.clone(),
                    route_budget,
                    STATUS_ROUTE_COLLECT_IDLE_GRACE,
                    source_status_payload.clone(),
                    None,
                )
                .await
                {
                    Ok((source_snapshot, _origin_snapshots, per_origin, _runtime_scope)) => {
                        let source_snapshot =
                            merge_roots_put_source_snapshot_with_local_observation(
                                source_snapshot,
                                &local_merge_observation,
                                None,
                            )
                            .await;
                        let runtime_scope =
                            summarize_roots_put_source_runtime_scope(&source_snapshot);
                        if roots_put_second_wave_source_runtime_scope_ready(
                            &expected_groups,
                            &source_snapshot,
                        ) {
                            return Ok(Some(SourceRuntimeScopeReadinessEvidence::source(
                                source_snapshot,
                            )));
                        }
                        last_err = None;
                        last_summary =
                            Some(summarize_source_status_route_snapshot(&source_snapshot));
                        last_per_origin = Some(if per_origin.is_empty() {
                            "none".to_string()
                        } else {
                            per_origin.join(" || ")
                        });
                        last_runtime_scope = Some(runtime_scope);
                    }
                    Err(err) => {
                        last_err = Some(err);
                        last_summary = None;
                        last_per_origin = None;
                        last_runtime_scope = None;
                    }
                }
            }
        }

        let now = tokio::time::Instant::now();
        if allow_control_resend && !resent_once && now >= next_resend_at {
            if !source_only_manual_rescan {
                control_target_node_ids.extend(
                    discover_roots_put_control_target_node_ids_with_boundary(
                        context
                            .query_runtime_boundary
                            .clone()
                            .or_else(|| context.runtime_boundary.clone()),
                        context.node_id.clone(),
                    )
                    .await,
                );
            }
            send_roots_put_control_second_wave(context, roots, &control_target_node_ids).await?;
            if source_only_manual_rescan {
                reset_manual_rescan_delivery_proof_after_roots_control_resend(
                    &mut accumulated_manual_rescan_source_status,
                    &mut prefer_scoped_source_probe,
                    &source_status_probe_node_ids,
                );
                last_summary =
                    Some("manual-rescan delivery proof reset after roots control resend".into());
                last_per_origin = None;
                last_runtime_scope = None;
                last_manual_rescan_current_roots_readiness = None;
            }
            resent_once = true;
            next_resend_at = deadline;
        }

        tokio::time::sleep(ROOTS_PUT_SOURCE_SECOND_WAVE_POLL_INTERVAL).await;
    }
}

