fn next_status_trace_request_id() -> Option<u64> {
    #[cfg(test)]
    {
        static NEXT_REQUEST_ID: AtomicU64 = AtomicU64::new(1);
        Some(NEXT_REQUEST_ID.fetch_add(1, Ordering::SeqCst))
    }
    #[cfg(not(test))]
    {
        None
    }
}

fn record_status_route_trace(_trace_id: Option<u64>, _stage: impl Into<String>) {
    #[cfg(test)]
    if let Some(trace_id) = _trace_id {
        let hook = {
            let guard = match status_route_trace_hook_cell().lock() {
                Ok(guard) => guard,
                Err(poisoned) => poisoned.into_inner(),
            };
            guard.clone()
        };
        if let Some(hook) = hook {
            let mut events = match hook.events.lock() {
                Ok(guard) => guard,
                Err(poisoned) => poisoned.into_inner(),
            };
            events.push(format!("{trace_id}:{}", _stage.into()));
        }
    }
}

fn summarize_sorted_set(groups: &BTreeSet<String>) -> String {
    if groups.is_empty() {
        return "-".to_string();
    }
    groups.iter().cloned().collect::<Vec<_>>().join("|")
}

fn summarize_candidate_sink_group_state(
    sink_status: &SinkStatusSnapshot,
    candidate_groups: &BTreeSet<String>,
) -> String {
    if candidate_groups.is_empty() {
        return "-".to_string();
    }
    let sink_groups = sink_status
        .groups
        .iter()
        .map(|group| (group.group_id.as_str(), group))
        .collect::<BTreeMap<_, _>>();
    candidate_groups
        .iter()
        .map(|group_id| match sink_groups.get(group_id.as_str()) {
            Some(group) => format!(
                "{group_id}:initial_audit_completed={}:overflow_pending_materialization={}",
                group.is_ready(),
                group.overflow_pending_materialization
            ),
            None => format!("{group_id}:missing"),
        })
        .collect::<Vec<_>>()
        .join("|")
}

pub async fn login(
    State(state): State<ApiState>,
    Json(req): Json<LoginRequest>,
) -> Result<Json<LoginResponse>, ApiError> {
    if req.username.trim().is_empty() || req.password.is_empty() {
        return Err(ApiError::bad_request("username/password must not be empty"));
    }
    let (token, expires_in_secs, user) = state.auth.login(&req.username, &req.password)?;
    Ok(Json(LoginResponse {
        token,
        expires_in_secs,
        user,
    }))
}

async fn run_status_source_repair_recovery_if_needed(state: &ApiState, force: bool) {
    if !force && state.control_gate.is_source_repair_ready() {
        return;
    }
    let Some(recovery) = state.control_gate.source_repair_recovery() else {
        return;
    };
    match tokio::time::timeout(STATUS_RECOVERY_TIMEOUT, recovery()).await {
        Ok(Ok(())) => {}
        Ok(Err(err)) => {
            eprintln!("fs_meta_api_status: bounded source repair failed err={err}");
        }
        Err(_) => {
            eprintln!("fs_meta_api_status: bounded source repair timed out");
        }
    }
}

fn source_runtime_scope_schedules_group(
    groups_by_node: &BTreeMap<String, Vec<String>>,
    group_id: &str,
) -> bool {
    groups_by_node
        .values()
        .any(|groups| groups.iter().any(|group| group == group_id))
}

fn source_runtime_scope_covers_roots(
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
) -> bool {
    !roots.is_empty()
        && roots.iter().all(|root| {
            source_runtime_scope_schedules_group(&source.scheduled_source_groups_by_node, &root.id)
                && source_runtime_scope_schedules_group(
                    &source.scheduled_scan_groups_by_node,
                    &root.id,
                )
        })
}

fn source_observation_is_sparse_runtime_scope_cache(source: &SourceObservabilitySnapshot) -> bool {
    let has_runtime_scope_cache_marker =
        source
            .status
            .degraded_roots
            .iter()
            .any(|(root_key, reason)| {
                root_key == SOURCE_WORKER_DEGRADED_ROOT_KEY
                    && (reason == SOURCE_WORKER_RUNTIME_SCOPE_CACHE_REASON
                        || reason == SOURCE_WORKER_PENDING_SOURCE_STATE_OBSERVATION_REASON)
            });
    has_runtime_scope_cache_marker
        && (source.logical_roots.is_empty()
            || source.status.logical_roots.is_empty()
            || source.status.concrete_roots.is_empty()
            || source.source_primary_by_group.is_empty())
}

fn manual_rescan_source_repair_needed_for_current_roots(
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
) -> bool {
    if roots.is_empty() {
        return false;
    }
    if source_observation_is_sparse_runtime_scope_cache(source)
        && !source_runtime_scope_covers_roots(roots, source)
    {
        return true;
    }
    !manual_rescan_runtime_scope_route_activation_gaps_by_root(roots, source).is_empty()
        || !manual_rescan_runtime_scope_route_readiness_gaps_by_root(roots, source).is_empty()
}

async fn run_manual_rescan_source_repair_if_current_roots_incomplete(
    state: &ApiState,
    roots: &[RootSpec],
) {
    if roots.is_empty() {
        return;
    }
    let Some(source_snapshot) = manual_rescan_local_source_observation(
        state.source.clone(),
        state.runtime_boundary.clone(),
        state.node_id.clone(),
        true,
        Some(Duration::from_secs(2)),
    )
    .await
    else {
        return;
    };
    if !manual_rescan_source_repair_needed_for_current_roots(roots, &source_snapshot) {
        return;
    }
    run_status_source_repair_recovery_if_needed(state, true).await;
}

async fn run_status_management_write_recovery_if_needed(state: &ApiState) {
    if state.control_gate.is_ready() && state.control_gate.is_management_write_ready() {
        return;
    }
    if state.control_gate.is_management_write_drain_closed() {
        return;
    }
    if !state.control_gate.is_source_repair_ready()
        && state.control_gate.source_repair_recovery().is_some()
    {
        return;
    }
    let Some(recovery) = state.control_gate.management_write_recovery() else {
        return;
    };
    match tokio::time::timeout(STATUS_RECOVERY_TIMEOUT, recovery()).await {
        Ok(Ok(())) => {}
        Ok(Err(err)) => {
            eprintln!("fs_meta_api_status: bounded recovery failed err={err}");
        }
        Err(_) => {
            eprintln!("fs_meta_api_status: bounded recovery timed out");
        }
    }
}

fn status_sink_observation_repair_expected_groups(
    source: &SourceObservabilitySnapshot,
) -> BTreeSet<String> {
    let mut expected_groups = source
        .logical_roots
        .iter()
        .filter(|root| root.scan)
        .map(|root| root.id.clone())
        .collect::<BTreeSet<_>>();
    expected_groups.extend(source_runtime_scope_scheduled_group_ids(source));
    expected_groups
}

fn status_should_run_sink_observation_repair(
    source: &SourceObservabilitySnapshot,
    sink_status: &SinkStatusSnapshot,
) -> bool {
    let expected_groups = status_sink_observation_repair_expected_groups(source);
    if expected_groups.is_empty() || trusted_observation_readiness_for_status(source, sink_status) {
        return false;
    }
    let any_published = expected_groups
        .iter()
        .any(|group| source_snapshot_has_publication_evidence_for_group(source, group));
    if !any_published {
        return false;
    }
    let missing_expected_sink_group =
        !expected_groups.is_subset(&sink_snapshot_advertised_groups(sink_status));
    if missing_expected_sink_group {
        return true;
    }
    source_snapshot_has_publication_evidence_for_groups(source, &expected_groups)
        && sink_status_snapshot_lacks_ingress_evidence(sink_status)
}

async fn run_status_sink_observation_repair_if_needed(
    state: &ApiState,
    source: &SourceObservabilitySnapshot,
    sink_status: &SinkStatusSnapshot,
) {
    if !status_should_run_sink_observation_repair(source, sink_status) {
        return;
    }
    let Some(recovery) = state.control_gate.sink_repair_recovery() else {
        return;
    };
    match tokio::time::timeout(STATUS_RECOVERY_TIMEOUT, recovery()).await {
        Ok(Ok(())) => {}
        Ok(Err(err)) => {
            eprintln!("fs_meta_api_status: bounded sink observation repair failed err={err}");
        }
        Err(_) => {
            eprintln!("fs_meta_api_status: bounded sink observation repair timed out");
        }
    }
}

pub async fn status(
    State(state): State<ApiState>,
    ingress_readiness: Option<Extension<ApiRequestControlReadinessSnapshot>>,
    headers: HeaderMap,
) -> Result<Json<StatusResponse>, ApiError> {
    let _ = authorize_management(&state, &headers)?;
    let started_at = StdInstant::now();
    let trace_id = next_status_trace_request_id();
    record_status_route_trace(trace_id, "status.enter");
    let control_gate_fully_ready_at_request_begin = ingress_readiness
        .as_ref()
        .map(|extension| extension.0.control_gate_fully_ready)
        .unwrap_or_else(|| {
            state.control_gate.is_ready()
                && state.control_gate.is_management_write_ready()
                && state.control_gate.is_source_repair_ready()
        });

    run_status_source_repair_recovery_if_needed(&state, false).await;
    run_status_management_write_recovery_if_needed(&state).await;

    let (local_sink, local_sink_used_cached_fallback) = match state
        .sink
        .status_snapshot_nonblocking_for_status_route()
        .await
    {
        Ok((snapshot, used_cached_fallback)) => (snapshot, used_cached_fallback),
        Err(err) if state.sink.is_worker() => {
            log::warn!("status falling back to default cached sink snapshot: {err}");
            (Default::default(), true)
        }
        Err(err) => {
            return Err(ApiError::internal(format!("sink status failed: {err}")));
        }
    };
    let (mut local_source, mut local_source_used_cached_fallback) = state
        .source
        .observability_snapshot_nonblocking_for_status_route()
        .await;
    if source_observation_is_sparse_runtime_scope_cache(&local_source) {
        run_status_source_repair_recovery_if_needed(&state, true).await;
        let (snapshot, used_cached_fallback) = state
            .source
            .observability_snapshot_nonblocking_for_status_route()
            .await;
        local_source = snapshot;
        local_source_used_cached_fallback = used_cached_fallback;
    }
    if local_source_used_cached_fallback && state.source.is_worker() {
        log::warn!("status using cached/degraded source observability snapshot");
    }
    let mut local_cached_sink_not_ready = false;
    if state.source.is_worker() || state.sink.is_worker() {
        let active_candidate_groups =
            status_local_observation_candidate_groups(&local_source, &local_sink);
        let local_observation_status = (!active_candidate_groups.is_empty()).then(|| {
            evaluate_observation_status(
                &candidate_group_observation_evidence(
                    &local_source.status,
                    &local_sink,
                    &active_candidate_groups,
                ),
                ObservationTrustPolicy::candidate_generation(),
            )
        });
        record_status_route_trace(
            trace_id,
            format!(
                "status.local.gate candidates={} source_scan={} source_degraded={} initial_audit={} overflow_pending={} sink_groups={}{}",
                summarize_sorted_set(&active_candidate_groups),
                summarize_sorted_set(&active_candidate_groups),
                summarize_sorted_set(
                    &candidate_group_observation_evidence(
                        &local_source.status,
                        &local_sink,
                        &active_candidate_groups,
                    )
                    .degraded_groups
                ),
                summarize_sorted_set(
                    &candidate_group_observation_evidence(
                        &local_source.status,
                        &local_sink,
                        &active_candidate_groups,
                    )
                    .initial_audit_groups
                ),
                summarize_sorted_set(
                    &candidate_group_observation_evidence(
                        &local_source.status,
                        &local_sink,
                        &active_candidate_groups,
                    )
                    .overflow_pending_groups
                ),
                summarize_candidate_sink_group_state(&local_sink, &active_candidate_groups),
                if active_candidate_groups.is_empty() {
                    " state=SkippedNoCandidateGroups".to_string()
                } else {
                    let local_observation_status = local_observation_status
                        .as_ref()
                        .expect("candidate groups imply observation status");
                    format!(
                        " state={:?} reasons={}",
                        local_observation_status.state,
                        local_observation_status.reasons.join(" ; ")
                    )
                }
            ),
        );
        local_cached_sink_not_ready = local_sink_used_cached_fallback
            && local_observation_status
                .as_ref()
                .is_some_and(|status| status.state != ObservationState::TrustedMaterialized);
        // Management /status remains available while active facade observation is still converging.
        // Facade readiness is reported via readiness planes and pending diagnostics rather than
        // by fail-closing the management surface on observation trust.
        if local_cached_sink_not_ready {
            record_status_route_trace(trace_id, "status.local.cached_sink_not_ready");
        }
    }
    let authoritative_source_for_status_fanin = source_snapshot_with_status_authority(
        local_source.clone(),
        state
            .source
            .cached_logical_roots_snapshot_with_failure()
            .ok(),
        state
            .source
            .cached_host_object_grants_snapshot_with_failure()
            .ok(),
    );
    let published_facade_status = state.published_facade_status.snapshot();
    let published_rollout_status = state.published_rollout_status.snapshot();
    let published_facade_state = published_facade_status.state;
    let use_short_status_route_budget =
        management_status_uses_short_observation_budget(published_facade_state);
    let status_remote_collection_guard = state.control_gate.begin_status_remote_collection();
    #[cfg(test)]
    maybe_pause_status_before_remote_collection().await;
    record_status_route_trace(trace_id, "status.remote.begin");
    let local_observation_status_complete = status_local_observation_completes_management_status(
        control_gate_fully_ready_at_request_begin,
        published_facade_state,
        &local_sink,
        &local_source,
        local_source_used_cached_fallback,
    );
    let (mut sink_status, mut source, mut runner_sets, sink_outcome, source_outcome) =
        if local_observation_status_complete {
            record_status_route_trace(trace_id, "status.remote.skipped_local_ready");
            let runner_sets = local_runner_sets(&local_source);
            (
                local_sink,
                local_source,
                runner_sets,
                StatusRouteOutcome::Skipped,
                StatusRouteOutcome::Skipped,
            )
        } else {
            let status_collect = |boundary, origin_id| {
                collect_remote_status_snapshots_on_shared_boundary(
                    local_sink.clone(),
                    local_source.clone(),
                    boundary,
                    origin_id,
                    trace_id,
                    use_short_status_route_budget,
                )
            };
            // Management /status should prefer the management/runtime boundary when present.
            // The query boundary can churn independently during generation-two turnover,
            // but it is still a valid second chance when the preferred runtime boundary
            // fully transport-collapses before any remote status evidence arrives.
            let runtime_boundary = state.runtime_boundary.clone();
            let query_boundary = state.query_runtime_boundary.clone();
            match runtime_boundary {
                Some(boundary) => {
                    let initial = status_collect(boundary, state.node_id.clone()).await;
                    let runtime_fully_unavailable =
                        status_route_collection_incomplete(initial.3, initial.4);
                    if runtime_fully_unavailable {
                        if let Some(query_boundary) = query_boundary {
                            let different_boundary =
                                state
                                    .runtime_boundary
                                    .as_ref()
                                    .is_none_or(|runtime_boundary| {
                                        !std::sync::Arc::ptr_eq(runtime_boundary, &query_boundary)
                                    });
                            if different_boundary {
                                status_collect(query_boundary, state.node_id.clone()).await
                            } else {
                                initial
                            }
                        } else {
                            initial
                        }
                    } else {
                        initial
                    }
                }
                None => {
                    if let Some(boundary) = query_boundary {
                        status_collect(boundary, state.node_id.clone()).await
                    } else {
                        (
                            local_sink,
                            local_source.clone(),
                            local_runner_sets(&local_source),
                            StatusRouteOutcome::Skipped,
                            StatusRouteOutcome::Skipped,
                        )
                    }
                }
            }
        };
    if matches!(sink_outcome, StatusRouteOutcome::Ok) {
        sink_status = apply_status_ready_sink_evidence_cache(sink_status);
    }
    let source_short_budget_owner_fanin_needed = use_short_status_route_budget
        && management_status_should_attempt_short_budget_source_owner_scoped_fanin(
            source_outcome,
            &source,
            &authoritative_source_for_status_fanin,
        );
    if source_short_budget_owner_fanin_needed {
        record_status_route_trace(trace_id, "source.owner_scoped.short_budget_needed");
    }
    let primary_owner_scoped_boundary = state
        .runtime_boundary
        .clone()
        .or_else(|| state.query_runtime_boundary.clone());
    let fallback_owner_scoped_boundary =
        match (&state.runtime_boundary, &state.query_runtime_boundary) {
            (Some(runtime_boundary), Some(query_boundary))
                if !std::sync::Arc::ptr_eq(runtime_boundary, query_boundary) =>
            {
                Some(query_boundary.clone())
            }
            _ => None,
        };
    let preferred_source_owner_scoped_boundary = if local_observation_status_complete {
        None
    } else if use_short_status_route_budget && !source_short_budget_owner_fanin_needed {
        None
    } else {
        primary_owner_scoped_boundary.clone()
    };
    let fallback_source_owner_scoped_boundary = if local_observation_status_complete {
        None
    } else if use_short_status_route_budget {
        None
    } else {
        fallback_owner_scoped_boundary.clone()
    };
    source = augment_management_status_source_with_owner_scoped_evidence(
        source,
        &authoritative_source_for_status_fanin,
        preferred_source_owner_scoped_boundary,
        state.node_id.clone(),
        management_status_source_owner_scoped_timeout(use_short_status_route_budget),
    )
    .await;
    source = augment_management_status_source_with_owner_scoped_evidence(
        source,
        &authoritative_source_for_status_fanin,
        fallback_source_owner_scoped_boundary,
        state.node_id.clone(),
        management_status_source_owner_scoped_timeout(use_short_status_route_budget),
    )
    .await;
    let sink_short_budget_owner_fanin_needed = use_short_status_route_budget
        && management_status_should_attempt_short_budget_sink_owner_scoped_fanin(
            &sink_status,
            &source,
            &authoritative_source_for_status_fanin,
        );
    if sink_short_budget_owner_fanin_needed {
        record_status_route_trace(trace_id, "sink.owner_scoped.short_budget_needed");
    }
    let preferred_sink_owner_scoped_boundary = if local_observation_status_complete {
        None
    } else if use_short_status_route_budget && !sink_short_budget_owner_fanin_needed {
        None
    } else {
        primary_owner_scoped_boundary
    };
    let fallback_sink_owner_scoped_boundary = if local_observation_status_complete {
        None
    } else if use_short_status_route_budget {
        None
    } else {
        fallback_owner_scoped_boundary
    };
    sink_status = augment_management_status_sink_with_owner_scoped_evidence(
        sink_status,
        &source,
        &authoritative_source_for_status_fanin,
        preferred_sink_owner_scoped_boundary,
        state.node_id.clone(),
        management_status_sink_owner_scoped_timeout(use_short_status_route_budget),
    )
    .await;
    sink_status = augment_management_status_sink_with_owner_scoped_evidence(
        sink_status,
        &source,
        &authoritative_source_for_status_fanin,
        fallback_sink_owner_scoped_boundary,
        state.node_id.clone(),
        management_status_sink_owner_scoped_timeout(use_short_status_route_budget),
    )
    .await;
    sink_status = fill_missing_authoritative_pending_sink_groups_from_source(
        sink_status,
        &source,
        &authoritative_source_for_status_fanin,
    );
    if matches!(sink_outcome, StatusRouteOutcome::Ok) {
        sink_status = apply_status_ready_sink_evidence_cache(sink_status);
    }
    record_status_route_trace(
        trace_id,
        format!(
            "status.remote.done sink={} source={}",
            sink_outcome.as_str(),
            source_outcome.as_str()
        ),
    );
    drop(status_remote_collection_guard);
    let live_source_nodes = active_source_node_count(&source);
    let gate_inflight = state
        .force_find_inflight
        .lock()
        .map(|guard| guard.iter().cloned().collect::<Vec<_>>())
        .unwrap_or_default();
    let mut merged_inflight = source.force_find_inflight_groups.clone();
    merged_inflight.extend(gate_inflight);
    merged_inflight.sort();
    merged_inflight.dedup();
    runner_sets =
        merge_api_force_find_runner_evidence(runner_sets, &state.force_find_runner_evidence);
    eprintln!(
        "fs_meta_api_status: sink_route={} source_route={} elapsed_ms={} sink_groups={} source_runners={:?} inflight={:?}",
        sink_outcome.as_str(),
        source_outcome.as_str(),
        started_at.elapsed().as_millis(),
        sink_status.groups.len(),
        runner_sets,
        merged_inflight
    );
    if local_cached_sink_not_ready && local_source_used_cached_fallback {
        record_status_route_trace(trace_id, "status.local.cached_sink_not_ready_nonblocking");
    }
    if should_fail_closed_status_route_collection(
        sink_outcome,
        source_outcome,
        published_facade_state,
        &sink_status,
        &source,
        &runner_sets,
    ) || should_fail_closed_partial_local_status_fallback(
        sink_outcome,
        source_outcome,
        published_facade_state,
        &sink_status,
        &source,
        &runner_sets,
    ) || should_fail_closed_source_ready_sink_empty_status(
        sink_outcome,
        source_outcome,
        published_facade_state,
        state.source.is_worker() || state.sink.is_worker(),
        &sink_status,
        &source,
    ) {
        return Err(ApiError::service_unavailable(format!(
            "status remote route collection incomplete: sink_route={} source_route={}",
            sink_outcome.as_str(),
            source_outcome.as_str()
        )));
    }
    if debug_force_find_runner_capture_enabled() {
        eprintln!(
            "fs_meta_api_status: runner_capture node={} source_route={} last_runner={:?} runner_sets={:?} inflight={:?}",
            state.node_id.0,
            source_outcome.as_str(),
            summarize_group_string_map(&source.last_force_find_runner_by_group),
            runner_sets,
            merged_inflight
        );
    }
    let trusted_observation_readiness =
        trusted_observation_readiness_for_status(&source, &sink_status);
    run_status_sink_observation_repair_if_needed(&state, &source, &sink_status).await;
    let status_source =
        status_source_from_observability(source, &sink_status, runner_sets, merged_inflight);
    let (api_facade_liveness, management_write_readiness, control_epoch) =
        state.control_gate.readiness_snapshot();
    let runtime_artifact = runtime_artifact_evidence();
    let authority_epoch = authority_epoch_evidence(
        &status_source,
        &sink_status,
        published_rollout_status.serving_generation,
        published_rollout_status.candidate_generation,
        published_rollout_status.retiring_generation,
        control_epoch,
    );

    Ok(Json(StatusResponse {
        runtime_artifact,
        authority_epoch,
        readiness_planes: ReadinessPlanesEvidence {
            api_facade_liveness,
            management_write_readiness,
            trusted_observation_readiness,
        },
        source: status_source,
        sink: StatusSink {
            live_nodes: status_sink_live_nodes(live_source_nodes, &sink_status),
            tombstoned_count: sink_status.tombstoned_count,
            attested_count: sink_status.attested_count,
            suspect_count: sink_status.suspect_count,
            blind_spot_count: sink_status.blind_spot_count,
            shadow_time_us: sink_status.shadow_time_us,
            estimated_heap_bytes: sink_status.estimated_heap_bytes,
            primary_host_ref_by_group: sink_status.primary_host_ref_by_group,
            groups: sink_status
                .groups
                .into_iter()
                .map(|group| {
                    let readiness = group.normalized_readiness();
                    let initial_audit_completed =
                        matches!(readiness, crate::sink::GroupReadinessState::Ready);
                    let service_state = sink_group_service_state(&group);
                    StatusSinkGroup {
                        group_id: group.group_id,
                        service_state,
                        primary_object_ref: group.primary_object_ref,
                        total_nodes: group.total_nodes,
                        live_nodes: group.live_nodes,
                        tombstoned_count: group.tombstoned_count,
                        attested_count: group.attested_count,
                        suspect_count: group.suspect_count,
                        blind_spot_count: group.blind_spot_count,
                        shadow_time_us: group.shadow_time_us,
                        shadow_lag_us: group.shadow_lag_us,
                        overflow_pending_materialization: group.overflow_pending_materialization,
                        initial_audit_completed,
                        materialization_readiness: match readiness {
                            crate::sink::GroupReadinessState::PendingMaterialization => {
                                StatusSinkGroupMaterializationReadiness::PendingMaterialization
                            }
                            crate::sink::GroupReadinessState::WaitingForMaterializedRoot => {
                                StatusSinkGroupMaterializationReadiness::WaitingForMaterializedRoot
                            }
                            crate::sink::GroupReadinessState::Ready => {
                                StatusSinkGroupMaterializationReadiness::Ready
                            }
                        },
                        estimated_heap_bytes: group.estimated_heap_bytes,
                    }
                })
                .collect(),
            debug: StatusSinkDebug {
                scheduled_groups_by_node: sink_status.scheduled_groups_by_node,
                last_control_frame_signals_by_node: sink_status.last_control_frame_signals_by_node,
                received_batches_by_node: sink_status.received_batches_by_node,
                received_events_by_node: sink_status.received_events_by_node,
                received_control_events_by_node: sink_status.received_control_events_by_node,
                received_data_events_by_node: sink_status.received_data_events_by_node,
                last_received_at_us_by_node: sink_status.last_received_at_us_by_node,
                last_received_origins_by_node: sink_status.last_received_origins_by_node,
                received_origin_counts_by_node: sink_status.received_origin_counts_by_node,
            },
        },
        rollout: status_rollout_from_published_state(published_rollout_status),
        facade: status_facade_from_published_state(published_facade_status),
    }))
}

fn active_source_node_count(source: &SourceObservabilitySnapshot) -> u64 {
    source
        .grants
        .iter()
        .filter(|grant| grant.active)
        .map(|grant| grant.host_ip.clone())
        .collect::<BTreeSet<_>>()
        .len() as u64
}

fn status_sink_live_nodes(live_source_nodes: u64, sink_status: &SinkStatusSnapshot) -> u64 {
    let _ = live_source_nodes;
    sink_status.live_nodes
}

fn runtime_artifact_evidence() -> RuntimeArtifactEvidence {
    static START: Once = Once::new();
    static CACHE: OnceLock<StdMutex<RuntimeArtifactEvidence>> = OnceLock::new();

    let cache = CACHE.get_or_init(|| StdMutex::new(runtime_artifact_pending_evidence()));
    START.call_once(|| {
        let cache = CACHE
            .get()
            .expect("runtime artifact evidence cache initialized before hash worker starts");
        std::thread::spawn(move || {
            let evidence = compute_runtime_artifact_evidence();
            if let Ok(mut cached) = cache.lock() {
                *cached = evidence;
            }
        });
    });

    cache
        .lock()
        .map(|cached| cached.clone())
        .unwrap_or_else(|_| RuntimeArtifactEvidence {
            available: false,
            path: None,
            sha256: None,
            error: Some("runtime artifact evidence cache poisoned".to_string()),
        })
}

fn runtime_artifact_pending_evidence() -> RuntimeArtifactEvidence {
    match runtime_artifact_path() {
        Ok((path, path_warning)) => RuntimeArtifactEvidence {
            available: false,
            path: Some(path.display().to_string()),
            sha256: None,
            error: Some(
                path_warning
                    .unwrap_or("runtime artifact hash pending")
                    .to_string(),
            ),
        },
        Err(err) => RuntimeArtifactEvidence {
            available: false,
            path: None,
            sha256: None,
            error: Some(err),
        },
    }
}

fn compute_runtime_artifact_evidence() -> RuntimeArtifactEvidence {
    match runtime_artifact_path() {
        Ok((path, path_warning)) => match file_sha256_hex(&path) {
            Ok(sha256) => RuntimeArtifactEvidence {
                available: path_warning.is_none(),
                path: Some(path.display().to_string()),
                sha256: Some(sha256),
                error: path_warning.map(ToString::to_string),
            },
            Err(err) => RuntimeArtifactEvidence {
                available: false,
                path: Some(path.display().to_string()),
                sha256: None,
                error: Some(err),
            },
        },
        Err(err) => RuntimeArtifactEvidence {
            available: false,
            path: None,
            sha256: None,
            error: Some(err),
        },
    }
}

fn runtime_artifact_path() -> Result<(PathBuf, Option<&'static str>), String> {
    for env_name in [
        "CAPANIX_LOADED_APP_PATH",
        "CAPANIX_FS_META_APP_BINARY",
        "DATANIX_FS_META_APP_SO",
    ] {
        if let Some(path) = std::env::var_os(env_name).filter(|value| !value.is_empty()) {
            return Ok((PathBuf::from(path), None));
        }
    }
    std::env::current_exe()
        .map(|path| {
            (
                path,
                Some(
                    "loaded app artifact path is not available; reporting host executable fallback",
                ),
            )
        })
        .map_err(|err| format!("resolve runtime artifact path failed: {err}"))
}

fn file_sha256_hex(path: &std::path::Path) -> Result<String, String> {
    let mut file =
        std::fs::File::open(path).map_err(|err| format!("open runtime artifact failed: {err}"))?;
    let mut hasher = Sha256::new();
    let mut buf = [0_u8; 64 * 1024];
    loop {
        let read = file
            .read(&mut buf)
            .map_err(|err| format!("read runtime artifact failed: {err}"))?;
        if read == 0 {
            break;
        }
        hasher.update(&buf[..read]);
    }
    Ok(format!("{:x}", hasher.finalize()))
}

fn authority_epoch_evidence(
    source: &StatusSource,
    sink: &SinkStatusSnapshot,
    serving_generation: Option<u64>,
    candidate_generation: Option<u64>,
    retiring_generation: Option<u64>,
    control_epoch: u64,
) -> AuthorityEpochEvidence {
    AuthorityEpochEvidence {
        roots_signature: status_roots_signature(source),
        grants_signature: format!(
            "version:{}:count:{}",
            source.host_object_grants_version, source.grants_count
        ),
        source_stream_generation: source.debug.current_stream_generation,
        sink_materialization_generation: status_sink_materialization_signature(sink),
        facade_runtime_generation: format!(
            "serving:{serving_generation:?}:candidate:{candidate_generation:?}:retiring:{retiring_generation:?}:control:{control_epoch}"
        ),
    }
}

fn status_roots_signature(source: &StatusSource) -> String {
    let mut parts = source
        .logical_roots
        .iter()
        .map(|root| {
            format!(
                "{}:{}:{}:{}",
                root.root_id, root.coverage_mode, root.matched_grants, root.active_members
            )
        })
        .collect::<Vec<_>>();
    parts.sort();
    format!("count:{}:{}", source.roots_count, parts.join("|"))
}

fn status_sink_materialization_signature(sink: &SinkStatusSnapshot) -> String {
    let mut parts = sink
        .groups
        .iter()
        .map(|group| {
            format!(
                "{}:{:?}:{}:{}",
                group.group_id,
                group.normalized_readiness(),
                group.overflow_pending_materialization,
                group.shadow_time_us
            )
        })
        .collect::<Vec<_>>();
    parts.sort();
    parts.join("|")
}

fn sink_snapshot_scheduled_groups(snapshot: &SinkStatusSnapshot) -> BTreeSet<String> {
    snapshot
        .scheduled_groups_by_node
        .values()
        .flatten()
        .cloned()
        .collect()
}

fn source_logical_root_service_state(
    root_id: &str,
    status: &str,
    matched_grants: usize,
    active_members: usize,
    sink_status: &SinkStatusSnapshot,
) -> GroupServiceState {
    let scheduled_sink_groups = sink_snapshot_scheduled_groups(sink_status);
    let sink_groups = sink_status
        .groups
        .iter()
        .map(|group| (group.group_id.as_str(), group))
        .collect::<BTreeMap<_, _>>();
    match status
        .split_once(':')
        .map(|(head, _)| head)
        .unwrap_or(status)
    {
        "ready" => {
            if let Some(group) = sink_groups.get(root_id) {
                sink_group_service_state(group)
            } else if scheduled_sink_groups.contains(root_id) {
                GroupServiceState::ServingDegraded
            } else {
                GroupServiceState::SelectedPending
            }
        }
        "retiring" => GroupServiceState::Retiring,
        "retired" => GroupServiceState::Retired,
        "no_visible_export_match" if matched_grants == 0 || active_members == 0 => {
            GroupServiceState::NotSelected
        }
        _ if matched_grants == 0 || active_members == 0 => GroupServiceState::SelectedPending,
        _ if status.contains("degraded")
            || status.contains("error")
            || status.contains("failed")
            || status.contains("overflow") =>
        {
            GroupServiceState::ServingDegraded
        }
        _ => GroupServiceState::SelectedPending,
    }
}

fn source_root_participation_state(status: &str) -> NodeParticipationState {
    match status
        .split_once(':')
        .map(|(head, _)| head)
        .unwrap_or(status)
    {
        "running" => NodeParticipationState::Serving,
        "planned" | "starting" | "warming" => NodeParticipationState::Joining,
        "retiring" | "stopped" | "draining" => NodeParticipationState::Retiring,
        "retired" => NodeParticipationState::Retired,
        "absent" => NodeParticipationState::Absent,
        _ if status.contains("degraded")
            || status.contains("error")
            || status.contains("failed")
            || status.contains("unreachable") =>
        {
            NodeParticipationState::Degraded
        }
        _ => NodeParticipationState::Joining,
    }
}

fn sink_group_service_state(group: &crate::sink::SinkGroupStatusSnapshot) -> GroupServiceState {
    let readiness = group.normalized_readiness();
    if matches!(readiness, crate::sink::GroupReadinessState::Ready) {
        if !group.materialized_service_ready() {
            GroupServiceState::ServingDegraded
        } else {
            GroupServiceState::ServingTrusted
        }
    } else if group.total_nodes > 0 || group.live_nodes > 0 {
        GroupServiceState::ServingDegraded
    } else {
        GroupServiceState::SelectedPending
    }
}

#[cfg(test)]
fn snapshot_scoped_active_facade_candidate_groups(
    local_source: &SourceObservabilitySnapshot,
    local_sink: &SinkStatusSnapshot,
) -> BTreeSet<String> {
    let mut source_groups = local_source
        .scheduled_source_groups_by_node
        .values()
        .flatten()
        .cloned()
        .collect::<BTreeSet<_>>();
    source_groups.extend(
        local_source
            .scheduled_scan_groups_by_node
            .values()
            .flatten()
            .cloned(),
    );
    let sink_groups = local_sink
        .scheduled_groups_by_node
        .values()
        .flatten()
        .cloned()
        .collect::<BTreeSet<_>>();
    if !source_groups.is_empty() && !sink_groups.is_empty() {
        return source_groups.intersection(&sink_groups).cloned().collect();
    }
    if !source_groups.is_empty() && sink_groups.is_empty() {
        return BTreeSet::new();
    }
    if !source_groups.is_empty() {
        return source_groups;
    }
    sink_groups
}

fn status_local_observation_candidate_groups(
    local_source: &SourceObservabilitySnapshot,
    local_sink: &SinkStatusSnapshot,
) -> BTreeSet<String> {
    let source_groups = source_snapshot_active_groups(local_source);
    let sink_groups = sink_snapshot_scheduled_groups(local_sink);
    if !source_groups.is_empty() && !sink_groups.is_empty() {
        return source_groups.intersection(&sink_groups).cloned().collect();
    }
    if !source_groups.is_empty() {
        return source_groups;
    }
    sink_groups
}

fn source_snapshot_active_groups(snapshot: &SourceObservabilitySnapshot) -> BTreeSet<String> {
    let mut groups = snapshot
        .scheduled_source_groups_by_node
        .values()
        .flatten()
        .cloned()
        .collect::<BTreeSet<_>>();
    groups.extend(
        snapshot
            .scheduled_scan_groups_by_node
            .values()
            .flatten()
            .cloned(),
    );
    groups
}

fn source_logical_root_counts_as_status_readiness(
    root: &crate::source::SourceLogicalRootHealthSnapshot,
) -> bool {
    root.matched_grants > 0
        && root.active_members > 0
        && !root.status.starts_with("waiting_for_root:")
}

fn source_concrete_root_counts_as_status_readiness(
    root: &crate::source::SourceConcreteRootHealthSnapshot,
) -> bool {
    root.active
        && root.scan_enabled
        && root.last_error.is_none()
        && !root.status.starts_with("waiting_for_root:")
}

fn source_snapshot_status_readiness_groups(
    snapshot: &SourceObservabilitySnapshot,
) -> BTreeSet<String> {
    let degraded_groups = snapshot
        .status
        .degraded_roots
        .iter()
        .map(|(group, _)| group.clone())
        .collect::<BTreeSet<_>>();
    let mut groups = source_snapshot_active_groups(snapshot);
    groups.extend(
        snapshot
            .status
            .logical_roots
            .iter()
            .filter(|root| source_logical_root_counts_as_status_readiness(root))
            .map(|root| root.root_id.clone()),
    );
    groups.extend(
        snapshot
            .status
            .concrete_roots
            .iter()
            .filter(|root| source_concrete_root_counts_as_status_readiness(root))
            .map(|root| root.logical_root_id.clone()),
    );
    for group in degraded_groups {
        groups.remove(&group);
    }
    groups
}

fn source_published_origin_count_mentions_group(entry: &str, group: &str) -> bool {
    let origin = entry
        .split_once('=')
        .map(|(origin, _)| origin)
        .unwrap_or(entry);
    origin
        .split_once("::")
        .map(|(_, root_id)| root_id == group)
        .unwrap_or(origin == group)
}

fn source_snapshot_has_publication_evidence_for_group(
    snapshot: &SourceObservabilitySnapshot,
    group: &str,
) -> bool {
    snapshot
        .published_origin_counts_by_node
        .values()
        .flatten()
        .any(|entry| source_published_origin_count_mentions_group(entry, group))
        || snapshot
            .last_published_origins_by_node
            .values()
            .flatten()
            .any(|entry| source_published_origin_count_mentions_group(entry, group))
        || snapshot.status.concrete_roots.iter().any(|root| {
            root.logical_root_id == group
                && root.active
                && root.is_group_primary
                && (root.forwarded_batch_count > 0
                    || root.forwarded_event_count > 0
                    || root.emitted_batch_count > 0
                    || root.emitted_event_count > 0
                    || root.last_forwarded_at_us.is_some()
                    || root.last_emitted_at_us.is_some())
        })
}

fn source_snapshot_has_publication_evidence_for_groups(
    snapshot: &SourceObservabilitySnapshot,
    groups: &BTreeSet<String>,
) -> bool {
    !groups.is_empty()
        && groups
            .iter()
            .all(|group| source_snapshot_has_publication_evidence_for_group(snapshot, group))
}

fn sink_snapshot_advertised_groups(snapshot: &SinkStatusSnapshot) -> BTreeSet<String> {
    let mut groups = sink_snapshot_scheduled_groups(snapshot);
    groups.extend(snapshot.groups.iter().map(|group| group.group_id.clone()));
    groups
}

fn sink_snapshot_live_materialized_groups(snapshot: &SinkStatusSnapshot) -> BTreeSet<String> {
    snapshot
        .groups
        .iter()
        .filter(|group| group.materialized_service_live_ready())
        .map(|group| group.group_id.clone())
        .collect()
}

fn local_sink_covers_active_source_groups(
    local_sink: &SinkStatusSnapshot,
    source: &SourceObservabilitySnapshot,
) -> bool {
    let active_source_groups = source_snapshot_status_readiness_groups(source);
    !active_source_groups.is_empty()
        && active_source_groups.is_subset(&sink_snapshot_live_materialized_groups(local_sink))
}

fn local_sink_has_schedule_evidence_for_active_source_groups(
    local_sink: &SinkStatusSnapshot,
    source: &SourceObservabilitySnapshot,
) -> bool {
    let active_source_groups = source_snapshot_status_readiness_groups(source);
    !active_source_groups.is_empty()
        && active_source_groups.is_subset(&sink_snapshot_scheduled_groups(local_sink))
}

fn source_runtime_scope_scheduled_groups_by_node(
    source: &SourceObservabilitySnapshot,
) -> BTreeMap<String, BTreeSet<String>> {
    let mut groups_by_node = BTreeMap::<String, BTreeSet<String>>::new();
    for (node_id, groups) in source
        .scheduled_source_groups_by_node
        .iter()
        .chain(source.scheduled_scan_groups_by_node.iter())
    {
        let entry = groups_by_node.entry(node_id.clone()).or_default();
        entry.extend(groups.iter().filter(|group| !group.is_empty()).cloned());
    }
    groups_by_node.retain(|_, groups| !groups.is_empty());
    groups_by_node
}

fn source_runtime_scope_scheduled_group_ids(
    source: &SourceObservabilitySnapshot,
) -> BTreeSet<String> {
    source_runtime_scope_scheduled_groups_by_node(source)
        .into_values()
        .flatten()
        .collect()
}

fn local_sink_schedule_covers_source_runtime_scope(
    local_sink: &SinkStatusSnapshot,
    source: &SourceObservabilitySnapshot,
) -> bool {
    let source_groups_by_node = source_runtime_scope_scheduled_groups_by_node(source);
    if source_groups_by_node.is_empty() {
        return true;
    }

    source_groups_by_node
        .into_iter()
        .all(|(node_id, source_groups)| {
            let sink_groups = local_sink
                .scheduled_groups_by_node
                .get(&node_id)
                .into_iter()
                .flat_map(|groups| groups.iter())
                .filter(|group| !group.is_empty())
                .cloned()
                .collect::<BTreeSet<_>>();
            source_groups.is_subset(&sink_groups)
        })
}

fn source_runtime_scope_covers_active_source_groups(source: &SourceObservabilitySnapshot) -> bool {
    let runtime_scope_groups = source_runtime_scope_scheduled_group_ids(source);
    if runtime_scope_groups.is_empty() {
        return true;
    }
    let active_source_groups = source_snapshot_status_readiness_groups(source);
    active_source_groups.is_subset(&runtime_scope_groups)
}

fn status_local_ready_evidence_completes_management_status(
    local_sink: &SinkStatusSnapshot,
    source: &SourceObservabilitySnapshot,
    source_used_cached_fallback: bool,
) -> bool {
    !source_used_cached_fallback
        && source.status.degraded_roots.is_empty()
        && source_observability_snapshot_has_active_state(source)
        && local_sink_covers_active_source_groups(local_sink, source)
        && local_sink_has_schedule_evidence_for_active_source_groups(local_sink, source)
        && source_runtime_scope_covers_active_source_groups(source)
        && local_sink_schedule_covers_source_runtime_scope(local_sink, source)
}

fn status_serving_observation_evidence_completes_management_status(
    published_facade_state: FacadeServiceState,
    local_sink: &SinkStatusSnapshot,
    source: &SourceObservabilitySnapshot,
    source_used_cached_fallback: bool,
) -> bool {
    matches!(published_facade_state, FacadeServiceState::Serving)
        && !source_used_cached_fallback
        && source.status.degraded_roots.is_empty()
        && source_observability_snapshot_has_active_state(source)
        && local_sink_covers_active_source_groups(local_sink, source)
        && source_runtime_scope_covers_active_source_groups(source)
        && local_sink_has_schedule_evidence_for_active_source_groups(local_sink, source)
}

fn status_local_observation_completes_management_status(
    control_gate_fully_ready_at_request_begin: bool,
    published_facade_state: FacadeServiceState,
    local_sink: &SinkStatusSnapshot,
    source: &SourceObservabilitySnapshot,
    source_used_cached_fallback: bool,
) -> bool {
    let local_ready_status_complete = control_gate_fully_ready_at_request_begin
        && status_local_ready_evidence_completes_management_status(
            local_sink,
            source,
            source_used_cached_fallback,
        );
    let serving_observation_status_complete =
        status_serving_observation_evidence_completes_management_status(
            published_facade_state,
            local_sink,
            source,
            source_used_cached_fallback,
        );
    local_ready_status_complete || serving_observation_status_complete
}

fn sink_status_snapshot_omits_active_source_groups(
    source: &SourceObservabilitySnapshot,
    sink: &SinkStatusSnapshot,
) -> bool {
    let active_source_groups = source_snapshot_active_groups(source);
    if active_source_groups.is_empty() {
        return false;
    }
    let advertised_sink_groups = sink_snapshot_advertised_groups(sink);
    !active_source_groups.is_subset(&advertised_sink_groups)
}

fn sink_status_snapshot_lacks_ingress_evidence(snapshot: &SinkStatusSnapshot) -> bool {
    snapshot.scheduled_groups_by_node.is_empty()
        && snapshot.last_control_frame_signals_by_node.is_empty()
        && snapshot.received_batches_by_node.is_empty()
        && snapshot.received_events_by_node.is_empty()
        && snapshot.received_control_events_by_node.is_empty()
        && snapshot.received_data_events_by_node.is_empty()
        && snapshot.last_received_at_us_by_node.is_empty()
        && snapshot.last_received_origins_by_node.is_empty()
        && snapshot.received_origin_counts_by_node.is_empty()
}

fn sink_status_snapshot_is_zeroish_for_active_source_groups(snapshot: &SinkStatusSnapshot) -> bool {
    snapshot.live_nodes == 0
        && snapshot.groups.iter().all(|group| {
            group.live_nodes == 0
                && group.total_nodes == 0
                && !matches!(group.readiness, crate::sink::GroupReadinessState::Ready)
        })
}

const STATUS_ROUTE_TIMEOUT: Duration = Duration::from_secs(3);
const STATUS_ROUTE_COLLECT_IDLE_GRACE: Duration = Duration::from_secs(2);
const STATUS_ROUTE_READY_FALLBACK_GRACE: Duration = Duration::from_millis(200);
const STATUS_RECOVERY_TIMEOUT: Duration = Duration::from_secs(10);
const STATUS_SINK_ROUTE_RECOLLECT_BUDGET: Duration = Duration::from_secs(3);
const STATUS_OWNER_SCOPED_ROUTE_TIMEOUT: Duration = Duration::from_millis(500);
const STATUS_SERVING_OWNER_SCOPED_ROUTE_TIMEOUT: Duration = Duration::from_secs(3);

fn management_status_uses_short_observation_budget(
    published_facade_state: FacadeServiceState,
) -> bool {
    matches!(published_facade_state, FacadeServiceState::Pending)
}

fn management_status_sink_owner_scoped_timeout(use_short_status_route_budget: bool) -> Duration {
    if use_short_status_route_budget {
        STATUS_OWNER_SCOPED_ROUTE_TIMEOUT
    } else {
        STATUS_SERVING_OWNER_SCOPED_ROUTE_TIMEOUT
    }
}

fn management_status_source_owner_scoped_timeout(use_short_status_route_budget: bool) -> Duration {
    if use_short_status_route_budget {
        STATUS_OWNER_SCOPED_ROUTE_TIMEOUT
    } else {
        STATUS_SERVING_OWNER_SCOPED_ROUTE_TIMEOUT
    }
}

fn status_ready_sink_evidence_cache() -> &'static StdMutex<BTreeMap<String, SinkGroupStatusSnapshot>>
{
    static CACHE: OnceLock<StdMutex<BTreeMap<String, SinkGroupStatusSnapshot>>> = OnceLock::new();
    CACHE.get_or_init(|| StdMutex::new(BTreeMap::new()))
}

fn status_ready_sink_evidence_key(group: &SinkGroupStatusSnapshot) -> String {
    format!("{}\0{}", group.group_id, group.primary_object_ref)
}

fn source_snapshot_with_status_authority(
    mut snapshot: SourceObservabilitySnapshot,
    authoritative_roots: Option<Vec<RootSpec>>,
    authoritative_grants: Option<Vec<GrantedMountRoot>>,
) -> SourceObservabilitySnapshot {
    if let Some(roots) = authoritative_roots
        && !roots.is_empty()
    {
        snapshot.logical_roots = roots;
    }
    if let Some(grants) = authoritative_grants
        && !grants.is_empty()
    {
        snapshot.grants = grants;
    }
    snapshot
}

fn sink_group_has_ready_live_evidence(group: &SinkGroupStatusSnapshot) -> bool {
    group.materialized_service_live_ready()
}

fn sink_group_is_unready_zero_for_same_primary(group: &SinkGroupStatusSnapshot) -> bool {
    !matches!(group.readiness, GroupReadinessState::Ready)
        && group.total_nodes == 0
        && group.live_nodes == 0
        && !group.primary_object_ref.trim().is_empty()
        && group.primary_object_ref != group.group_id
}

fn apply_status_ready_sink_evidence_cache(snapshot: SinkStatusSnapshot) -> SinkStatusSnapshot {
    let mut cache = match status_ready_sink_evidence_cache().lock() {
        Ok(cache) => cache,
        Err(_) => return snapshot,
    };
    let mut merged = snapshot;
    let mut replacements = BTreeMap::<String, SinkGroupStatusSnapshot>::new();
    for group in &merged.groups {
        let key = status_ready_sink_evidence_key(group);
        if sink_group_has_ready_live_evidence(group) {
            cache.insert(key, group.clone());
        } else if sink_group_is_unready_zero_for_same_primary(group)
            && let Some(cached) = cache.get(&key)
            && sink_group_has_ready_live_evidence(cached)
        {
            replacements.insert(group.group_id.clone(), cached.clone());
        }
    }
    if replacements.is_empty() {
        return merged;
    }
    for group in &mut merged.groups {
        if let Some(cached) = replacements.get(&group.group_id) {
            *group = cached.clone();
        }
    }
    merged.live_nodes = 0;
    merged.tombstoned_count = 0;
    merged.attested_count = 0;
    merged.suspect_count = 0;
    merged.blind_spot_count = 0;
    merged.estimated_heap_bytes = 0;
    merged.shadow_time_us = 0;
    for group in &merged.groups {
        merged.live_nodes += group.live_nodes;
        merged.tombstoned_count += group.tombstoned_count;
        merged.attested_count += group.attested_count;
        merged.suspect_count += group.suspect_count;
        merged.blind_spot_count += group.blind_spot_count;
        merged.estimated_heap_bytes += group.estimated_heap_bytes;
        merged.shadow_time_us = merged.shadow_time_us.max(group.shadow_time_us);
    }
    merged
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum StatusRouteOutcome {
    Skipped,
    Ok,
    Timeout,
    Transport,
    Protocol,
    Internal,
}

impl StatusRouteOutcome {
    fn as_str(self) -> &'static str {
        match self {
            Self::Skipped => "skipped",
            Self::Ok => "ok",
            Self::Timeout => "timeout",
            Self::Transport => "transport",
            Self::Protocol => "protocol",
            Self::Internal => "internal",
        }
    }
}

type StatusSinkRouteResult = Result<SinkStatusSnapshot, CnxError>;
type StatusSourceRouteResult =
    Result<(SourceObservabilitySnapshot, BTreeMap<String, Vec<String>>), CnxError>;

fn local_runner_sets(local_source: &SourceObservabilitySnapshot) -> BTreeMap<String, Vec<String>> {
    local_source
        .last_force_find_runner_by_group
        .iter()
        .map(|(group, runner)| (group.clone(), vec![runner.clone()]))
        .collect()
}

fn merge_source_runner_sets(
    primary: BTreeMap<String, Vec<String>>,
    fallback: BTreeMap<String, Vec<String>>,
) -> BTreeMap<String, Vec<String>> {
    let mut merged = primary
        .into_iter()
        .map(|(group, runners)| (group, runners.into_iter().collect::<BTreeSet<_>>()))
        .collect::<BTreeMap<_, _>>();
    for (group, runners) in fallback {
        merged.entry(group).or_default().extend(runners);
    }
    merged
        .into_iter()
        .map(|(group, runners)| (group, runners.into_iter().collect()))
        .collect()
}

fn merge_api_force_find_runner_evidence(
    runner_sets: BTreeMap<String, Vec<String>>,
    force_find_runner_evidence: &ForceFindRunnerEvidence,
) -> BTreeMap<String, Vec<String>> {
    merge_source_runner_sets(runner_sets, force_find_runner_evidence.snapshot())
}

async fn collect_shared_status_routes_once(
    local_sink: &SinkStatusSnapshot,
    local_source: &SourceObservabilitySnapshot,
    boundary: std::sync::Arc<dyn ChannelIoSubset>,
    node_id: NodeId,
    use_short_observation_budget: bool,
) -> (StatusSinkRouteResult, StatusSourceRouteResult) {
    let local_ready_summary =
        status_local_ready_evidence_completes_management_status(local_sink, local_source, false);
    let use_short_route_budget = local_ready_summary || use_short_observation_budget;
    let route_timeout = if use_short_route_budget {
        STATUS_ROUTE_READY_FALLBACK_GRACE
    } else {
        STATUS_ROUTE_TIMEOUT
    };
    let collect_idle_grace = if use_short_route_budget {
        STATUS_ROUTE_READY_FALLBACK_GRACE
    } else {
        STATUS_ROUTE_COLLECT_IDLE_GRACE
    };
    let sink_future = route_sink_status_snapshot(
        boundary.clone(),
        node_id.clone(),
        crate::query::api::StatusRoutePlan::new(route_timeout, collect_idle_grace),
    );
    let source_future = {
        let source_node_id = node_id;
        async move {
            if local_ready_summary {
                route_source_observability_snapshot_until_first(
                    boundary,
                    source_node_id,
                    route_timeout,
                )
                .await
            } else {
                route_source_observability_snapshot(
                    boundary,
                    source_node_id,
                    route_timeout,
                    collect_idle_grace,
                )
                .await
            }
        }
    };
    tokio::pin!(sink_future);
    tokio::pin!(source_future);

    let mut sink_result = None::<StatusSinkRouteResult>;
    let mut source_result = None::<StatusSourceRouteResult>;
    let hard_deadline = tokio::time::Instant::now() + route_timeout;
    loop {
        if sink_result.is_some() && source_result.is_some() {
            break;
        }
        if sink_result.is_none()
            && let Some(Ok((source_snapshot, _))) = source_result.as_ref()
            && status_local_ready_evidence_completes_management_status(
                local_sink,
                source_snapshot,
                false,
            )
        {
            sink_result = Some(
                match tokio::time::timeout(STATUS_ROUTE_READY_FALLBACK_GRACE, sink_future.as_mut())
                    .await
                {
                    Ok(result) => result,
                    Err(_) => Err(CnxError::Timeout),
                },
            );
            break;
        }
        tokio::select! {
            biased;
            result = sink_future.as_mut(), if sink_result.is_none() => {
                sink_result = Some(result);
            }
            result = source_future.as_mut(), if source_result.is_none() => {
                source_result = Some(result);
            }
            _ = tokio::time::sleep_until(hard_deadline), if sink_result.is_none() || source_result.is_none() => {
                break;
            }
        }
    }

    (
        sink_result.unwrap_or(Err(CnxError::Timeout)),
        source_result.unwrap_or(Err(CnxError::Timeout)),
    )
}

#[cfg(test)]
async fn merge_remote_status_snapshots<SinkCollect, SinkFuture, SourceCollect, SourceFuture>(
    local_sink: SinkStatusSnapshot,
    local_source: SourceObservabilitySnapshot,
    query_runtime_boundary: Option<std::sync::Arc<dyn ChannelIoSubset>>,
    node_id: NodeId,
    sink_collect: SinkCollect,
    source_collect: SourceCollect,
) -> (
    SinkStatusSnapshot,
    SourceObservabilitySnapshot,
    BTreeMap<String, Vec<String>>,
    StatusRouteOutcome,
    StatusRouteOutcome,
)
where
    SinkCollect:
        Fn(std::sync::Arc<dyn ChannelIoSubset>, NodeId) -> SinkFuture + Send + Sync + 'static,
    SinkFuture: Future<Output = Result<SinkStatusSnapshot, CnxError>> + Send,
    SourceCollect:
        Fn(std::sync::Arc<dyn ChannelIoSubset>, NodeId) -> SourceFuture + Send + Sync + 'static,
    SourceFuture: Future<
            Output = Result<(SourceObservabilitySnapshot, BTreeMap<String, Vec<String>>), CnxError>,
        > + Send,
{
    let Some(boundary) = query_runtime_boundary else {
        return (
            local_sink,
            local_source.clone(),
            local_runner_sets(&local_source),
            StatusRouteOutcome::Skipped,
            StatusRouteOutcome::Skipped,
        );
    };

    let retry_boundary = boundary.clone();
    let retry_node_id = node_id.clone();
    let (mut sink_result, mut source_result) = tokio::join!(
        sink_collect(boundary.clone(), node_id.clone()),
        source_collect(boundary, node_id),
    );
    let both_internal = matches!(sink_result, Err(CnxError::Internal(_)))
        && matches!(source_result, Err(CnxError::Internal(_)));
    let both_transport = sink_result
        .as_ref()
        .err()
        .is_some_and(|err| classify_status_route_error(err) == StatusRouteOutcome::Transport)
        && source_result
            .as_ref()
            .err()
            .is_some_and(|err| classify_status_route_error(err) == StatusRouteOutcome::Transport);
    if both_internal || both_transport {
        sink_result = sink_collect(retry_boundary.clone(), retry_node_id.clone()).await;
        source_result = source_collect(retry_boundary, retry_node_id).await;
    }
    let local_source_runner_sets = local_runner_sets(&local_source);

    let (sink_status, sink_outcome) = match sink_result {
        Ok(snapshot) => (
            merge_sink_status_snapshots(vec![local_sink, snapshot]),
            StatusRouteOutcome::Ok,
        ),
        Err(err) => {
            log_status_route_fallback("sink", &err);
            (local_sink, classify_status_route_error(&err))
        }
    };
    let (source, runner_sets, source_outcome) = match source_result {
        Ok((snapshot, runner_sets)) => (
            merge_source_observability(local_source, snapshot),
            merge_source_runner_sets(runner_sets, local_source_runner_sets.clone()),
            StatusRouteOutcome::Ok,
        ),
        Err(err) => {
            log_status_route_fallback("source", &err);
            let mut source = local_source;
            fail_close_incomplete_active_source_observability_snapshot(&mut source);
            (
                source,
                local_source_runner_sets,
                classify_status_route_error(&err),
            )
        }
    };

    (
        sink_status,
        source,
        runner_sets,
        sink_outcome,
        source_outcome,
    )
}

async fn collect_remote_status_snapshots_on_shared_boundary(
    local_sink: SinkStatusSnapshot,
    local_source: SourceObservabilitySnapshot,
    boundary: std::sync::Arc<dyn ChannelIoSubset>,
    node_id: NodeId,
    trace_id: Option<u64>,
    use_short_observation_budget: bool,
) -> (
    SinkStatusSnapshot,
    SourceObservabilitySnapshot,
    BTreeMap<String, Vec<String>>,
    StatusRouteOutcome,
    StatusRouteOutcome,
) {
    let retry_boundary = boundary.clone();
    let retry_node_id = node_id.clone();
    let sink_retry_boundary = boundary.clone();
    let sink_retry_node_id = node_id.clone();
    let route_timeout = if use_short_observation_budget {
        STATUS_ROUTE_READY_FALLBACK_GRACE
    } else {
        STATUS_ROUTE_TIMEOUT
    };
    let mut retryable_gap_deadline = tokio::time::Instant::now() + route_timeout;
    record_status_route_trace(trace_id, "sink.collect.begin");
    record_status_route_trace(trace_id, "source.collect.begin");
    let (mut sink_result, mut source_result) = collect_shared_status_routes_once(
        &local_sink,
        &local_source,
        boundary,
        node_id,
        use_short_observation_budget,
    )
    .await;
    let both_internal = matches!(sink_result, Err(CnxError::Internal(_)))
        && matches!(source_result, Err(CnxError::Internal(_)));
    let both_transport = sink_result
        .as_ref()
        .err()
        .is_some_and(|err| classify_status_route_error(err) == StatusRouteOutcome::Transport)
        && source_result
            .as_ref()
            .err()
            .is_some_and(|err| classify_status_route_error(err) == StatusRouteOutcome::Transport);
    if both_internal || both_transport {
        let collect_idle_grace = if use_short_observation_budget {
            STATUS_ROUTE_READY_FALLBACK_GRACE
        } else {
            STATUS_ROUTE_COLLECT_IDLE_GRACE
        };
        retryable_gap_deadline = tokio::time::Instant::now() + route_timeout;
        sink_result = route_sink_status_snapshot(
            retry_boundary.clone(),
            retry_node_id.clone(),
            crate::query::api::StatusRoutePlan::new(route_timeout, collect_idle_grace),
        )
        .await;
        source_result = route_source_observability_snapshot(
            retry_boundary,
            retry_node_id,
            route_timeout,
            collect_idle_grace,
        )
        .await;
    }
    if let (Ok(sink_snapshot), Ok((source_snapshot, _))) = (&mut sink_result, &source_result)
        && sink_status_snapshot_omits_active_source_groups(source_snapshot, sink_snapshot)
        && !source_snapshot_active_groups(source_snapshot)
            .is_subset(&sink_snapshot_live_materialized_groups(&local_sink))
        && !use_short_observation_budget
    {
        if let Ok(retry_snapshot) = route_sink_status_snapshot(
            sink_retry_boundary,
            sink_retry_node_id,
            crate::query::api::StatusRoutePlan::new(
                STATUS_SINK_ROUTE_RECOLLECT_BUDGET,
                STATUS_ROUTE_COLLECT_IDLE_GRACE,
            ),
        )
        .await
        {
            *sink_snapshot = retry_snapshot;
        }
    }
    let local_source_runner_sets = local_runner_sets(&local_source);

    let (sink_status, sink_outcome) = match sink_result {
        Ok(snapshot) => (
            merge_sink_status_snapshots(vec![local_sink, snapshot]),
            StatusRouteOutcome::Ok,
        ),
        Err(err) => {
            log_status_route_fallback("sink", &err);
            (
                local_sink,
                classify_status_route_collect_error(&err, retryable_gap_deadline),
            )
        }
    };
    record_status_route_trace(
        trace_id,
        format!("sink.collect.outcome={}", sink_outcome.as_str()),
    );
    let (source, runner_sets, source_outcome) = match source_result {
        Ok((snapshot, runner_sets)) => (
            merge_source_observability(local_source, snapshot),
            merge_source_runner_sets(runner_sets, local_source_runner_sets.clone()),
            StatusRouteOutcome::Ok,
        ),
        Err(err) => {
            log_status_route_fallback("source", &err);
            let mut source = local_source;
            fail_close_incomplete_active_source_observability_snapshot(&mut source);
            (
                source,
                local_source_runner_sets,
                classify_status_route_collect_error(&err, retryable_gap_deadline),
            )
        }
    };
    record_status_route_trace(
        trace_id,
        format!("source.collect.outcome={}", source_outcome.as_str()),
    );

    (
        sink_status,
        source,
        runner_sets,
        sink_outcome,
        source_outcome,
    )
}

fn management_status_authoritative_source_root_ids(
    source: &SourceObservabilitySnapshot,
) -> BTreeSet<String> {
    let root_ids = source
        .logical_roots
        .iter()
        .map(|root| root.id.clone())
        .collect::<BTreeSet<_>>();
    if !root_ids.is_empty() {
        return root_ids;
    }

    let mut status_root_ids = source
        .status
        .logical_roots
        .iter()
        .map(|root| root.root_id.clone())
        .collect::<BTreeSet<_>>();
    status_root_ids.extend(
        source
            .status
            .concrete_roots
            .iter()
            .map(|root| root.logical_root_id.clone()),
    );
    status_root_ids
}

fn source_status_current_health_root_ids(source: &SourceObservabilitySnapshot) -> BTreeSet<String> {
    source
        .status
        .logical_roots
        .iter()
        .filter(|root| {
            root.matched_grants > 0
                && root.active_members > 0
                && !root.status.starts_with("waiting_for_root:")
        })
        .map(|root| root.root_id.clone())
        .collect()
}

fn source_status_missing_authoritative_root_ids(
    source: &SourceObservabilitySnapshot,
    expected_root_ids: &BTreeSet<String>,
) -> BTreeSet<String> {
    let current_root_ids = source_status_current_health_root_ids(source);
    expected_root_ids
        .difference(&current_root_ids)
        .cloned()
        .collect()
}

fn source_status_root_ids_needing_current_owner_evidence(
    source: &SourceObservabilitySnapshot,
    expected_root_ids: &BTreeSet<String>,
) -> BTreeSet<String> {
    let mut root_ids = source_status_missing_authoritative_root_ids(source, expected_root_ids);
    for root_id in expected_root_ids {
        let concrete_roots = source
            .status
            .concrete_roots
            .iter()
            .filter(|root| root.logical_root_id == *root_id)
            .collect::<Vec<_>>();
        if concrete_roots.is_empty() {
            root_ids.insert(root_id.clone());
            continue;
        }
        if concrete_roots.iter().any(|root| {
            crate::query::observation::source_concrete_root_needs_current_owner_evidence(root)
        }) && !concrete_roots.iter().any(|root| {
            crate::query::observation::source_concrete_root_has_current_owner_evidence(root)
        }) {
            root_ids.insert(root_id.clone());
        }
    }
    root_ids
}

fn source_status_current_health_covers_authoritative_roots(
    source: &SourceObservabilitySnapshot,
    expected_root_ids: &BTreeSet<String>,
) -> bool {
    !expected_root_ids.is_empty()
        && expected_root_ids.is_subset(&source_status_current_health_root_ids(source))
}

fn clear_explanatory_runtime_scope_cache_marker_when_source_health_complete(
    mut source: SourceObservabilitySnapshot,
    expected_root_ids: &BTreeSet<String>,
) -> SourceObservabilitySnapshot {
    if source_status_current_health_covers_authoritative_roots(&source, expected_root_ids) {
        source.status.degraded_roots.retain(|(root_key, reason)| {
            !(root_key == SOURCE_WORKER_DEGRADED_ROOT_KEY
                && reason == SOURCE_WORKER_RUNTIME_SCOPE_CACHE_REASON)
        });
    }
    source
}

fn clear_worker_status_cache_marker_after_live_merge_when_source_health_complete(
    source: &mut SourceObservabilitySnapshot,
    saw_non_cache_live_snapshot: bool,
) {
    if !saw_non_cache_live_snapshot {
        return;
    }
    let expected_root_ids = management_status_authoritative_source_root_ids(source);
    if source_status_current_health_covers_authoritative_roots(source, &expected_root_ids) {
        source.status.degraded_roots.retain(|(root_key, reason)| {
            !(root_key == SOURCE_WORKER_DEGRADED_ROOT_KEY
                && reason == SOURCE_WORKER_STATUS_CACHE_REASON)
        });
    }
}

fn management_status_should_attempt_short_budget_source_owner_scoped_fanin(
    source_outcome: StatusRouteOutcome,
    source: &SourceObservabilitySnapshot,
    authoritative_source: &SourceObservabilitySnapshot,
) -> bool {
    if !matches!(source_outcome, StatusRouteOutcome::Ok) {
        return false;
    }
    let expected_root_ids = management_status_authoritative_source_root_ids(authoritative_source);
    if expected_root_ids.is_empty() {
        return false;
    }
    let root_ids_needing_owner_evidence =
        source_status_root_ids_needing_current_owner_evidence(source, &expected_root_ids);
    if root_ids_needing_owner_evidence.is_empty() {
        return false;
    }
    !management_status_source_owner_candidate_node_ids(
        source,
        authoritative_source,
        &root_ids_needing_owner_evidence,
    )
    .is_empty()
}

fn management_status_should_attempt_short_budget_sink_owner_scoped_fanin(
    sink: &SinkStatusSnapshot,
    source: &SourceObservabilitySnapshot,
    authoritative_source: &SourceObservabilitySnapshot,
) -> bool {
    let mut expected_group_ids =
        management_status_authoritative_source_root_ids(authoritative_source);
    if expected_group_ids.is_empty() {
        expected_group_ids = sink_snapshot_advertised_groups(sink);
    }
    if expected_group_ids.is_empty() {
        return false;
    }
    let source_runtime_scope_group_ids = source_runtime_scope_scheduled_group_ids(source)
        .into_iter()
        .chain(source_runtime_scope_scheduled_group_ids(
            authoritative_source,
        ))
        .collect::<BTreeSet<_>>();
    let groups_needing_owner_evidence = sink_status_groups_needing_owner_scoped_evidence(
        sink,
        &expected_group_ids,
        &source_runtime_scope_group_ids,
    );
    if groups_needing_owner_evidence.is_empty() {
        return false;
    }
    let speculative_zero_rows_without_sink_owner_evidence =
        sink_status_groups_are_speculative_zero_rows_without_sink_owner_evidence(
            sink,
            &groups_needing_owner_evidence,
        );
    let mut candidate_node_ids = management_status_source_owner_candidate_node_ids(
        source,
        authoritative_source,
        &groups_needing_owner_evidence,
    );
    collect_source_grant_candidate_nodes_for_roots(
        &mut candidate_node_ids,
        source,
        &groups_needing_owner_evidence,
    );
    collect_source_grant_candidate_nodes_for_roots(
        &mut candidate_node_ids,
        authoritative_source,
        &groups_needing_owner_evidence,
    );
    collect_active_source_grant_candidate_nodes(&mut candidate_node_ids, source);
    collect_active_source_grant_candidate_nodes(&mut candidate_node_ids, authoritative_source);
    collect_sink_owner_candidate_nodes_from_snapshot(
        &mut candidate_node_ids,
        sink,
        &groups_needing_owner_evidence,
    );
    !candidate_node_ids.is_empty() || !speculative_zero_rows_without_sink_owner_evidence
}

fn collect_source_owner_candidate_nodes_from_snapshot(
    nodes: &mut BTreeSet<String>,
    source: &SourceObservabilitySnapshot,
    missing_root_ids: &BTreeSet<String>,
) {
    for (root_id, object_ref) in &source.source_primary_by_group {
        if missing_root_ids.contains(root_id)
            && let Some(node_id) = roots_put_control_target_node_id_for_ref_or_node(object_ref)
        {
            nodes.insert(node_id);
        }
    }
    for (node_id, groups) in &source.scheduled_source_groups_by_node {
        if groups.iter().any(|group| missing_root_ids.contains(group))
            && let Some(node_id) = roots_put_control_target_node_id_for_ref_or_node(node_id)
        {
            nodes.insert(node_id);
        }
    }
    for (node_id, groups) in &source.scheduled_scan_groups_by_node {
        if groups.iter().any(|group| missing_root_ids.contains(group))
            && let Some(node_id) = roots_put_control_target_node_id_for_ref_or_node(node_id)
        {
            nodes.insert(node_id);
        }
    }
    for root in source
        .status
        .concrete_roots
        .iter()
        .filter(|root| missing_root_ids.contains(&root.logical_root_id))
    {
        if let Some(node_id) = roots_put_control_target_node_id_for_ref_or_node(&root.object_ref) {
            nodes.insert(node_id);
        }
    }
    for root in source
        .logical_roots
        .iter()
        .filter(|root| missing_root_ids.contains(&root.id))
    {
        for grant in source
            .grants
            .iter()
            .filter(|grant| grant.active && root.selector.matches(grant))
        {
            collect_source_grant_runtime_candidate_nodes(nodes, grant);
        }
    }
}

fn management_status_source_owner_candidate_node_ids(
    source: &SourceObservabilitySnapshot,
    authoritative_source: &SourceObservabilitySnapshot,
    missing_root_ids: &BTreeSet<String>,
) -> BTreeSet<String> {
    let mut nodes = BTreeSet::new();
    collect_source_owner_candidate_nodes_from_snapshot(&mut nodes, source, missing_root_ids);
    collect_source_owner_candidate_nodes_from_snapshot(
        &mut nodes,
        authoritative_source,
        missing_root_ids,
    );
    nodes
}

fn collect_source_grant_candidate_nodes_for_roots(
    nodes: &mut BTreeSet<String>,
    source: &SourceObservabilitySnapshot,
    root_ids: &BTreeSet<String>,
) {
    for root in source
        .logical_roots
        .iter()
        .filter(|root| root_ids.contains(&root.id))
    {
        for grant in source
            .grants
            .iter()
            .filter(|grant| grant.active && root.selector.matches(grant))
        {
            collect_source_grant_runtime_candidate_nodes(nodes, grant);
        }
    }
}

fn collect_active_source_grant_candidate_nodes(
    nodes: &mut BTreeSet<String>,
    source: &SourceObservabilitySnapshot,
) {
    for grant in source.grants.iter().filter(|grant| grant.active) {
        collect_source_grant_runtime_candidate_nodes(nodes, grant);
    }
}

fn collect_source_grant_runtime_candidate_nodes(
    nodes: &mut BTreeSet<String>,
    grant: &GrantedMountRoot,
) {
    if let Some(node_id) = source_node_id_from_grant(grant) {
        nodes.insert(node_id);
    }
    if let Some(node_id) = roots_put_control_target_node_id_for_grant(grant) {
        nodes.insert(node_id);
    }
}

async fn augment_management_status_source_with_owner_scoped_evidence(
    mut source: SourceObservabilitySnapshot,
    authoritative_source: &SourceObservabilitySnapshot,
    boundary: Option<std::sync::Arc<dyn ChannelIoSubset>>,
    origin_id: NodeId,
    owner_scoped_timeout: Duration,
) -> SourceObservabilitySnapshot {
    let expected_root_ids = management_status_authoritative_source_root_ids(authoritative_source);
    if expected_root_ids.is_empty() {
        return source;
    }
    source = clear_explanatory_runtime_scope_cache_marker_when_source_health_complete(
        source,
        &expected_root_ids,
    );
    let root_ids_needing_owner_evidence =
        source_status_root_ids_needing_current_owner_evidence(&source, &expected_root_ids);
    if root_ids_needing_owner_evidence.is_empty() {
        return source;
    }
    let Some(boundary) = boundary else {
        return source;
    };
    let candidate_node_ids = management_status_source_owner_candidate_node_ids(
        &source,
        authoritative_source,
        &root_ids_needing_owner_evidence,
    );
    if candidate_node_ids.is_empty() {
        return source;
    }

    let mut pending = candidate_node_ids
        .into_iter()
        .map(|node_id| {
            let boundary = boundary.clone();
            let origin_id = origin_id.clone();
            async move {
                let result = collect_node_scoped_status_source_observability_origin_snapshot(
                    boundary,
                    origin_id,
                    owner_scoped_timeout,
                    &node_id,
                )
                .await;
                (node_id, result)
            }
        })
        .collect::<FuturesUnordered<_>>();
    while let Some((node_id, result)) = pending.next().await {
        let origin_snapshots = match result {
            Ok(origin_snapshots) => origin_snapshots,
            Err(err) => {
                if debug_status_route_fanin_enabled() {
                    eprintln!(
                        "fs_meta_api_status: source_owner_scoped_collect_failed node={} err={}",
                        node_id, err
                    );
                }
                continue;
            }
        };
        let mut snapshots = Vec::with_capacity(origin_snapshots.len() + 1);
        snapshots.push(source);
        snapshots.extend(origin_snapshots.into_iter().map(|(_, snapshot)| snapshot));
        source = merge_source_observability_snapshots(snapshots);
        if debug_status_route_fanin_enabled() {
            eprintln!(
                "fs_meta_api_status: source_owner_scoped_collect node={} source={}",
                node_id,
                summarize_source_status_route_snapshot(&source)
            );
        }
        source = clear_explanatory_runtime_scope_cache_marker_when_source_health_complete(
            source,
            &expected_root_ids,
        );
        if source_status_root_ids_needing_current_owner_evidence(&source, &expected_root_ids)
            .is_empty()
        {
            break;
        }
    }
    source
}

fn sink_status_reported_group_ids(sink: &SinkStatusSnapshot) -> BTreeSet<String> {
    sink.groups
        .iter()
        .map(|group| group.group_id.clone())
        .collect()
}

fn non_empty_string(value: impl Into<String>) -> Option<String> {
    let value = value.into();
    (!value.trim().is_empty()).then_some(value)
}

fn source_matching_active_grant_for_group<'a>(
    source: &'a SourceObservabilitySnapshot,
    group_id: &str,
) -> Option<&'a GrantedMountRoot> {
    source
        .logical_roots
        .iter()
        .find(|root| root.id == group_id)
        .and_then(|root| {
            source
                .grants
                .iter()
                .find(|grant| grant.active && root.selector.matches(grant))
        })
        .or_else(|| {
            source.grants.iter().find(|grant| {
                grant.active
                    && grant
                        .object_ref
                        .split_once("::")
                        .is_some_and(|(_, root_id)| root_id == group_id)
            })
        })
}

fn source_primary_object_ref_for_sink_group(
    source: &SourceObservabilitySnapshot,
    group_id: &str,
) -> Option<String> {
    source
        .status
        .concrete_roots
        .iter()
        .filter(|root| root.logical_root_id == group_id && root.active)
        .find(|root| root.is_group_primary)
        .and_then(|root| non_empty_string(root.object_ref.clone()))
        .or_else(|| {
            source
                .status
                .concrete_roots
                .iter()
                .find(|root| root.logical_root_id == group_id && root.active)
                .and_then(|root| non_empty_string(root.object_ref.clone()))
        })
        .or_else(|| {
            source
                .source_primary_by_group
                .get(group_id)
                .cloned()
                .and_then(non_empty_string)
        })
        .or_else(|| {
            source_matching_active_grant_for_group(source, group_id)
                .and_then(|grant| non_empty_string(grant.object_ref.clone()))
        })
}

fn pending_authoritative_sink_group_from_source(
    group_id: &str,
    source: &SourceObservabilitySnapshot,
    authoritative_source: &SourceObservabilitySnapshot,
) -> SinkGroupStatusSnapshot {
    let primary_object_ref = source_primary_object_ref_for_sink_group(source, group_id)
        .or_else(|| source_primary_object_ref_for_sink_group(authoritative_source, group_id))
        .unwrap_or_else(|| group_id.to_string());
    SinkGroupStatusSnapshot {
        group_id: group_id.to_string(),
        primary_object_ref,
        total_nodes: 0,
        live_nodes: 0,
        tombstoned_count: 0,
        attested_count: 0,
        suspect_count: 0,
        blind_spot_count: 0,
        shadow_time_us: 0,
        shadow_lag_us: 0,
        overflow_pending_materialization: false,
        readiness: GroupReadinessState::PendingMaterialization,
        materialized_revision: 0,
        estimated_heap_bytes: 0,
    }
}

fn fill_missing_authoritative_pending_sink_groups_from_source(
    mut sink: SinkStatusSnapshot,
    source: &SourceObservabilitySnapshot,
    authoritative_source: &SourceObservabilitySnapshot,
) -> SinkStatusSnapshot {
    let mut expected_group_ids =
        management_status_authoritative_source_root_ids(authoritative_source);
    expected_group_ids.extend(management_status_authoritative_source_root_ids(source));
    if expected_group_ids.is_empty() {
        return sink;
    }

    let reported_group_ids = sink_status_reported_group_ids(&sink);
    let missing_group_ids = expected_group_ids
        .difference(&reported_group_ids)
        .cloned()
        .collect::<Vec<_>>();
    if missing_group_ids.is_empty() {
        return sink;
    }

    for group_id in missing_group_ids {
        sink.groups
            .push(pending_authoritative_sink_group_from_source(
                &group_id,
                source,
                authoritative_source,
            ));
    }
    sink.groups.sort_by(|left, right| {
        left.group_id
            .cmp(&right.group_id)
            .then_with(|| left.primary_object_ref.cmp(&right.primary_object_ref))
    });
    sink
}

fn sink_status_missing_authoritative_group_ids(
    sink: &SinkStatusSnapshot,
    expected_group_ids: &BTreeSet<String>,
) -> BTreeSet<String> {
    let reported_group_ids = sink_status_reported_group_ids(sink);
    expected_group_ids
        .difference(&reported_group_ids)
        .cloned()
        .collect()
}

fn sink_status_has_scheduled_group_evidence(sink: &SinkStatusSnapshot, group_id: &str) -> bool {
    sink.scheduled_groups_by_node
        .values()
        .flatten()
        .any(|scheduled_group| scheduled_group == group_id)
}

fn sink_status_group_needs_owner_scoped_evidence(
    sink: &SinkStatusSnapshot,
    group_id: &str,
    source_runtime_scope_group_ids: &BTreeSet<String>,
) -> bool {
    let lacks_scheduled_group = !sink_status_has_scheduled_group_evidence(sink, group_id);
    let Some(group) = sink.groups.iter().find(|group| group.group_id == group_id) else {
        return true;
    };
    if lacks_scheduled_group
        && (!group.materialized_service_live_ready()
            || source_runtime_scope_group_ids.contains(group_id))
    {
        return true;
    }
    if group.materialized_service_live_ready() {
        return lacks_scheduled_group && sink_status_snapshot_lacks_ingress_evidence(sink);
    }
    sink_group_is_unready_zero_for_same_primary(group)
        || (lacks_scheduled_group && sink_status_snapshot_lacks_ingress_evidence(sink))
}

fn sink_status_groups_needing_owner_scoped_evidence(
    sink: &SinkStatusSnapshot,
    expected_group_ids: &BTreeSet<String>,
    source_runtime_scope_group_ids: &BTreeSet<String>,
) -> BTreeSet<String> {
    let mut group_ids = sink_status_missing_authoritative_group_ids(sink, expected_group_ids);
    group_ids.extend(
        expected_group_ids
            .iter()
            .filter(|group_id| {
                sink_status_group_needs_owner_scoped_evidence(
                    sink,
                    group_id,
                    source_runtime_scope_group_ids,
                )
            })
            .cloned(),
    );
    group_ids
}

fn sink_status_groups_are_speculative_zero_rows_without_sink_owner_evidence(
    sink: &SinkStatusSnapshot,
    group_ids: &BTreeSet<String>,
) -> bool {
    if group_ids.is_empty()
        || !sink.primary_host_ref_by_group.is_empty()
        || !sink_status_snapshot_lacks_ingress_evidence(sink)
    {
        return false;
    }
    group_ids.iter().all(|group_id| {
        sink.groups.iter().any(|group| {
            group.group_id == *group_id
                && group.live_nodes == 0
                && group.total_nodes == 0
                && !matches!(group.readiness, crate::sink::GroupReadinessState::Ready)
        })
    })
}

fn collect_sink_owner_candidate_nodes_from_snapshot(
    nodes: &mut BTreeSet<String>,
    sink: &SinkStatusSnapshot,
    group_ids: &BTreeSet<String>,
) {
    for (group_id, host_ref) in &sink.primary_host_ref_by_group {
        if group_ids.contains(group_id)
            && let Some(node_id) = roots_put_control_target_node_id_for_ref_or_node(host_ref)
        {
            nodes.insert(node_id);
        }
    }
    for (node_id, groups) in &sink.scheduled_groups_by_node {
        if groups.iter().any(|group| group_ids.contains(group))
            && let Some(node_id) = roots_put_control_target_node_id_for_ref_or_node(node_id)
        {
            nodes.insert(node_id);
        }
    }
    for (node_id, signals) in &sink.last_control_frame_signals_by_node {
        if signals
            .iter()
            .any(|signal| group_ids.iter().any(|group_id| signal.contains(group_id)))
            && let Some(node_id) = roots_put_control_target_node_id_for_ref_or_node(node_id)
        {
            nodes.insert(node_id);
        }
    }
}

async fn augment_management_status_sink_with_owner_scoped_evidence(
    mut sink: SinkStatusSnapshot,
    source: &SourceObservabilitySnapshot,
    authoritative_source: &SourceObservabilitySnapshot,
    boundary: Option<std::sync::Arc<dyn ChannelIoSubset>>,
    origin_id: NodeId,
    owner_scoped_timeout: Duration,
) -> SinkStatusSnapshot {
    let mut expected_group_ids =
        management_status_authoritative_source_root_ids(authoritative_source);
    if expected_group_ids.is_empty() {
        expected_group_ids = sink_snapshot_advertised_groups(&sink);
    }
    if expected_group_ids.is_empty() {
        return sink;
    }
    let source_runtime_scope_group_ids = source_runtime_scope_scheduled_group_ids(source)
        .into_iter()
        .chain(source_runtime_scope_scheduled_group_ids(
            authoritative_source,
        ))
        .collect::<BTreeSet<_>>();
    let groups_needing_owner_evidence = sink_status_groups_needing_owner_scoped_evidence(
        &sink,
        &expected_group_ids,
        &source_runtime_scope_group_ids,
    );
    if groups_needing_owner_evidence.is_empty() {
        return sink;
    }
    let speculative_zero_rows_without_sink_owner_evidence =
        sink_status_groups_are_speculative_zero_rows_without_sink_owner_evidence(
            &sink,
            &groups_needing_owner_evidence,
        );
    let Some(boundary) = boundary else {
        return sink;
    };
    let mut candidate_node_ids = management_status_source_owner_candidate_node_ids(
        source,
        authoritative_source,
        &groups_needing_owner_evidence,
    );
    collect_source_grant_candidate_nodes_for_roots(
        &mut candidate_node_ids,
        source,
        &groups_needing_owner_evidence,
    );
    collect_source_grant_candidate_nodes_for_roots(
        &mut candidate_node_ids,
        authoritative_source,
        &groups_needing_owner_evidence,
    );
    collect_active_source_grant_candidate_nodes(&mut candidate_node_ids, source);
    collect_active_source_grant_candidate_nodes(&mut candidate_node_ids, authoritative_source);
    collect_sink_owner_candidate_nodes_from_snapshot(
        &mut candidate_node_ids,
        &sink,
        &groups_needing_owner_evidence,
    );
    if speculative_zero_rows_without_sink_owner_evidence && candidate_node_ids.is_empty() {
        return sink;
    }
    if !speculative_zero_rows_without_sink_owner_evidence
        && let Some(node_id) = roots_put_control_target_node_id_for_ref_or_node(&origin_id.0)
    {
        candidate_node_ids.insert(node_id);
    }
    if candidate_node_ids.is_empty() {
        return sink;
    }

    let mut pending = candidate_node_ids
        .into_iter()
        .map(|node_id| {
            let boundary = boundary.clone();
            let origin_id = origin_id.clone();
            async move {
                let result = collect_node_scoped_status_sink_snapshot(
                    boundary,
                    origin_id,
                    owner_scoped_timeout,
                    &node_id,
                )
                .await;
                (node_id, result)
            }
        })
        .collect::<FuturesUnordered<_>>();
    while let Some((node_id, result)) = pending.next().await {
        let snapshot = match result {
            Ok(snapshot) => snapshot,
            Err(err) => {
                if debug_status_route_fanin_enabled() {
                    eprintln!(
                        "fs_meta_api_status: sink_owner_scoped_collect_failed node={} err={}",
                        node_id, err
                    );
                }
                continue;
            }
        };
        sink = merge_sink_status_snapshots(vec![sink, snapshot]);
        if debug_status_route_fanin_enabled() {
            eprintln!(
                "fs_meta_api_status: sink_owner_scoped_collect node={} sink={}",
                node_id,
                summarize_sink_status_route_snapshot(&sink)
            );
        }
        if sink_status_groups_needing_owner_scoped_evidence(
            &sink,
            &expected_group_ids,
            &source_runtime_scope_group_ids,
        )
        .is_empty()
        {
            break;
        }
    }
    sink
}

fn classify_status_route_error(err: &CnxError) -> StatusRouteOutcome {
    match err {
        CnxError::Timeout => StatusRouteOutcome::Timeout,
        CnxError::ChannelClosed => StatusRouteOutcome::Transport,
        CnxError::TransportClosed(_) => StatusRouteOutcome::Transport,
        CnxError::ProtocolViolation(_) => StatusRouteOutcome::Protocol,
        CnxError::AccessDenied(message)
            if message.contains("drained/fenced") && message.contains("grant attachments")
                || message.contains("invalid or revoked grant attachment token") =>
        {
            StatusRouteOutcome::Transport
        }
        CnxError::PeerError(message)
            if message.contains("transport closed")
                || message.contains("bound route is closed")
                || message.contains("sidecar control bridge")
                || message.contains("sidecar data bridge")
                || message.contains("ipc read len")
                || message.contains("ipc write len")
                || message.contains("Connection reset by peer")
                || message.contains("Broken pipe")
                || message.contains("early eof") =>
        {
            StatusRouteOutcome::Transport
        }
        CnxError::Internal(message)
            if message.contains("transport closed")
                || message.contains("bound route is closed")
                || message.contains("sidecar control bridge")
                || message.contains("sidecar data bridge")
                || message.contains("ipc read len")
                || message.contains("ipc write len")
                || message.contains("Connection reset by peer")
                || message.contains("Broken pipe")
                || message.contains("early eof") =>
        {
            StatusRouteOutcome::Transport
        }
        _ => StatusRouteOutcome::Internal,
    }
}

fn classify_status_route_collect_error(
    err: &CnxError,
    retryable_gap_deadline: tokio::time::Instant,
) -> StatusRouteOutcome {
    let outcome = classify_status_route_error(err);
    if matches!(outcome, StatusRouteOutcome::Transport)
        && tokio::time::Instant::now() >= retryable_gap_deadline
    {
        StatusRouteOutcome::Timeout
    } else {
        outcome
    }
}

fn should_fail_closed_status_route_collection(
    sink_outcome: StatusRouteOutcome,
    source_outcome: StatusRouteOutcome,
    published_facade_state: FacadeServiceState,
    sink_status: &SinkStatusSnapshot,
    source: &SourceObservabilitySnapshot,
    runner_sets: &BTreeMap<String, Vec<String>>,
) -> bool {
    if matches!(
        published_facade_state,
        FacadeServiceState::Pending | FacadeServiceState::Serving | FacadeServiceState::Degraded
    ) {
        return false;
    }
    if status_route_collection_timeout_only(sink_outcome, source_outcome)
        && management_status_has_local_visibility_fallback(sink_status, source, runner_sets)
    {
        return false;
    }
    status_route_collection_incomplete(sink_outcome, source_outcome)
}

fn status_route_collection_timeout_only(
    sink_outcome: StatusRouteOutcome,
    source_outcome: StatusRouteOutcome,
) -> bool {
    matches!(sink_outcome, StatusRouteOutcome::Timeout)
        && matches!(source_outcome, StatusRouteOutcome::Timeout)
}

fn management_status_has_local_visibility_fallback(
    sink_status: &SinkStatusSnapshot,
    source: &SourceObservabilitySnapshot,
    runner_sets: &BTreeMap<String, Vec<String>>,
) -> bool {
    !sink_status.groups.is_empty()
        || sink_status.live_nodes > 0
        || !source.status.logical_roots.is_empty()
        || !source.status.concrete_roots.is_empty()
        || !source.source_primary_by_group.is_empty()
        || !source.last_force_find_runner_by_group.is_empty()
        || !runner_sets.is_empty()
        || !source_observability_snapshot_debug_maps_absent(source)
}

fn should_fail_closed_partial_local_status_fallback(
    sink_outcome: StatusRouteOutcome,
    source_outcome: StatusRouteOutcome,
    published_facade_state: FacadeServiceState,
    sink_status: &SinkStatusSnapshot,
    source: &SourceObservabilitySnapshot,
    runner_sets: &BTreeMap<String, Vec<String>>,
) -> bool {
    matches!(
        published_facade_state,
        FacadeServiceState::Serving | FacadeServiceState::Degraded
    ) && status_route_collection_incomplete(sink_outcome, source_outcome)
        && sink_status.live_nodes == 0
        && sink_status.groups.is_empty()
        && source.status.logical_roots.is_empty()
        && source.status.concrete_roots.is_empty()
        && source.source_primary_by_group.is_empty()
        && source.last_force_find_runner_by_group.is_empty()
        && runner_sets.is_empty()
        && source_observability_snapshot_debug_maps_absent(source)
}

fn should_fail_closed_source_ready_sink_empty_status(
    sink_outcome: StatusRouteOutcome,
    source_outcome: StatusRouteOutcome,
    published_facade_state: FacadeServiceState,
    worker_runtime: bool,
    sink_status: &SinkStatusSnapshot,
    source: &SourceObservabilitySnapshot,
) -> bool {
    if worker_runtime {
        return false;
    }
    if status_route_collection_timeout_only(sink_outcome, source_outcome) {
        return false;
    }
    let source_ready_groups = source_status_current_health_root_ids(source);
    if source_ready_groups.is_empty() {
        return false;
    }
    matches!(
        published_facade_state,
        FacadeServiceState::Serving | FacadeServiceState::Degraded
    ) && status_route_collection_requested(sink_outcome, source_outcome)
        && source_ready_groups.is_subset(&sink_status_reported_group_ids(sink_status))
        && !source_ready_groups.is_subset(&sink_snapshot_live_materialized_groups(sink_status))
        && sink_status_snapshot_is_zeroish_for_active_source_groups(sink_status)
        && sink_status_snapshot_lacks_ingress_evidence(sink_status)
}

fn status_route_collection_incomplete(
    sink_outcome: StatusRouteOutcome,
    source_outcome: StatusRouteOutcome,
) -> bool {
    !matches!(
        sink_outcome,
        StatusRouteOutcome::Skipped | StatusRouteOutcome::Ok
    ) && !matches!(
        source_outcome,
        StatusRouteOutcome::Skipped | StatusRouteOutcome::Ok
    )
}

fn status_route_collection_requested(
    sink_outcome: StatusRouteOutcome,
    source_outcome: StatusRouteOutcome,
) -> bool {
    !matches!(sink_outcome, StatusRouteOutcome::Skipped)
        || !matches!(source_outcome, StatusRouteOutcome::Skipped)
}

fn log_status_route_fallback(label: &str, err: &CnxError) {
    match classify_status_route_error(err) {
        StatusRouteOutcome::Timeout
        | StatusRouteOutcome::Transport
        | StatusRouteOutcome::Protocol => {
            log::warn!("status falling back to local {label} snapshot after route error: {err}");
        }
        StatusRouteOutcome::Internal => {
            log::warn!("status falling back to local {label} snapshot: {err}");
        }
        StatusRouteOutcome::Skipped | StatusRouteOutcome::Ok => {}
    }
}

fn source_snapshot_api_error(label: &str, err: &CnxError) -> ApiError {
    let message = err.to_string();
    if matches!(err, CnxError::TransportClosed(_)) || message.contains("channel closed") {
        return ApiError::service_unavailable(format!(
            "{label} temporarily unavailable while runtime workers reconfigure: {message}"
        ));
    }
    if matches!(err, CnxError::ResourceExhausted(_))
        || (message.contains("resource exhausted")
            && (message.contains("source worker unavailable") || message.contains("max channels")))
    {
        return ApiError::service_unavailable(format!(
            "{label} temporarily unavailable while runtime workers are under resource pressure: {message}"
        ));
    }
    ApiError::internal(format!("{label} failed: {message}"))
}

pub async fn runtime_grants(
    State(state): State<ApiState>,
    headers: HeaderMap,
) -> Result<Json<RuntimeGrantsResponse>, ApiError> {
    let _ = authorize_management(&state, &headers)?;
    Ok(Json(RuntimeGrantsResponse {
        grants: state
            .source
            .host_object_grants_snapshot_with_failure()
            .await
            .map_err(|err| source_snapshot_api_error("source grants snapshot", err.as_error()))?,
    }))
}

pub async fn roots_get(
    State(state): State<ApiState>,
    headers: HeaderMap,
) -> Result<Json<RootsResponse>, ApiError> {
    let _ = authorize_management(&state, &headers)?;
    let roots = state
        .source
        .logical_roots_snapshot_with_failure()
        .await
        .map_err(|err| {
            ApiError::internal(format!(
                "source logical roots snapshot failed: {}",
                err.as_error()
            ))
        })?
        .into_iter()
        .map(root_entry_from_spec)
        .collect();
    Ok(Json(RootsResponse { roots }))
}

pub async fn roots_preview(
    State(state): State<ApiState>,
    headers: HeaderMap,
    Json(req): Json<RootsUpdateRequest>,
) -> Result<Json<RootsPreviewResponse>, ApiError> {
    let _ = authorize_management(&state, &headers)?;
    eprintln!(
        "fs_meta_api: roots_preview request roots={}",
        req.roots.len()
    );
    let mut roots = Vec::with_capacity(req.roots.len());
    for entry in req.roots {
        match root_spec_from_update(entry) {
            Ok(root) => roots.push(root),
            Err(err) => {
                eprintln!("fs_meta_api: roots_preview invalid input: {}", err.message);
                return Err(err);
            }
        }
    }
    let grants = state
        .source
        .host_object_grants_snapshot_with_failure()
        .await
        .map_err(|err| {
            eprintln!(
                "fs_meta_api: roots_preview grants snapshot failed: {}",
                err.as_error()
            );
            source_snapshot_api_error("source grants snapshot", err.as_error())
        })?;
    Ok(Json(preview_roots(&roots, &grants)?))
}

pub async fn roots_put(
    State(state): State<ApiState>,
    headers: HeaderMap,
    Json(req): Json<RootsUpdateRequest>,
) -> Result<Json<RootsUpdateResponse>, ApiError> {
    let _ = authorize_management(&state, &headers)?;
    wait_roots_put_management_write_ready(&state).await?;
    let roots = req
        .roots
        .into_iter()
        .map(root_spec_from_update)
        .collect::<Result<Vec<_>, _>>()?;
    validate_unique_root_ids(&roots)?;
    eprintln!("fs_meta_api: roots_put request roots={}", roots.len());

    let grants = state
        .source
        .host_object_grants_snapshot_with_failure()
        .await
        .map_err(|err| source_snapshot_api_error("source grants snapshot", err.as_error()))?;
    eprintln!(
        "fs_meta_api: roots_put grants snapshot ok grants={}",
        grants.len()
    );
    let preview = preview_roots(&roots, &grants)?;
    if !preview.unmatched_roots.is_empty() {
        return Err(ApiError::bad_request(format!(
            "roots update rejected: unmatched runtime grants for roots [{}]",
            preview.unmatched_roots.join(", ")
        )));
    }
    eprintln!("fs_meta_api: roots_put preview ok roots={}", roots.len());

    let previous_source_roots = state
        .source
        .logical_roots_snapshot_with_failure()
        .await
        .map_err(|err| {
            ApiError::internal(format!(
                "source logical roots snapshot failed: {}",
                err.as_error()
            ))
        })?;
    eprintln!(
        "fs_meta_api: roots_put previous source roots ok roots={}",
        previous_source_roots.len()
    );
    #[cfg(test)]
    maybe_pause_roots_put_after_previous_source_roots(&roots).await;
    let previous_grants = grants.clone();
    let previous_sink_roots = state
        .sink
        .cached_logical_roots_snapshot_with_failure()
        .map_err(|err| {
            eprintln!(
                "fs_meta_api: roots_put previous sink roots unavailable: {}",
                err.as_error()
            );
            ApiError::internal(format!(
                "previous sink roots snapshot unavailable: {}",
                err.as_error()
            ))
        })?;
    eprintln!(
        "fs_meta_api: roots_put previous sink roots ok roots={}",
        previous_sink_roots.len()
    );
    // roots apply updates app-owned authoritative root/group definitions and
    // refreshes source/sink state against current runtime grants and bound
    // scopes. It does not make the API the owner of runtime bind/run
    // realization.
    state
        .source
        .update_logical_roots_with_failure(roots.clone())
        .await
        .map_err(|err| {
            eprintln!(
                "fs_meta_api: roots_put source update failed: {}",
                err.as_error()
            );
            ApiError::internal(format!("source roots update failed: {}", err.as_error()))
        })?;
    eprintln!(
        "fs_meta_api: roots_put source update ok roots={}",
        roots.len()
    );
    if let Err(err) = state
        .sink
        .update_logical_roots_from_management_apply_with_failure(roots.clone(), &grants)
        .await
    {
        eprintln!(
            "fs_meta_api: roots_put sink sync failed: {}",
            err.as_error()
        );
        let sink_rollback = state
            .sink
            .update_logical_roots_from_management_apply_with_failure(
                previous_sink_roots,
                &previous_grants,
            )
            .await;
        let source_rollback = state
            .source
            .update_logical_roots_with_failure(previous_source_roots)
            .await;
        return match (sink_rollback, source_rollback) {
            (Ok(()), Ok(())) => Err(ApiError::internal(format!(
                "roots update aborted: sink sync failed: {}",
                err.as_error()
            ))),
            (Err(sink_rollback_err), Ok(())) => Err(ApiError::internal(format!(
                "roots update diverged after sink sync failure: sink={}; sink_rollback={}",
                err.as_error(),
                sink_rollback_err.as_error()
            ))),
            (Ok(()), Err(source_rollback_err)) => Err(ApiError::internal(format!(
                "roots update diverged after sink sync failure: sink={}; source_rollback={}",
                err.as_error(),
                source_rollback_err.as_error()
            ))),
            (Err(sink_rollback_err), Err(source_rollback_err)) => Err(ApiError::internal(format!(
                "roots update diverged after sink sync failure: sink={}; sink_rollback={}; source_rollback={}",
                err.as_error(),
                sink_rollback_err.as_error(),
                source_rollback_err.as_error()
            ))),
        };
    }
    eprintln!(
        "fs_meta_api: roots_put sink update ok roots={}",
        roots.len()
    );
    let second_wave_context = roots_put_second_wave_context_with_current_generation(&state).await?;
    let mut initial_target_node_ids =
        derive_roots_put_control_target_node_ids_for_declaration_replacement(
            &state.node_id,
            &roots,
            &grants,
            &previous_source_roots,
            &previous_sink_roots,
            &previous_grants,
        );
    if roots_put_replacement_needs_routed_owner_discovery(
        &grants,
        &previous_source_roots,
        &previous_sink_roots,
    ) {
        initial_target_node_ids.extend(
            discover_roots_put_control_target_node_ids_with_boundary(
                state.query_runtime_boundary.clone(),
                state.node_id.clone(),
            )
            .await,
        );
    }
    send_roots_put_control_second_wave(&second_wave_context, &roots, &initial_target_node_ids)
        .await?;
    refresh_policy_from_host_object_grants(&state.projection_policy, &grants);
    eprintln!("fs_meta_api: roots_put policy refresh ok");
    spawn_roots_put_source_second_wave_followup(
        second_wave_context,
        roots.clone(),
        initial_target_node_ids,
    );
    #[cfg(test)]
    maybe_pause_roots_put_before_response(&roots).await;

    Ok(Json(RootsUpdateResponse {
        roots_count: roots.len(),
    }))
}

async fn wait_roots_put_management_write_ready(state: &ApiState) -> Result<(), ApiError> {
    if state.control_gate.is_management_write_ready() {
        return Ok(());
    }
    if state.control_gate.is_management_write_drain_closed() {
        return Err(ApiError::service_unavailable(
            "fs-meta management request handling is unavailable until runtime control initializes the app",
        ));
    }
    if let Some(recovery) = state.control_gate.management_write_recovery() {
        tokio::spawn(async move {
            if let Err(err) = recovery().await {
                eprintln!(
                    "fs_meta_api: roots_put management write readiness recovery failed err={err}"
                );
            }
        });
    }
    if !state.control_gate.is_management_write_ready()
        && tokio::time::timeout(
            Duration::from_secs(15),
            state.control_gate.wait_management_write_ready(),
        )
        .await
        .is_err()
    {
        return Err(ApiError::service_unavailable(
            "fs-meta management request handling is unavailable until runtime control initializes the app",
        ));
    }
    Ok(())
}

pub async fn rescan(
    State(state): State<ApiState>,
    headers: HeaderMap,
) -> Result<Json<RescanResponse>, ApiError> {
    let _ = authorize_management(&state, &headers)?;
    let _facade_request_guard = state.request_tracker.begin();
    if let Some(boundary) = state.runtime_boundary.as_ref() {
        eprintln!(
            "fs_meta_api: rescan via runtime_boundary node={}",
            state.node_id.0
        );
        let requested_at_us = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .map(|d| d.as_micros().min(u128::from(u64::MAX)) as u64)
            .unwrap_or(0);
        let request_sequence = MANUAL_RESCAN_REQUEST_SEQUENCE.fetch_add(1, Ordering::Relaxed);
        let request_id = format!(
            "{}:{}:{}",
            state.node_id.0, requested_at_us, request_sequence
        );
        let envelope =
            encode_manual_rescan_envelope_with_request_id_and_scoped_target_acceptance_timeout(
                request_id,
                requested_at_us,
                Some(manual_rescan_scoped_target_acceptance_timeout()),
            )
            .map_err(|err| {
                ApiError::internal(format!("manual rescan envelope encode failed: {err}"))
            })?;
        let payload = rmp_serde::to_vec_named(&envelope).map_err(|err| {
            ApiError::internal(format!("manual rescan envelope serialize failed: {err}"))
        })?;
        let payload = bytes::Bytes::from(payload);
        let (roots, grants, mut active_source_node_ids) = {
            let roots = state
                .source
                .manual_rescan_logical_roots_snapshot_with_failure()
                .await
                .map_err(|err| {
                    source_snapshot_api_error(
                        "manual rescan source logical roots snapshot",
                        err.as_error(),
                    )
                })?;
            let grants = state
                .source
                .host_object_grants_snapshot_with_failure()
                .await
                .map_err(|err| {
                    source_snapshot_api_error(
                        "manual rescan source grants snapshot",
                        err.as_error(),
                    )
                })?;
            let active_source_node_ids =
                manual_rescan_delivery_fallback_node_ids_from_current_roots(
                    &state.node_id,
                    &roots,
                    &grants,
                );
            (roots, grants, active_source_node_ids)
        };
        run_manual_rescan_source_repair_if_current_roots_incomplete(&state, &roots).await;
        if manual_rescan_should_run_current_roots_preflight(&roots, &active_source_node_ids) {
            match tokio::time::timeout(
                MANUAL_RESCAN_CURRENT_ROOTS_PREFLIGHT_TIMEOUT,
                wait_manual_rescan_current_roots_runtime_scope_readiness(&state, &roots, &grants),
            )
            .await
            {
                Ok(Ok(Some(runtime_source_primary_node_ids))) => {
                    active_source_node_ids = manual_rescan_scoped_delivery_targets_after_preflight(
                        Some(runtime_source_primary_node_ids),
                    );
                }
                Ok(Ok(None)) => {
                    active_source_node_ids =
                        manual_rescan_scoped_delivery_targets_after_preflight(None);
                }
                Ok(Err(err)) if err.status == StatusCode::SERVICE_UNAVAILABLE => {
                    eprintln!(
                        "fs_meta_api: manual rescan current-roots observation incomplete; refusing grant fallback before scoped delivery: {}",
                        err.message
                    );
                    return Err(ApiError::service_unavailable(format!(
                        "manual rescan current roots runtime-scope readiness failed: {}",
                        err.message
                    )));
                }
                Ok(Err(err)) => return Err(err),
                Err(_) => {
                    eprintln!(
                        "fs_meta_api: manual rescan current-roots observation window elapsed; refusing grant fallback before scoped delivery targets={:?}",
                        active_source_node_ids
                    );
                    return Err(ApiError::service_unavailable(
                        "manual rescan current roots runtime-scope readiness failed: operation timed out before scoped delivery target proof",
                    ));
                }
            }
        }
        eprintln!(
            "fs_meta_api: rescan source targets ready node={} targets={:?}",
            state.node_id.0, active_source_node_ids
        );
        if active_source_node_ids.is_empty() {
            eprintln!(
                "fs_meta_api: rescan control send begin route={}.stream",
                ROUTE_KEY_SOURCE_RESCAN_CONTROL
            );
            match boundary
                .channel_send(
                    BoundaryContext::default(),
                    ChannelSendRequest {
                        channel_key: ChannelKey(format!(
                            "{}.stream",
                            ROUTE_KEY_SOURCE_RESCAN_CONTROL
                        )),
                        events: vec![Event::new(
                            EventMetadata {
                                origin_id: state.node_id.clone(),
                                timestamp_us: 0,
                                logical_ts: None,
                                correlation_id: None,
                                ingress_auth: None,
                                trace: None,
                            },
                            payload.clone(),
                        )],
                        timeout_ms: Some(Duration::from_secs(5).as_millis() as u64),
                    },
                )
                .await
            {
                Ok(()) => {
                    eprintln!(
                        "fs_meta_api: rescan control send ok route={}.stream",
                        ROUTE_KEY_SOURCE_RESCAN_CONTROL
                    );
                    collect_manual_rescan_requests(
                        boundary.clone(),
                        state.node_id.clone(),
                        payload.clone(),
                    )
                    .await
                    .map_err(manual_rescan_generic_source_route_api_error)?;
                    eprintln!(
                        "fs_meta_api: rescan runtime delivery accepted node={} scoped_targets={:?}",
                        state.node_id.0, active_source_node_ids
                    );
                }
                Err(err) if is_stale_drained_pid_control_send_error(&err) => {
                    eprintln!(
                        "fs_meta_api: rescan control send tolerated stale drained pid route={} err={}",
                        ROUTE_KEY_SOURCE_RESCAN_CONTROL, err
                    );
                    state
                        .source
                        .publish_manual_rescan_signal_with_failure()
                        .await
                        .map_err(|signal_err| {
                            ApiError::internal(format!(
                                "manual rescan signal publish failed after stale drained control pid: {}",
                                signal_err.as_error()
                            ))
                        })?;
                }
                Err(err) => {
                    return Err(ApiError::internal(format!(
                        "manual rescan control send failed: {err}"
                    )));
                }
            }
        } else {
            eprintln!(
                "fs_meta_api: rescan scoped delivery begin node={} targets={:?}",
                state.node_id.0, active_source_node_ids
            );
            match collect_scoped_manual_rescan_requests_until_converged(
                boundary.clone(),
                state.node_id.clone(),
                payload.clone(),
                &active_source_node_ids,
                MANUAL_RESCAN_SCOPED_DELIVERY_CONVERGENCE_TIMEOUT,
            )
            .await
            {
                Ok(_) => {}
                Err(err)
                    if manual_rescan_scoped_source_delivery_error_is_pending(&err)
                        && manual_rescan_scoped_delivery_confirmed_by_source_status(
                            &state,
                            &roots,
                            &active_source_node_ids,
                            requested_at_us,
                        )
                        .await =>
                {
                    eprintln!(
                        "fs_meta_api: rescan scoped delivery accepted by source-status proof node={} targets={:?}",
                        state.node_id.0, active_source_node_ids
                    );
                }
                Err(err) => return Err(manual_rescan_scoped_source_route_api_error(err)),
            }
            eprintln!(
                "fs_meta_api: rescan runtime delivery accepted node={} scoped_targets={:?}",
                state.node_id.0, active_source_node_ids
            );
        }
    } else {
        eprintln!(
            "fs_meta_api: rescan via local source node={}",
            state.node_id.0
        );
        let _ = state
            .source
            .trigger_rescan_when_ready_epoch_with_failure()
            .await
            .map_err(|err| {
                ApiError::internal(format!(
                    "trigger rescan when ready failed: {}",
                    err.as_error()
                ))
            })?;
    }
    #[cfg(test)]
    maybe_pause_rescan_before_return().await;
    Ok(Json(RescanResponse { accepted: true }))
}

fn active_source_rescan_node_ids_from_current_roots(
    roots: &[RootSpec],
    grants: &[GrantedMountRoot],
) -> BTreeSet<String> {
    grants
        .iter()
        .filter(|grant| grant.active)
        .filter(|grant| roots.iter().any(|root| root.selector.matches(grant)))
        .filter_map(source_node_id_from_grant)
        .collect()
}

fn manual_rescan_current_roots_runtime_scope_snapshot_from_active_grants(
    roots: &[RootSpec],
    grants: &[GrantedMountRoot],
) -> Option<SourceObservabilitySnapshot> {
    if roots.is_empty() {
        return None;
    }

    let mut status_logical_roots = Vec::new();
    let mut concrete_roots = Vec::new();
    let mut source_primary_by_group = BTreeMap::new();
    let mut scheduled_source_groups_by_node = BTreeMap::<String, Vec<String>>::new();
    let mut scheduled_scan_groups_by_node = BTreeMap::<String, Vec<String>>::new();

    for root in roots {
        let matching_grants = grants
            .iter()
            .filter(|grant| grant.active && root.selector.matches(grant))
            .filter_map(|grant| source_node_id_from_grant(grant).map(|node_id| (grant, node_id)))
            .collect::<Vec<_>>();
        let active_members = matching_grants.len();
        status_logical_roots.push(SourceLogicalRootHealthSnapshot {
            root_id: root.id.clone(),
            status: if active_members > 0 {
                "healthy".to_string()
            } else {
                "waiting_for_root:grant".to_string()
            },
            matched_grants: active_members,
            active_members,
            coverage_mode: "grant_derived_current_roots".to_string(),
        });

        for (grant_index, (grant, node_id)) in matching_grants.into_iter().enumerate() {
            let primary_ref = source_primary_by_group
                .entry(root.id.clone())
                .or_insert_with(|| grant.object_ref.clone())
                .clone();
            if root.watch {
                scheduled_source_groups_by_node
                    .entry(node_id.clone())
                    .or_default()
                    .push(root.id.clone());
            }
            if root.scan {
                scheduled_scan_groups_by_node
                    .entry(node_id.clone())
                    .or_default()
                    .push(root.id.clone());
            }
            concrete_roots.push(SourceConcreteRootHealthSnapshot {
                root_key: format!("{}@{}#{grant_index}", root.id, node_id),
                logical_root_id: root.id.clone(),
                object_ref: grant.object_ref.clone(),
                status: "healthy".to_string(),
                coverage_mode: "grant_derived_current_roots".to_string(),
                watch_enabled: root.watch,
                scan_enabled: root.scan,
                is_group_primary: primary_ref == grant.object_ref,
                active: true,
                watch_lru_capacity: 0,
                audit_interval_ms: root.audit_interval_ms.unwrap_or_default(),
                overflow_count: 0,
                overflow_pending: false,
                rescan_pending: false,
                last_rescan_requested_at_us: None,
                last_rescan_reason: None,
                last_error: None,
                last_audit_started_at_us: None,
                last_audit_completed_at_us: None,
                last_audit_duration_ms: None,
                emitted_batch_count: 0,
                emitted_event_count: 0,
                emitted_control_event_count: 0,
                emitted_data_event_count: 0,
                emitted_path_capture_target: None,
                emitted_path_event_count: 0,
                last_emitted_at_us: None,
                last_emitted_origins: Vec::new(),
                forwarded_batch_count: 0,
                forwarded_event_count: 0,
                forwarded_path_event_count: 0,
                last_forwarded_at_us: None,
                last_forwarded_origins: Vec::new(),
                current_revision: None,
                current_stream_generation: None,
                candidate_revision: None,
                candidate_stream_generation: None,
                candidate_status: None,
                draining_revision: None,
                draining_stream_generation: None,
                draining_status: None,
            });
        }
    }

    for groups in scheduled_source_groups_by_node
        .values_mut()
        .chain(scheduled_scan_groups_by_node.values_mut())
    {
        groups.sort();
        groups.dedup();
    }

    Some(SourceObservabilitySnapshot {
        lifecycle_state: "grant_derived_current_roots".to_string(),
        host_object_grants_version: 0,
        grants: grants.to_vec(),
        logical_roots: roots.to_vec(),
        status: SourceStatusSnapshot {
            current_stream_generation: None,
            logical_roots: status_logical_roots,
            concrete_roots,
            degraded_roots: Vec::new(),
        },
        source_primary_by_group,
        last_force_find_runner_by_group: BTreeMap::new(),
        force_find_inflight_groups: Vec::new(),
        scheduled_source_groups_by_node,
        scheduled_scan_groups_by_node,
        last_control_frame_signals_by_node: BTreeMap::new(),
        published_batches_by_node: BTreeMap::new(),
        published_events_by_node: BTreeMap::new(),
        published_control_events_by_node: BTreeMap::new(),
        published_data_events_by_node: BTreeMap::new(),
        last_published_at_us_by_node: BTreeMap::new(),
        last_published_origins_by_node: BTreeMap::new(),
        published_origin_counts_by_node: BTreeMap::new(),
        published_path_capture_target: None,
        enqueued_path_origin_counts_by_node: BTreeMap::new(),
        pending_path_origin_counts_by_node: BTreeMap::new(),
        yielded_path_origin_counts_by_node: BTreeMap::new(),
        summarized_path_origin_counts_by_node: BTreeMap::new(),
        published_path_origin_counts_by_node: BTreeMap::new(),
    })
}

fn manual_rescan_delivery_fallback_node_ids_from_current_roots(
    node_id: &NodeId,
    roots: &[RootSpec],
    grants: &[GrantedMountRoot],
) -> BTreeSet<String> {
    let mut node_ids = active_source_rescan_node_ids_from_current_roots(roots, grants);
    if local_source_node_owns_any_current_root(node_id, roots, grants)
        && node_ids
            .iter()
            .any(|candidate| runtime_node_identity_matches(candidate, &node_id.0))
    {
        node_ids.retain(|candidate| !runtime_node_identity_matches(candidate, &node_id.0));
        node_ids.insert(node_id.0.clone());
    }
    retain_most_specific_runtime_node_identities(&mut node_ids);
    node_ids
}

fn manual_rescan_scoped_delivery_targets_after_preflight(
    runtime_source_primary_node_ids: Option<BTreeSet<String>>,
) -> BTreeSet<String> {
    runtime_source_primary_node_ids.unwrap_or_default()
}

fn manual_rescan_should_run_current_roots_preflight(
    roots: &[RootSpec],
    active_source_node_ids: &BTreeSet<String>,
) -> bool {
    !roots.is_empty() || !active_source_node_ids.is_empty()
}

fn source_node_id_from_grant(grant: &GrantedMountRoot) -> Option<String> {
    let host_ref = grant.host_ref.trim();
    if !host_ref.is_empty() {
        return Some(host_ref.to_string());
    }
    roots_put_control_target_node_id_for_grant(grant)
}

fn runtime_node_identity_matches(left: &str, right: &str) -> bool {
    if left == right {
        return true;
    }
    left.strip_prefix(right)
        .is_some_and(|suffix| suffix.starts_with('-'))
        || right
            .strip_prefix(left)
            .is_some_and(|suffix| suffix.starts_with('-'))
        || left.strip_prefix("cluster-").is_some_and(|left_scoped| {
            left_scoped == right
                || left_scoped
                    .strip_prefix(right)
                    .is_some_and(|suffix| suffix.starts_with('-'))
        })
        || right.strip_prefix("cluster-").is_some_and(|right_scoped| {
            right_scoped == left
                || right_scoped
                    .strip_prefix(left)
                    .is_some_and(|suffix| suffix.starts_with('-'))
        })
}

fn retain_most_specific_runtime_node_identities(node_ids: &mut BTreeSet<String>) {
    let identities = node_ids.iter().cloned().collect::<Vec<_>>();
    node_ids.retain(|candidate| {
        !identities.iter().any(|other| {
            other != candidate
                && other.len() > candidate.len()
                && runtime_node_identity_matches(candidate, other)
        })
    });
}

fn source_primary_runtime_node_id_from_ref(
    primary_ref: &str,
    grants: &[GrantedMountRoot],
) -> Option<String> {
    grants
        .iter()
        .find(|grant| grant.object_ref == primary_ref)
        .and_then(source_node_id_from_grant)
        .or_else(|| {
            primary_ref
                .split_once("::")
                .map(|(node_id, _)| node_id.to_string())
        })
        .or_else(|| (!primary_ref.is_empty()).then(|| primary_ref.to_string()))
}

fn source_runtime_scope_nodes_for_group(
    source: &SourceObservabilitySnapshot,
    group_id: &str,
) -> BTreeSet<String> {
    source
        .scheduled_source_groups_by_node
        .iter()
        .chain(source.scheduled_scan_groups_by_node.iter())
        .filter(|(_, groups)| groups.iter().any(|group| group == group_id))
        .map(|(node_id, _)| node_id.clone())
        .collect()
}

fn source_node_reports_runtime_scope_group(
    source: &SourceObservabilitySnapshot,
    group_id: &str,
    node_id: &str,
) -> bool {
    source
        .scheduled_source_groups_by_node
        .iter()
        .chain(source.scheduled_scan_groups_by_node.iter())
        .any(|(observed_node_id, groups)| {
            runtime_node_identity_matches(observed_node_id, node_id)
                && groups.iter().any(|group| group == group_id)
        })
}

fn source_node_reports_scan_runtime_scope_group(
    source: &SourceObservabilitySnapshot,
    group_id: &str,
    node_id: &str,
) -> bool {
    source
        .scheduled_scan_groups_by_node
        .iter()
        .any(|(observed_node_id, groups)| {
            runtime_node_identity_matches(observed_node_id, node_id)
                && groups.iter().any(|group| group == group_id)
        })
}

fn source_control_signal_generation(signal: &str) -> Option<u64> {
    let (_, suffix) = signal.split_once("generation=")?;
    let digits = suffix
        .chars()
        .take_while(|ch| ch.is_ascii_digit())
        .collect::<String>();
    (!digits.is_empty())
        .then(|| digits.parse::<u64>().ok())
        .flatten()
}

fn source_control_signal_applies_to_group(signal: &str, group_id: &str) -> bool {
    if !(signal.contains("unit=runtime.exec.source") || signal.contains("unit=runtime.exec.scan")) {
        return false;
    }
    match signal.split_once("scopes=") {
        Some((_prefix, scopes)) => scopes.contains(&format!("{group_id}=>")),
        None => true,
    }
}

fn source_ready_control_signal_applies_to_group(signal: &str, group_id: &str) -> bool {
    if signal.contains("ready ") && !signal.contains("scopes=") {
        return false;
    }
    source_control_signal_applies_to_group(signal, group_id)
}

fn source_control_signal_scope_targets_for_group(signal: &str, group_id: &str) -> Vec<String> {
    let Some((_prefix, scopes)) = signal.split_once("scopes=") else {
        return Vec::new();
    };
    let marker = format!("{group_id}=>");
    scopes
        .split(&marker)
        .skip(1)
        .filter_map(|suffix| {
            let target = suffix
                .chars()
                .take_while(|ch| {
                    !ch.is_whitespace() && *ch != '"' && *ch != '\'' && *ch != ',' && *ch != ']'
                })
                .collect::<String>();
            (!target.is_empty()).then_some(target)
        })
        .collect()
}

fn source_control_signal_defines_owner_runtime_scope(signal: &str, group_id: &str) -> bool {
    signal.contains("activate ")
        && source_control_signal_applies_to_group(signal, group_id)
        && source_control_signal_scope_targets_for_group(signal, group_id)
            .into_iter()
            .any(|target| target != group_id)
}

fn source_owner_scope_control_generation_for_group_node(
    source: &SourceObservabilitySnapshot,
    group_id: &str,
    node_id: &str,
) -> Option<u64> {
    source
        .last_control_frame_signals_by_node
        .get(node_id)?
        .iter()
        .filter(|signal| source_control_signal_defines_owner_runtime_scope(signal, group_id))
        .filter_map(|signal| source_control_signal_generation(signal))
        .max()
}

#[cfg(test)]
fn source_runtime_scope_control_generation_for_group_node(
    source: &SourceObservabilitySnapshot,
    group_id: &str,
    node_id: &str,
) -> Option<u64> {
    source
        .last_control_frame_signals_by_node
        .get(node_id)?
        .iter()
        .filter(|signal| source_control_signal_defines_runtime_scope(signal, group_id))
        .filter_map(|signal| source_control_signal_generation(signal))
        .max()
}

#[cfg(test)]
fn source_control_signal_defines_runtime_scope(signal: &str, group_id: &str) -> bool {
    signal.contains("activate ") && source_control_signal_applies_to_group(signal, group_id)
}

fn source_has_current_runtime_scope_generation_for_group(
    source: &SourceObservabilitySnapshot,
    group_id: &str,
    node_id: &str,
) -> bool {
    let candidate_groups = source_runtime_scope_candidate_groups(source);
    let Some(latest_generation) =
        source_latest_control_generation_by_group(source, &candidate_groups)
            .get(group_id)
            .copied()
    else {
        return true;
    };
    source_owner_scope_control_generation_for_group_node(source, group_id, node_id)
        .is_some_and(|generation| generation == latest_generation)
}

fn source_primary_matching_runtime_scope_nodes(
    source: &SourceObservabilitySnapshot,
    group_id: &str,
    primary_ref: &str,
) -> BTreeSet<String> {
    let Some(primary_node_id) =
        source_primary_runtime_node_id_from_ref(primary_ref, &source.grants)
    else {
        return BTreeSet::new();
    };
    source_runtime_scope_nodes_for_group(source, group_id)
        .into_iter()
        .filter(|node_id| runtime_node_identity_matches(node_id, &primary_node_id))
        .collect()
}

fn source_origin_entry_matches_object_ref_for_node(
    source: &SourceObservabilitySnapshot,
    object_ref: &str,
    origin_node_id: &str,
    origin_group_id: &str,
) -> bool {
    if object_ref == origin_group_id || object_ref == format!("{origin_node_id}::{origin_group_id}")
    {
        return true;
    }
    source_primary_runtime_node_id_from_ref(object_ref, &source.grants).is_some_and(
        |object_node_id| {
            runtime_node_identity_matches(&object_node_id, origin_node_id)
                && object_ref
                    .rsplit_once("::")
                    .is_some_and(|(_, tail)| tail == origin_group_id)
        },
    )
}

fn source_origin_entry_matches_group_node(
    source: &SourceObservabilitySnapshot,
    entry: &str,
    group_id: &str,
    node_id: &str,
) -> bool {
    let key = entry.split('=').next().unwrap_or(entry);
    let Some((origin_node_id, origin_group_id)) = key.split_once("::") else {
        return false;
    };
    if !runtime_node_identity_matches(origin_node_id, node_id) {
        return false;
    }
    if origin_group_id == group_id {
        return true;
    }
    if source
        .source_primary_by_group
        .get(group_id)
        .is_some_and(|primary_ref| {
            source_origin_entry_matches_object_ref_for_node(
                source,
                primary_ref,
                origin_node_id,
                origin_group_id,
            )
        })
    {
        return true;
    }
    source.status.concrete_roots.iter().any(|root| {
        root.logical_root_id == group_id
            && source_origin_entry_matches_object_ref_for_node(
                source,
                &root.object_ref,
                origin_node_id,
                origin_group_id,
            )
    })
}

fn source_node_has_published_origin_for_group(
    source: &SourceObservabilitySnapshot,
    group_id: &str,
    node_id: &str,
) -> bool {
    source
        .last_published_origins_by_node
        .values()
        .chain(source.published_origin_counts_by_node.values())
        .any(|origins| {
            origins.iter().any(|entry| {
                source_origin_entry_matches_group_node(source, entry, group_id, node_id)
            })
        })
}

fn source_accepts_manual_rescan_origin_target_for_group(
    aggregate_source: &SourceObservabilitySnapshot,
    origin_node_id: &str,
    group_id: &str,
    target_node_id: &str,
) -> bool {
    if runtime_node_identity_matches(origin_node_id, target_node_id) {
        return source_node_has_published_origin_for_group(
            aggregate_source,
            group_id,
            target_node_id,
        ) || source_has_current_runtime_scope_generation_for_group(
            aggregate_source,
            group_id,
            target_node_id,
        );
    }
    source_node_has_published_origin_for_group(aggregate_source, group_id, target_node_id)
}

fn source_control_signal_activates_scoped_rescan_route_for_group(
    signal: &str,
    node_id: &str,
    group_id: &str,
) -> bool {
    signal.contains("activate ")
        && signal.contains("unit=runtime.exec.source")
        && source_control_signal_scoped_rescan_route_targets_node(signal, node_id)
        && source_control_signal_applies_to_group(signal, group_id)
}

fn source_control_signal_activates_scoped_rescan_route_for_empty_roots_bootstrap(
    signal: &str,
    node_id: &str,
) -> bool {
    signal.contains("activate ")
        && signal.contains("unit=runtime.exec.source")
        && source_control_signal_scoped_rescan_route_targets_node(signal, node_id)
        && signal.contains("__fsmeta_empty_roots_bootstrap=>")
}

fn source_control_signal_marks_scoped_rescan_route_receivable_for_group(
    signal: &str,
    node_id: &str,
    group_id: &str,
) -> bool {
    signal.contains("ready ")
        && signal.contains("unit=runtime.exec.source")
        && source_control_signal_scoped_rescan_route_targets_node(signal, node_id)
        && source_ready_control_signal_applies_to_group(signal, group_id)
}

fn source_control_signal_deactivates_scoped_rescan_route_for_node(
    signal: &str,
    node_id: &str,
) -> bool {
    signal.contains("deactivate ")
        && signal.contains("unit=runtime.exec.source")
        && source_control_signal_scoped_rescan_route_targets_node(signal, node_id)
}

fn source_control_signal_deactivates_scoped_rescan_route_for_group(
    signal: &str,
    node_id: &str,
    group_id: &str,
) -> bool {
    source_control_signal_deactivates_scoped_rescan_route_for_node(signal, node_id)
        && source_control_signal_applies_to_group(signal, group_id)
}

fn normalized_route_node_id(node_id: &str) -> String {
    node_id
        .chars()
        .map(|ch| {
            if ch.is_ascii_alphanumeric() {
                ch.to_ascii_lowercase()
            } else {
                '_'
            }
        })
        .collect()
}

fn normalized_route_node_id_matches(left: &str, right: &str) -> bool {
    left == right
        || left
            .strip_prefix(right)
            .is_some_and(|suffix| suffix.starts_with('_'))
        || right
            .strip_prefix(left)
            .is_some_and(|suffix| suffix.starts_with('_'))
}

fn source_control_signal_scoped_rescan_route_targets_node(signal: &str, node_id: &str) -> bool {
    if signal.contains(&format!(
        "route={}.req",
        source_rescan_route_key_for(node_id)
    )) {
        return true;
    }
    let Some((_, suffix)) = signal.split_once("route=") else {
        return false;
    };
    let route_key = suffix.split_whitespace().next().unwrap_or_default();
    let Some(route_key) = route_key.strip_suffix(".req") else {
        return false;
    };
    let Some((route_stem, route_version)) = ROUTE_KEY_SOURCE_RESCAN_INTERNAL.rsplit_once(':')
    else {
        return false;
    };
    let Some(scoped_suffix) = route_key
        .strip_prefix(route_stem)
        .and_then(|suffix| suffix.strip_prefix('.'))
        .and_then(|suffix| suffix.strip_suffix(&format!(":{route_version}")))
    else {
        return false;
    };
    normalized_route_node_id_matches(scoped_suffix, &normalized_route_node_id(node_id))
}

fn source_scoped_rescan_route_owner_for_group(
    source: &SourceObservabilitySnapshot,
    group_id: &str,
    node_id: &str,
) -> Option<String> {
    let control_cache_scope = source_observability_snapshot_has_runtime_scope_control_cache(source);
    if control_cache_scope {
        return source.last_control_frame_signals_by_node.iter().find_map(
            |(observed_node_id, signals)| {
                signals
                    .iter()
                    .any(|signal| {
                        source_control_signal_activates_scoped_rescan_route_for_group(
                            signal, node_id, group_id,
                        ) && runtime_node_identity_matches(observed_node_id, node_id)
                    })
                    .then(|| observed_node_id.clone())
            },
        );
    }
    source
        .last_control_frame_signals_by_node
        .iter()
        .find_map(|(observed_node_id, signals)| {
            signals
                .iter()
                .any(|signal| {
                    source_control_signal_activates_scoped_rescan_route_for_group(
                        signal, node_id, group_id,
                    ) && runtime_node_identity_matches(observed_node_id, node_id)
                })
                .then(|| observed_node_id.clone())
        })
        .or_else(|| {
            matches!(
                source_latest_scoped_rescan_route_freshness_for_group_node(
                    source, group_id, node_id
                ),
                Some(ScopedRescanRouteFreshness::Active(_))
            )
            .then(|| node_id.to_string())
        })
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum ScopedRescanRouteFreshness {
    Active(u64),
    Deactivated,
}

fn source_has_scoped_rescan_route_receivable_for_group(
    source: &SourceObservabilitySnapshot,
    group_id: &str,
    node_id: &str,
) -> bool {
    source_has_scoped_rescan_route_receivable_for_group_with_freshness(
        source, source, group_id, node_id,
    )
}

fn source_has_scoped_rescan_route_receivable_for_group_with_freshness(
    source: &SourceObservabilitySnapshot,
    route_freshness_source: &SourceObservabilitySnapshot,
    group_id: &str,
    node_id: &str,
) -> bool {
    let reports_runtime_scope = source_node_reports_runtime_scope_group(source, group_id, node_id);
    let reports_scan_runtime_scope =
        source_node_reports_scan_runtime_scope_group(source, group_id, node_id);
    let reports_publisher_root =
        source_node_has_live_group_primary_root_for_group(source, group_id, node_id)
            || source_node_has_published_group_primary_root_for_group(source, group_id, node_id);
    if !reports_runtime_scope || !reports_scan_runtime_scope || !reports_publisher_root {
        return false;
    }
    if !source_has_current_runtime_scope_generation_for_group(source, group_id, node_id) {
        return false;
    }
    let route_freshness = source_latest_scoped_rescan_route_freshness_for_group_node(
        route_freshness_source,
        group_id,
        node_id,
    );
    source
        .last_control_frame_signals_by_node
        .iter()
        .any(|(observed_node_id, signals)| {
            runtime_node_identity_matches(observed_node_id, node_id)
                && signals.iter().any(|signal| {
                    source_control_signal_marks_scoped_rescan_route_receivable_for_group(
                        signal, node_id, group_id,
                    ) && matches!(
                        route_freshness,
                        Some(ScopedRescanRouteFreshness::Active(generation))
                            if source_control_signal_generation(signal) == Some(generation)
                    )
                })
        })
}

fn source_node_has_published_group_primary_root_for_group(
    source: &SourceObservabilitySnapshot,
    group_id: &str,
    node_id: &str,
) -> bool {
    if source_observability_snapshot_is_worker_status_cache(source)
        || source_observability_snapshot_has_pending_source_state_observation(source)
    {
        return false;
    }
    if !source_node_has_published_origin_for_group(source, group_id, node_id) {
        return false;
    }
    source.status.concrete_roots.iter().any(|root| {
        root.logical_root_id == group_id
            && root.is_group_primary
            && source_concrete_root_allows_domain_target(root)
            && source_primary_runtime_node_id_from_ref(&root.object_ref, &source.grants)
                .is_some_and(|primary_node_id| {
                    runtime_node_identity_matches(&primary_node_id, node_id)
                })
    })
}

fn source_latest_scoped_rescan_route_freshness_for_group_node(
    source: &SourceObservabilitySnapshot,
    group_id: &str,
    node_id: &str,
) -> Option<ScopedRescanRouteFreshness> {
    let latest_activation = source
        .last_control_frame_signals_by_node
        .iter()
        .filter(|(observed_node_id, _)| runtime_node_identity_matches(observed_node_id, node_id))
        .flat_map(|(_, signals)| signals.iter())
        .filter(|signal| {
            source_control_signal_activates_scoped_rescan_route_for_group(signal, node_id, group_id)
                || source_control_signal_activates_scoped_rescan_route_for_empty_roots_bootstrap(
                    signal, node_id,
                )
        })
        .filter_map(|signal| source_control_signal_generation(signal))
        .max();
    let latest_deactivation = source
        .last_control_frame_signals_by_node
        .values()
        .flat_map(|signals| signals.iter())
        .filter(|signal| {
            source_control_signal_deactivates_scoped_rescan_route_for_group(
                signal, node_id, group_id,
            )
        })
        .filter_map(|signal| source_control_signal_generation(signal))
        .max();
    match (latest_activation, latest_deactivation) {
        (Some(activation), Some(deactivation)) if deactivation >= activation => {
            Some(ScopedRescanRouteFreshness::Deactivated)
        }
        (Some(activation), _) => Some(ScopedRescanRouteFreshness::Active(activation)),
        (None, Some(_)) => Some(ScopedRescanRouteFreshness::Deactivated),
        (None, None) => None,
    }
}

fn source_has_ready_scoped_rescan_route_for_group_node(
    source: &SourceObservabilitySnapshot,
    group_id: &str,
    node_id: &str,
) -> bool {
    let Some(ScopedRescanRouteFreshness::Active(active_generation)) =
        source_latest_scoped_rescan_route_freshness_for_group_node(source, group_id, node_id)
    else {
        return false;
    };
    source
        .last_control_frame_signals_by_node
        .iter()
        .any(|(observed_node_id, signals)| {
            runtime_node_identity_matches(observed_node_id, node_id)
                && signals.iter().any(|signal| {
                    source_control_signal_marks_scoped_rescan_route_receivable_for_group(
                        signal, node_id, group_id,
                    ) && source_control_signal_generation(signal) == Some(active_generation)
                })
        })
}

fn manual_rescan_runtime_scope_active_scoped_rescan_route_targets_for_root(
    source: &SourceObservabilitySnapshot,
    root_id: &str,
) -> BTreeSet<String> {
    source_runtime_scope_nodes_for_group(source, root_id)
        .into_iter()
        .filter(|node_id| {
            source_node_reports_runtime_scope_group(source, root_id, node_id)
                && source_node_reports_scan_runtime_scope_group(source, root_id, node_id)
                && matches!(
                    source_latest_scoped_rescan_route_freshness_for_group_node(
                        source, root_id, node_id,
                    ),
                    Some(ScopedRescanRouteFreshness::Active(_))
                )
        })
        .collect()
}

fn manual_rescan_runtime_scope_ready_scoped_rescan_route_targets_for_root(
    source: &SourceObservabilitySnapshot,
    root_id: &str,
    active_route_targets: &BTreeSet<String>,
) -> BTreeSet<String> {
    active_route_targets
        .iter()
        .filter(|node_id| {
            source_has_ready_scoped_rescan_route_for_group_node(source, root_id, node_id)
        })
        .cloned()
        .collect()
}

fn manual_rescan_runtime_scope_active_route_can_fallback(
    source: &SourceObservabilitySnapshot,
) -> bool {
    source_observability_snapshot_has_runtime_scope_control_cache(source)
        || source_observability_snapshot_has_pending_source_state_observation(source)
}

fn source_observability_snapshot_has_runtime_scope_control_cache(
    source: &SourceObservabilitySnapshot,
) -> bool {
    source
        .status
        .degraded_roots
        .iter()
        .any(|(root_key, reason)| {
            root_key == "source-worker"
                && reason == "source worker runtime scope served from control cache"
        })
}

fn source_observability_snapshot_has_manual_rescan_delivery_cache(
    source: &SourceObservabilitySnapshot,
) -> bool {
    source
        .status
        .degraded_roots
        .iter()
        .any(|(root_key, reason)| {
            root_key == SOURCE_WORKER_DEGRADED_ROOT_KEY
                && reason == SOURCE_WORKER_MANUAL_RESCAN_DELIVERY_CACHE_REASON
        })
}

fn source_observability_snapshot_has_pending_source_state_observation(
    source: &SourceObservabilitySnapshot,
) -> bool {
    source
        .status
        .degraded_roots
        .iter()
        .any(|(root_key, reason)| {
            root_key == SOURCE_WORKER_DEGRADED_ROOT_KEY
                && reason == SOURCE_WORKER_PENDING_SOURCE_STATE_OBSERVATION_REASON
        })
}

fn source_snapshot_for_manual_rescan_delivery_proof(
    source: &SourceObservabilitySnapshot,
) -> Option<SourceObservabilitySnapshot> {
    if source_observability_snapshot_is_worker_status_cache(source)
        || source_observability_snapshot_has_pending_source_state_observation(source)
    {
        return None;
    }
    let has_runtime_scope_control_cache =
        source_observability_snapshot_has_runtime_scope_control_cache(source);
    let has_manual_rescan_delivery_cache =
        source_observability_snapshot_has_manual_rescan_delivery_cache(source);
    let has_live_manual_rescan_delivery_domain_evidence =
        source_observability_snapshot_has_live_manual_rescan_delivery_domain_evidence(source);
    let has_published_manual_rescan_delivery_domain_evidence =
        source_observability_snapshot_has_published_manual_rescan_delivery_domain_evidence(source);
    if source_observability_snapshot_is_degraded_worker_cache(source)
        && !has_manual_rescan_delivery_cache
        && !has_live_manual_rescan_delivery_domain_evidence
        && !has_published_manual_rescan_delivery_domain_evidence
    {
        return None;
    }
    if !has_runtime_scope_control_cache
        && !source_observability_snapshot_is_degraded_worker_cache(source)
    {
        return Some(source_snapshot_without_stale_runtime_scope_generation(
            source.clone(),
        ));
    }
    if !has_manual_rescan_delivery_cache
        && !has_live_manual_rescan_delivery_domain_evidence
        && !has_published_manual_rescan_delivery_domain_evidence
    {
        return None;
    }
    let mut source = source.clone();
    source.status.degraded_roots.retain(|(root_key, reason)| {
        !(root_key == SOURCE_WORKER_DEGRADED_ROOT_KEY
            && reason == SOURCE_WORKER_RUNTIME_SCOPE_CACHE_REASON)
            && !source_worker_unavailable_degraded_root_reason(root_key, reason)
    });
    if source_observability_snapshot_is_degraded_worker_cache(&source) {
        source.lifecycle_state = "manual_rescan_delivery_ready".to_string();
    }
    Some(source_snapshot_without_stale_runtime_scope_generation(
        source,
    ))
}

fn source_observability_snapshot_has_live_manual_rescan_delivery_domain_evidence(
    source: &SourceObservabilitySnapshot,
) -> bool {
    source.status.concrete_roots.iter().any(|concrete_root| {
        if !concrete_root.is_group_primary
            || !source_concrete_root_allows_domain_target(concrete_root)
        {
            return false;
        }
        let Some(primary_node_id) =
            source_primary_runtime_node_id_from_ref(&concrete_root.object_ref, &source.grants)
        else {
            return false;
        };
        source.status.logical_roots.iter().any(|logical_root| {
            logical_root.root_id == concrete_root.logical_root_id
                && logical_root.matched_grants > 0
                && logical_root.active_members > 0
                && !source_logical_root_status_is_not_live(&logical_root.status)
        }) && source_node_reports_runtime_scope_group(
            source,
            &concrete_root.logical_root_id,
            &primary_node_id,
        ) && source_node_reports_scan_runtime_scope_group(
            source,
            &concrete_root.logical_root_id,
            &primary_node_id,
        )
    })
}

fn source_observability_snapshot_has_published_manual_rescan_delivery_domain_evidence(
    source: &SourceObservabilitySnapshot,
) -> bool {
    source.status.concrete_roots.iter().any(|concrete_root| {
        if !concrete_root.is_group_primary
            || !source_concrete_root_allows_domain_target(concrete_root)
        {
            return false;
        }
        let Some(primary_node_id) =
            source_primary_runtime_node_id_from_ref(&concrete_root.object_ref, &source.grants)
        else {
            return false;
        };
        source_node_reports_runtime_scope_group(
            source,
            &concrete_root.logical_root_id,
            &primary_node_id,
        ) && source_node_reports_scan_runtime_scope_group(
            source,
            &concrete_root.logical_root_id,
            &primary_node_id,
        ) && source_node_has_published_origin_for_group(
            source,
            &concrete_root.logical_root_id,
            &primary_node_id,
        )
    })
}

fn source_logical_root_allows_domain_target(
    source: &SourceObservabilitySnapshot,
    root_id: &str,
) -> bool {
    let control_cache_scope = source_observability_snapshot_has_runtime_scope_control_cache(source);
    source.status.logical_roots.iter().any(|root| {
        root.root_id == root_id
            && root.matched_grants > 0
            && root.active_members > 0
            && (!source_logical_root_status_is_not_live(&root.status)
                || (control_cache_scope && !root.status.starts_with("waiting_for_root:")))
    })
}

fn source_logical_root_status_is_not_live(status: &str) -> bool {
    status.starts_with("waiting_for_root:") || status.contains("degraded")
}

fn source_concrete_root_allows_domain_target(
    concrete_root: &crate::source::SourceConcreteRootHealthSnapshot,
) -> bool {
    concrete_root.active
        && (concrete_root.watch_enabled || concrete_root.scan_enabled)
        && concrete_root.last_error.is_none()
        && !concrete_root.status.starts_with("waiting_for_root:")
        && !concrete_root.status.contains("degraded")
}

fn source_node_has_live_group_primary_root_for_group(
    source: &SourceObservabilitySnapshot,
    group_id: &str,
    node_id: &str,
) -> bool {
    if source_observability_snapshot_is_worker_status_cache(source)
        || source_observability_snapshot_is_degraded_worker_cache(source)
        || source_observability_snapshot_has_runtime_scope_control_cache(source)
        || !source_logical_root_allows_domain_target(source, group_id)
    {
        return false;
    }
    source.status.concrete_roots.iter().any(|concrete_root| {
        concrete_root.logical_root_id == group_id
            && concrete_root.is_group_primary
            && source_concrete_root_allows_domain_target(concrete_root)
            && source_primary_runtime_node_id_from_ref(&concrete_root.object_ref, &source.grants)
                .is_some_and(|primary_node_id| {
                    runtime_node_identity_matches(&primary_node_id, node_id)
                })
    })
}

fn live_group_primary_domain_target_node_id_for_root(
    source: &SourceObservabilitySnapshot,
    root_id: &str,
) -> Option<String> {
    if source_observability_snapshot_is_degraded_worker_cache(source)
        || !source_logical_root_allows_domain_target(source, root_id)
    {
        return None;
    }
    source
        .status
        .concrete_roots
        .iter()
        .filter(|concrete_root| {
            concrete_root.logical_root_id == root_id
                && concrete_root.is_group_primary
                && source_concrete_root_allows_domain_target(concrete_root)
        })
        .filter_map(|concrete_root| {
            let node_id =
                source_primary_runtime_node_id_from_ref(&concrete_root.object_ref, &source.grants)?;
            source_scoped_rescan_route_owner_for_group(source, root_id, &node_id)
        })
        .next()
}

fn live_non_degraded_group_primary_domain_target_node_id_for_root(
    source: &SourceObservabilitySnapshot,
    root_id: &str,
) -> Option<String> {
    if source_observability_snapshot_is_degraded_worker_cache(source)
        || !source.status.logical_roots.iter().any(|root| {
            root.root_id == root_id
                && root.matched_grants > 0
                && root.active_members > 0
                && !source_logical_root_status_is_not_live(&root.status)
        })
    {
        return None;
    }
    live_group_primary_domain_target_node_id_for_root(source, root_id)
}

fn manual_rescan_source_primary_target_node_ids_from_runtime_scope(
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
) -> BTreeSet<String> {
    manual_rescan_source_primary_target_node_ids_by_root_from_runtime_scope(roots, source)
        .into_values()
        .flatten()
        .collect()
}

fn manual_rescan_source_status_probe_hint_node_ids_from_runtime_scope(
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
) -> BTreeSet<String> {
    let mut target_node_ids =
        manual_rescan_source_primary_target_node_ids_from_runtime_scope(roots, source);
    for root in roots {
        for node_id in source_runtime_scope_nodes_for_group(source, &root.id) {
            if source_node_reports_runtime_scope_group(source, &root.id, &node_id)
                && source_node_reports_scan_runtime_scope_group(source, &root.id, &node_id)
            {
                target_node_ids.insert(node_id);
            }
        }
    }
    retain_most_specific_runtime_node_identities(&mut target_node_ids);
    target_node_ids
}

fn manual_rescan_source_status_probe_target_node_ids(
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
    authoritative_target_node_ids: &BTreeSet<String>,
) -> BTreeSet<String> {
    let mut target_node_ids =
        manual_rescan_source_status_probe_hint_node_ids_from_runtime_scope(roots, source);
    if target_node_ids.is_empty()
        && !manual_rescan_source_status_has_runtime_scope_evidence(roots, source)
    {
        target_node_ids = authoritative_target_node_ids.clone();
    } else if !manual_rescan_source_status_probe_hints_cover_current_roots(roots, source) {
        target_node_ids.extend(authoritative_target_node_ids.iter().cloned());
    }
    retain_most_specific_runtime_node_identities(&mut target_node_ids);
    target_node_ids
}

fn manual_rescan_scoped_delivery_targets_from_runtime_scope_after_preflight(
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
) -> BTreeSet<String> {
    if roots.is_empty() || source.lifecycle_state == "grant_derived_current_roots" {
        return BTreeSet::new();
    }
    let mut targets_by_root = BTreeMap::<String, BTreeSet<String>>::new();
    for root in roots {
        let active_route_targets =
            manual_rescan_runtime_scope_active_scoped_rescan_route_targets_for_root(
                source, &root.id,
            );
        if active_route_targets.is_empty() {
            return BTreeSet::new();
        }
        let ready_route_targets =
            manual_rescan_runtime_scope_ready_scoped_rescan_route_targets_for_root(
                source,
                &root.id,
                &active_route_targets,
            );
        let root_targets = if !ready_route_targets.is_empty() {
            ready_route_targets
        } else if manual_rescan_runtime_scope_active_route_can_fallback(source) {
            active_route_targets
        } else {
            return BTreeSet::new();
        };
        targets_by_root.insert(root.id.clone(), root_targets);
    }
    let mut targets = manual_rescan_minimal_target_cover_for_roots(roots, targets_by_root);
    retain_most_specific_runtime_node_identities(&mut targets);
    targets
}

fn manual_rescan_minimal_target_cover_for_roots(
    roots: &[RootSpec],
    targets_by_root: BTreeMap<String, BTreeSet<String>>,
) -> BTreeSet<String> {
    let mut uncovered_roots = roots
        .iter()
        .map(|root| root.id.clone())
        .collect::<BTreeSet<_>>();
    let mut selected_targets = BTreeSet::new();
    while !uncovered_roots.is_empty() {
        let Some((best_target, covered_roots)) = targets_by_root
            .values()
            .flat_map(|targets| targets.iter())
            .collect::<BTreeSet<_>>()
            .into_iter()
            .filter_map(|target| {
                let covered_roots = uncovered_roots
                    .iter()
                    .filter(|root_id| {
                        targets_by_root
                            .get(root_id.as_str())
                            .is_some_and(|targets| targets.contains(target))
                    })
                    .cloned()
                    .collect::<BTreeSet<_>>();
                (!covered_roots.is_empty()).then(|| (target.clone(), covered_roots))
            })
            .max_by(|(left_target, left_roots), (right_target, right_roots)| {
                left_roots
                    .len()
                    .cmp(&right_roots.len())
                    .then_with(|| right_target.cmp(left_target))
            })
        else {
            return BTreeSet::new();
        };
        selected_targets.insert(best_target);
        for root_id in covered_roots {
            uncovered_roots.remove(&root_id);
        }
    }
    selected_targets
}

fn manual_rescan_runtime_scope_route_activation_gaps_by_root(
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
) -> BTreeMap<String, BTreeSet<String>> {
    if roots.is_empty() || source.lifecycle_state == "grant_derived_current_roots" {
        return BTreeMap::new();
    }
    roots
        .iter()
        .filter_map(|root| {
            let runtime_scope_targets = source_runtime_scope_nodes_for_group(source, &root.id)
                .into_iter()
                .filter(|node_id| {
                    source_node_reports_runtime_scope_group(source, &root.id, node_id)
                        && source_node_reports_scan_runtime_scope_group(source, &root.id, node_id)
                })
                .collect::<BTreeSet<_>>();
            if runtime_scope_targets.is_empty() {
                return None;
            }
            let active_route_targets = runtime_scope_targets
                .iter()
                .filter(|node_id| {
                    matches!(
                        source_latest_scoped_rescan_route_freshness_for_group_node(
                            source, &root.id, node_id,
                        ),
                        Some(ScopedRescanRouteFreshness::Active(_))
                    )
                })
                .cloned()
                .collect::<BTreeSet<_>>();
            active_route_targets
                .is_empty()
                .then(|| (root.id.clone(), runtime_scope_targets))
        })
        .collect()
}

fn manual_rescan_runtime_scope_route_readiness_gaps_by_root(
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
) -> BTreeMap<String, BTreeSet<String>> {
    if roots.is_empty() || source.lifecycle_state == "grant_derived_current_roots" {
        return BTreeMap::new();
    }
    roots
        .iter()
        .filter_map(|root| {
            let active_route_targets =
                manual_rescan_runtime_scope_active_scoped_rescan_route_targets_for_root(
                    source, &root.id,
                );
            if active_route_targets.is_empty() {
                return None;
            }
            let ready_route_targets =
                manual_rescan_runtime_scope_ready_scoped_rescan_route_targets_for_root(
                    source,
                    &root.id,
                    &active_route_targets,
                );
            let active_fallback = manual_rescan_runtime_scope_active_route_can_fallback(source);
            (ready_route_targets.is_empty() && !active_fallback)
                .then(|| (root.id.clone(), active_route_targets))
        })
        .collect()
}

fn manual_rescan_runtime_scope_coverage_gaps_by_root(
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
) -> BTreeSet<String> {
    if roots.is_empty() || source.lifecycle_state == "grant_derived_current_roots" {
        return BTreeSet::new();
    }
    roots
        .iter()
        .filter(|root| {
            source_runtime_scope_nodes_for_group(source, &root.id)
                .into_iter()
                .all(|node_id| {
                    !source_node_reports_runtime_scope_group(source, &root.id, &node_id)
                        || !source_node_reports_scan_runtime_scope_group(source, &root.id, &node_id)
                })
        })
        .map(|root| root.id.clone())
        .collect()
}

fn source_node_has_generic_fallback_group_primary_root_for_group(
    source: &SourceObservabilitySnapshot,
    group_id: &str,
    node_id: &str,
) -> bool {
    if source_observability_snapshot_is_worker_status_cache(source)
        || source_observability_snapshot_is_degraded_worker_cache(source)
        || source_observability_snapshot_has_pending_source_state_observation(source)
    {
        return false;
    }
    if !source.status.logical_roots.iter().any(|root| {
        root.root_id == group_id
            && root.matched_grants > 0
            && root.active_members > 0
            && !source_logical_root_status_is_not_live(&root.status)
    }) {
        return false;
    }
    source.status.concrete_roots.iter().any(|concrete_root| {
        concrete_root.logical_root_id == group_id
            && concrete_root.is_group_primary
            && source_concrete_root_allows_domain_target(concrete_root)
            && source_primary_runtime_node_id_from_ref(&concrete_root.object_ref, &source.grants)
                .is_some_and(|primary_node_id| {
                    runtime_node_identity_matches(&primary_node_id, node_id)
                })
    })
}

fn manual_rescan_generic_fallback_allowed_after_scoped_activation_gaps(
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
    coverage_gaps: &BTreeSet<String>,
    route_activation_gaps: &BTreeMap<String, BTreeSet<String>>,
    route_readiness_gaps: &BTreeMap<String, BTreeSet<String>>,
) -> bool {
    manual_rescan_generic_fallback_blocker_after_scoped_activation_gaps(
        roots,
        source,
        coverage_gaps,
        route_activation_gaps,
        route_readiness_gaps,
    )
    .is_none()
}

fn manual_rescan_generic_fallback_blocker_after_scoped_activation_gaps(
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
    coverage_gaps: &BTreeSet<String>,
    route_activation_gaps: &BTreeMap<String, BTreeSet<String>>,
    route_readiness_gaps: &BTreeMap<String, BTreeSet<String>>,
) -> Option<String> {
    if roots.is_empty() {
        return Some("empty_roots".to_string());
    }
    if source.lifecycle_state == "grant_derived_current_roots" {
        return Some("grant_derived_current_roots".to_string());
    }
    if !coverage_gaps.is_empty() {
        return Some(format!("coverage_gaps={coverage_gaps:?}"));
    }
    if route_activation_gaps.is_empty() {
        return Some("no_route_activation_gaps".to_string());
    }
    if !route_readiness_gaps.is_empty() {
        return Some(format!("route_readiness_gaps={route_readiness_gaps:?}"));
    }
    if source_observability_snapshot_is_worker_status_cache(source) {
        return Some("worker_status_cache".to_string());
    }
    if source_observability_snapshot_is_degraded_worker_cache(source) {
        return Some(format!(
            "degraded_worker_cache={:?}",
            source.status.degraded_roots
        ));
    }
    if source_observability_snapshot_has_pending_source_state_observation(source) {
        return Some("pending_source_state_observation".to_string());
    }
    let expected_groups = roots_put_second_wave_expected_groups(roots);
    if !source_snapshot_declares_only_current_logical_roots(roots, source) {
        let declared = source
            .logical_roots
            .iter()
            .map(|root| root.id.clone())
            .collect::<BTreeSet<_>>();
        return Some(format!("logical_roots_not_current={declared:?}"));
    }
    if !source_snapshot_has_current_root_health_evidence(roots, source) {
        let missing = roots
            .iter()
            .filter(|root| {
                !source.status.logical_roots.iter().any(|health| {
                    health.root_id == root.id
                        && health.matched_grants > 0
                        && health.active_members > 0
                        && !health.status.starts_with("waiting_for_root:")
                })
            })
            .map(|root| root.id.clone())
            .collect::<BTreeSet<_>>();
        return Some(format!("missing_current_root_health={missing:?}"));
    }
    if !roots_put_second_wave_source_runtime_scope_ready(&expected_groups, source) {
        let observed = roots_put_second_wave_source_runtime_scope_observed_groups(source);
        return Some(format!(
            "runtime_scope_not_exact expected_source={:?} expected_scan={:?} observed_source={:?} observed_scan={:?}",
            expected_groups.source_groups, expected_groups.scan_groups, observed.0, observed.1,
        ));
    }
    let missing_group_primary = roots
        .iter()
        .filter(|root| {
            !source_runtime_scope_nodes_for_group(source, &root.id)
                .into_iter()
                .any(|node_id| {
                    source_node_reports_runtime_scope_group(source, &root.id, &node_id)
                        && source_node_reports_scan_runtime_scope_group(source, &root.id, &node_id)
                        && source_node_has_generic_fallback_group_primary_root_for_group(
                            source, &root.id, &node_id,
                        )
                })
        })
        .map(|root| {
            let candidates = source_runtime_scope_nodes_for_group(source, &root.id)
                .into_iter()
                .map(|node_id| {
                    format!(
                        "{node_id}:source={} scan={} primary={}",
                        source_node_reports_runtime_scope_group(source, &root.id, &node_id),
                        source_node_reports_scan_runtime_scope_group(source, &root.id, &node_id),
                        source_node_has_generic_fallback_group_primary_root_for_group(
                            source, &root.id, &node_id,
                        )
                    )
                })
                .collect::<Vec<_>>();
            format!("{}={candidates:?}", root.id)
        })
        .collect::<Vec<_>>();
    if !missing_group_primary.is_empty() {
        return Some(format!("missing_group_primary={missing_group_primary:?}"));
    }
    None
}

fn manual_rescan_generic_fallback_allowed_with_current_roots_evidence(
    roots: &[RootSpec],
    current_roots_source: &SourceObservabilitySnapshot,
    fallback_source: &SourceObservabilitySnapshot,
    coverage_gaps: &BTreeSet<String>,
    route_activation_gaps: &BTreeMap<String, BTreeSet<String>>,
    route_readiness_gaps: &BTreeMap<String, BTreeSet<String>>,
) -> bool {
    manual_rescan_generic_fallback_allowed_after_scoped_activation_gaps(
        roots,
        fallback_source,
        coverage_gaps,
        route_activation_gaps,
        route_readiness_gaps,
    ) || manual_rescan_generic_fallback_allowed_after_scoped_activation_gaps(
        roots,
        current_roots_source,
        coverage_gaps,
        route_activation_gaps,
        route_readiness_gaps,
    )
}

fn manual_rescan_generic_fallback_blocker_with_current_roots_evidence(
    roots: &[RootSpec],
    current_roots_source: &SourceObservabilitySnapshot,
    fallback_source: &SourceObservabilitySnapshot,
    coverage_gaps: &BTreeSet<String>,
    route_activation_gaps: &BTreeMap<String, BTreeSet<String>>,
    route_readiness_gaps: &BTreeMap<String, BTreeSet<String>>,
) -> String {
    let fallback_blocker = manual_rescan_generic_fallback_blocker_after_scoped_activation_gaps(
        roots,
        fallback_source,
        coverage_gaps,
        route_activation_gaps,
        route_readiness_gaps,
    );
    let current_blocker = manual_rescan_generic_fallback_blocker_after_scoped_activation_gaps(
        roots,
        current_roots_source,
        coverage_gaps,
        route_activation_gaps,
        route_readiness_gaps,
    );
    format!("fallback_snapshot={fallback_blocker:?} current_roots_snapshot={current_blocker:?}")
}

#[cfg(test)]
fn manual_rescan_generic_fallback_allowed_after_target_probe_loses_live_domain_evidence(
    roots: &[RootSpec],
    current_roots_source: &SourceObservabilitySnapshot,
    target_probe_source: &SourceObservabilitySnapshot,
) -> bool {
    let coverage_gaps =
        manual_rescan_runtime_scope_coverage_gaps_by_root(roots, target_probe_source);
    let route_activation_gaps =
        manual_rescan_runtime_scope_route_activation_gaps_by_root(roots, target_probe_source);
    let route_readiness_gaps =
        manual_rescan_runtime_scope_route_readiness_gaps_by_root(roots, target_probe_source);
    manual_rescan_generic_fallback_allowed_with_current_roots_evidence(
        roots,
        current_roots_source,
        target_probe_source,
        &coverage_gaps,
        &route_activation_gaps,
        &route_readiness_gaps,
    )
}

fn manual_rescan_discovered_source_status_probe_target_node_ids(
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
) -> Option<BTreeSet<String>> {
    if !manual_rescan_source_status_probe_hints_cover_current_roots(roots, source) {
        return None;
    }
    let mut target_node_ids =
        manual_rescan_source_status_probe_hint_node_ids_from_runtime_scope(roots, source);
    retain_most_specific_runtime_node_identities(&mut target_node_ids);
    (!target_node_ids.is_empty()).then_some(target_node_ids)
}

fn manual_rescan_source_status_probe_hints_cover_current_roots(
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
) -> bool {
    let target_node_ids_by_root =
        manual_rescan_source_primary_target_node_ids_by_root_from_runtime_scope(roots, source);
    roots.iter().all(|root| {
        target_node_ids_by_root
            .get(&root.id)
            .is_some_and(|target_node_ids| !target_node_ids.is_empty())
    })
}

fn manual_rescan_source_status_has_runtime_scope_evidence(
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
) -> bool {
    roots
        .iter()
        .any(|root| !source_runtime_scope_nodes_for_group(source, &root.id).is_empty())
}

fn manual_rescan_target_node_ids_from_source_status_origin_snapshots(
    roots: &[RootSpec],
    source_status_origin_snapshots: &[(String, SourceObservabilitySnapshot)],
) -> Option<BTreeSet<String>> {
    let target_node_ids_by_root =
        manual_rescan_target_node_ids_by_root_from_source_status_origin_snapshots(
            roots,
            source_status_origin_snapshots,
        );
    let current_root_ids = roots
        .iter()
        .map(|root| root.id.clone())
        .collect::<BTreeSet<_>>();
    if current_root_ids.is_empty() {
        return None;
    }
    current_root_ids
        .iter()
        .all(|root_id| {
            target_node_ids_by_root
                .get(root_id)
                .is_some_and(|target_node_ids| !target_node_ids.is_empty())
        })
        .then(|| target_node_ids_by_root.into_values().flatten().collect())
}

fn manual_rescan_target_node_ids_by_root_from_source_status_origin_snapshots(
    roots: &[RootSpec],
    source_status_origin_snapshots: &[(String, SourceObservabilitySnapshot)],
) -> BTreeMap<String, BTreeSet<String>> {
    let current_root_ids = roots
        .iter()
        .map(|root| root.id.clone())
        .collect::<BTreeSet<_>>();
    if current_root_ids.is_empty() {
        return BTreeMap::new();
    }
    let delivery_proof_snapshots = source_status_origin_snapshots
        .iter()
        .filter_map(|(_, source)| {
            let source = source_snapshot_for_manual_rescan_delivery_proof(source)?;
            source_snapshot_declares_only_current_logical_roots(roots, &source).then_some(source)
        })
        .collect::<Vec<_>>();
    if delivery_proof_snapshots.is_empty() {
        return BTreeMap::new();
    }
    let delivery_proof_source = merge_source_observability_snapshots(delivery_proof_snapshots);
    let mut target_node_ids_by_root = BTreeMap::<String, BTreeSet<String>>::new();
    for (origin_node_id, source_snapshot) in source_status_origin_snapshots {
        let Some(source_snapshot) =
            source_snapshot_for_manual_rescan_delivery_proof(source_snapshot)
        else {
            continue;
        };
        if !source_snapshot_declares_only_current_logical_roots(roots, &source_snapshot) {
            continue;
        }
        for (root_id, target_node_ids) in
            manual_rescan_source_primary_target_node_ids_by_root_from_runtime_scope(
                roots,
                &source_snapshot,
            )
        {
            for target_node_id in target_node_ids {
                if source_accepts_manual_rescan_origin_target_for_group(
                    &delivery_proof_source,
                    origin_node_id,
                    &root_id,
                    &target_node_id,
                ) && source_has_scoped_rescan_route_receivable_for_group_with_freshness(
                    &source_snapshot,
                    &delivery_proof_source,
                    &root_id,
                    &target_node_id,
                ) {
                    target_node_ids_by_root
                        .entry(root_id.clone())
                        .or_default()
                        .insert(target_node_id);
                }
            }
        }
    }
    target_node_ids_by_root
}

fn manual_rescan_target_proof_debug_from_source_status_origin_snapshots(
    roots: &[RootSpec],
    source_status_origin_snapshots: &[(String, SourceObservabilitySnapshot)],
) -> Vec<String> {
    let current_root_ids = roots
        .iter()
        .map(|root| root.id.clone())
        .collect::<BTreeSet<_>>();
    let delivery_proof_snapshots = source_status_origin_snapshots
        .iter()
        .filter_map(|(_, source)| {
            let source = source_snapshot_for_manual_rescan_delivery_proof(source)?;
            source_snapshot_declares_only_current_logical_roots(roots, &source).then_some(source)
        })
        .collect::<Vec<_>>();
    if current_root_ids.is_empty() || delivery_proof_snapshots.is_empty() {
        return Vec::new();
    }
    let delivery_proof_source = merge_source_observability_snapshots(delivery_proof_snapshots);
    let mut debug = Vec::new();
    for (origin_node_id, source_snapshot) in source_status_origin_snapshots {
        let Some(source_snapshot) =
            source_snapshot_for_manual_rescan_delivery_proof(source_snapshot)
        else {
            debug.push(format!("{origin_node_id}:control-cache"));
            continue;
        };
        if !source_snapshot_declares_only_current_logical_roots(roots, &source_snapshot) {
            debug.push(format!("{origin_node_id}:stale-logical-roots"));
            continue;
        }
        let candidates_by_root =
            manual_rescan_source_primary_target_node_ids_by_root_from_runtime_scope(
                roots,
                &source_snapshot,
            );
        for root_id in &current_root_ids {
            let candidates = candidates_by_root.get(root_id).cloned().unwrap_or_default();
            if candidates.is_empty() {
                debug.push(format!("{origin_node_id}:{root_id}:candidates=[]"));
                continue;
            }
            for target_node_id in candidates {
                let route_freshness = source_latest_scoped_rescan_route_freshness_for_group_node(
                    &delivery_proof_source,
                    root_id,
                    &target_node_id,
                );
                debug.push(format!(
                    "{origin_node_id}:{root_id}->{target_node_id}:origin_ok={} runtime={} scan={} primary={} gen={} freshness={route_freshness:?} route={}",
                    source_accepts_manual_rescan_origin_target_for_group(
                        &delivery_proof_source,
                        origin_node_id,
                        root_id,
                        &target_node_id,
                    ),
                    source_node_reports_runtime_scope_group(&source_snapshot, root_id, &target_node_id),
                    source_node_reports_scan_runtime_scope_group(&source_snapshot, root_id, &target_node_id),
                    source_node_has_live_group_primary_root_for_group(&source_snapshot, root_id, &target_node_id),
                    source_has_current_runtime_scope_generation_for_group(&source_snapshot, root_id, &target_node_id),
                    source_has_scoped_rescan_route_receivable_for_group_with_freshness(
                        &source_snapshot,
                        &delivery_proof_source,
                        root_id,
                        &target_node_id,
                    ),
                ));
            }
        }
    }
    debug
}

fn manual_rescan_accumulated_source_status_has_delivery_target_node_id(
    roots: &[RootSpec],
    accumulated: &BTreeMap<String, SourceObservabilitySnapshot>,
    node_id: &str,
) -> bool {
    let origin_snapshots = accumulated
        .iter()
        .map(|(origin, snapshot)| (origin.clone(), snapshot.clone()))
        .collect::<Vec<_>>();
    manual_rescan_target_node_ids_by_root_from_source_status_origin_snapshots(
        roots,
        &origin_snapshots,
    )
    .values()
    .flatten()
    .any(|target_node_id| runtime_node_identity_matches(target_node_id, node_id))
}

fn manual_rescan_target_node_ids_from_receivable_source_snapshot(
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
) -> Option<BTreeSet<String>> {
    let current_root_ids = roots
        .iter()
        .map(|root| root.id.clone())
        .collect::<BTreeSet<_>>();
    if current_root_ids.is_empty() {
        return None;
    }
    let source = source_snapshot_for_manual_rescan_delivery_proof(source)?;
    if !source_snapshot_declares_only_current_logical_roots(roots, &source) {
        return None;
    }
    let candidate_node_ids_by_root =
        manual_rescan_source_primary_target_node_ids_by_root_from_runtime_scope(roots, &source);
    let mut receivable_node_ids_by_root = BTreeMap::<String, BTreeSet<String>>::new();
    for root_id in &current_root_ids {
        let Some(candidate_node_ids) = candidate_node_ids_by_root.get(root_id) else {
            return None;
        };
        let receivable_node_ids = candidate_node_ids
            .iter()
            .filter(|node_id| {
                source_has_scoped_rescan_route_receivable_for_group(&source, root_id, node_id)
            })
            .cloned()
            .collect::<BTreeSet<_>>();
        if receivable_node_ids.is_empty() {
            return None;
        }
        receivable_node_ids_by_root.insert(root_id.clone(), receivable_node_ids);
    }
    Some(
        receivable_node_ids_by_root
            .into_values()
            .flatten()
            .collect(),
    )
}

fn source_snapshot_for_manual_rescan_target_selection(
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
) -> SourceObservabilitySnapshot {
    if source_observability_snapshot_is_degraded_worker_cache(source) {
        let current_source =
            local_source_snapshot_without_unavailable_worker_runtime_scope_evidence(source.clone());
        let expected_groups = roots_put_second_wave_expected_groups(roots);
        if source_snapshot_has_current_root_health_evidence(roots, &current_source)
            && roots_put_second_wave_source_runtime_scope_ready(&expected_groups, &current_source)
        {
            return current_source;
        }
        return source_snapshot_without_degraded_worker_runtime_scope_evidence(source.clone());
    }
    local_source_snapshot_without_unavailable_worker_runtime_scope_evidence(source.clone())
}

fn manual_rescan_source_primary_target_node_ids_by_root_from_runtime_scope(
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
) -> BTreeMap<String, BTreeSet<String>> {
    if source_observability_snapshot_is_worker_status_cache(source) {
        return BTreeMap::new();
    }
    let domain_source = source;
    let source = source_snapshot_for_manual_rescan_target_selection(roots, source);
    let worker_status_cache = source_observability_snapshot_is_worker_status_cache(&source);
    let current_root_ids = roots
        .iter()
        .map(|root| root.id.clone())
        .collect::<BTreeSet<_>>();
    let mut target_node_ids_by_root = BTreeMap::new();

    for root_id in &current_root_ids {
        let runtime_scope_nodes = source_runtime_scope_nodes_for_group(&source, root_id);
        let has_runtime_scope_evidence = !runtime_scope_nodes.is_empty();
        let mut root_target_node_ids = BTreeSet::new();

        if let Some(primary_ref) = source.source_primary_by_group.get(root_id.as_str()) {
            if !worker_status_cache {
                root_target_node_ids.extend(source_primary_matching_runtime_scope_nodes(
                    &source,
                    root_id,
                    primary_ref,
                ));
                if root_target_node_ids.is_empty()
                    && let Some(primary_node_id) =
                        source_primary_runtime_node_id_from_ref(primary_ref, &source.grants)
                    && source_logical_root_allows_domain_target(&source, root_id)
                    && source_node_has_published_origin_for_group(
                        domain_source,
                        root_id,
                        &primary_node_id,
                    )
                    && let Some(route_owner_node_id) = source_scoped_rescan_route_owner_for_group(
                        &source,
                        root_id,
                        &primary_node_id,
                    )
                {
                    root_target_node_ids.insert(route_owner_node_id);
                }
            }
        }

        for concrete_root in &source.status.concrete_roots {
            if concrete_root.logical_root_id != root_id.as_str()
                || !concrete_root.active
                || !concrete_root.is_group_primary
                || !(concrete_root.watch_enabled || concrete_root.scan_enabled)
            {
                continue;
            }
            let matching_nodes = source_primary_matching_runtime_scope_nodes(
                &source,
                &concrete_root.logical_root_id,
                &concrete_root.object_ref,
            );
            if matching_nodes.is_empty()
                && source_logical_root_allows_domain_target(&source, &concrete_root.logical_root_id)
                && source_concrete_root_allows_domain_target(concrete_root)
                && let Some(primary_node_id) = source_primary_runtime_node_id_from_ref(
                    &concrete_root.object_ref,
                    &source.grants,
                )
                && source_node_has_published_origin_for_group(
                    domain_source,
                    &concrete_root.logical_root_id,
                    &primary_node_id,
                )
                && let Some(route_owner_node_id) = source_scoped_rescan_route_owner_for_group(
                    &source,
                    &concrete_root.logical_root_id,
                    &primary_node_id,
                )
            {
                root_target_node_ids.insert(route_owner_node_id);
            } else {
                root_target_node_ids.extend(matching_nodes);
            }
        }

        if root_target_node_ids.is_empty()
            && !worker_status_cache
            && !has_runtime_scope_evidence
            && let Some(domain_primary_node_id) =
                live_non_degraded_group_primary_domain_target_node_id_for_root(
                    domain_source,
                    root_id,
                )
        {
            root_target_node_ids.insert(domain_primary_node_id);
        }
        if root_target_node_ids.is_empty()
            && !worker_status_cache
            && !has_runtime_scope_evidence
            && let Some(domain_primary_node_id) =
                live_group_primary_domain_target_node_id_for_root(domain_source, root_id)
        {
            root_target_node_ids.insert(domain_primary_node_id);
        }

        root_target_node_ids.retain(|node_id| {
            source_node_has_live_group_primary_root_for_group(&source, root_id, node_id)
                || source_node_has_live_group_primary_root_for_group(
                    domain_source,
                    root_id,
                    node_id,
                )
                || source_node_has_published_origin_for_group(&source, root_id, node_id)
                || source_node_has_published_origin_for_group(domain_source, root_id, node_id)
        });

        if !root_target_node_ids.is_empty() {
            target_node_ids_by_root.insert(root_id.clone(), root_target_node_ids);
        }
    }

    target_node_ids_by_root
}

#[cfg(test)]
fn manual_rescan_source_primary_targets_cover_current_roots(
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
) -> bool {
    let target_node_ids_by_root =
        manual_rescan_source_primary_target_node_ids_by_root_from_runtime_scope(roots, source);
    roots
        .iter()
        .all(|root| target_node_ids_by_root.contains_key(&root.id))
}

fn source_observability_snapshot_is_worker_status_cache(
    source: &SourceObservabilitySnapshot,
) -> bool {
    source
        .status
        .degraded_roots
        .iter()
        .any(|(root_key, reason)| {
            root_key == SOURCE_WORKER_DEGRADED_ROOT_KEY
                && reason == SOURCE_WORKER_STATUS_CACHE_REASON
        })
}

fn manual_rescan_source_snapshot_ready_for_delivery(
    _expected_groups: &RootsPutSecondWaveExpectedGroups,
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
) -> bool {
    if source_observability_snapshot_is_degraded_worker_cache(source) {
        return false;
    }
    if source_observability_snapshot_is_worker_status_cache(source) {
        return false;
    }
    manual_rescan_target_node_ids_from_receivable_source_snapshot(roots, source).is_some()
}

fn manual_rescan_source_snapshot_ready_for_current_roots(
    expected_groups: &RootsPutSecondWaveExpectedGroups,
    roots: &[RootSpec],
    source: &SourceObservabilitySnapshot,
) -> bool {
    if source_observability_snapshot_is_degraded_worker_cache(source) {
        return false;
    }
    if source_observability_snapshot_is_worker_status_cache(source) {
        return false;
    }
    source_snapshot_declares_only_current_logical_roots(roots, source)
        && source_snapshot_has_current_root_health_evidence(roots, source)
        && roots_put_second_wave_source_runtime_scope_ready(expected_groups, source)
}

#[cfg(test)]
fn manual_rescan_readiness_from_source_snapshot(
    expected_groups: &RootsPutSecondWaveExpectedGroups,
    roots: &[RootSpec],
    source_snapshot: SourceObservabilitySnapshot,
) -> Option<SourceRuntimeScopeReadinessEvidence> {
    if manual_rescan_source_snapshot_ready_for_delivery(expected_groups, roots, &source_snapshot) {
        return Some(SourceRuntimeScopeReadinessEvidence::source(source_snapshot));
    }
    if manual_rescan_source_snapshot_ready_for_current_roots(
        expected_groups,
        roots,
        &source_snapshot,
    ) {
        return Some(SourceRuntimeScopeReadinessEvidence::source(source_snapshot));
    }
    None
}

fn manual_rescan_readiness_from_origin_fan_in_snapshot(
    expected_groups: &RootsPutSecondWaveExpectedGroups,
    roots: &[RootSpec],
    source_snapshot: SourceObservabilitySnapshot,
    target_node_ids: &BTreeSet<String>,
) -> Option<SourceRuntimeScopeReadinessEvidence> {
    if manual_rescan_source_snapshot_ready_for_current_roots(
        expected_groups,
        roots,
        &source_snapshot,
    ) {
        return Some(SourceRuntimeScopeReadinessEvidence::source(source_snapshot));
    }
    if target_node_ids.is_empty()
        && manual_rescan_source_snapshot_ready_for_delivery(
            expected_groups,
            roots,
            &source_snapshot,
        )
    {
        return Some(SourceRuntimeScopeReadinessEvidence::source(source_snapshot));
    }
    None
}

async fn manual_rescan_local_source_observation(
    source: std::sync::Arc<crate::workers::source::SourceFacade>,
    _runtime_boundary: Option<std::sync::Arc<dyn ChannelIoSubset>>,
    _node_id: NodeId,
    allow_local_current_root_observation: bool,
    budget: Option<Duration>,
) -> Option<SourceObservabilitySnapshot> {
    if !allow_local_current_root_observation {
        return None;
    }
    if source.is_worker() {
        let (snapshot, _used_cached_fallback) = source
            .source_state_pending_observability_snapshot_for_status_route()
            .await;
        return Some(snapshot);
    }
    let (snapshot, _used_cached_fallback) = source
        .observability_snapshot_nonblocking_for_status_route_with_timeout(budget)
        .await;
    Some(snapshot)
}

async fn wait_manual_rescan_current_roots_runtime_scope_readiness(
    state: &ApiState,
    roots: &[RootSpec],
    grants: &[GrantedMountRoot],
) -> Result<Option<BTreeSet<String>>, ApiError> {
    let context = roots_put_second_wave_context_with_current_generation(state).await?;
    if roots.is_empty() || !context.has_status_collection_boundary() {
        return Ok(None);
    }
    let source_status_probe_seed_node_ids =
        manual_rescan_source_status_probe_seed_node_ids_from_grants(roots, grants);
    let mut target_node_ids =
        derive_roots_put_control_target_node_ids_from_grants(&state.node_id, roots, grants);
    target_node_ids.extend(source_status_probe_seed_node_ids.iter().cloned());
    send_manual_rescan_current_roots_control_second_wave_once(&context, roots, &target_node_ids)
        .await?;
    let source = state.source.clone();
    let runtime_boundary = state.runtime_boundary.clone();
    let local_source_covers_current_roots =
        local_source_node_covers_current_roots(&state.node_id, roots, grants);
    let local_source_owns_current_root =
        local_source_node_owns_any_current_root(&state.node_id, roots, grants);
    let fast_source = source.clone();
    let fast_runtime_boundary = runtime_boundary.clone();
    let local_fast_observation = move |budget| {
        let source = fast_source.clone();
        let runtime_boundary = fast_runtime_boundary.clone();
        let node_id = state.node_id.clone();
        async move {
            manual_rescan_local_source_observation(
                source,
                runtime_boundary,
                node_id,
                local_source_covers_current_roots,
                budget,
            )
            .await
        }
    };
    let merge_source = source.clone();
    let merge_runtime_boundary = runtime_boundary.clone();
    let merge_expected_groups = roots_put_second_wave_expected_groups(roots);
    let merge_roots = roots.to_vec();
    let grant_runtime_scope_observation =
        manual_rescan_current_roots_runtime_scope_snapshot_from_active_grants(roots, grants);
    let local_merge_observation = move |budget| {
        let source = merge_source.clone();
        let runtime_boundary = merge_runtime_boundary.clone();
        let node_id = state.node_id.clone();
        let merge_expected_groups = merge_expected_groups.clone();
        let merge_roots = merge_roots.clone();
        let grant_runtime_scope_observation = grant_runtime_scope_observation.clone();
        async move {
            let local_observation = manual_rescan_local_source_observation(
                source,
                runtime_boundary,
                node_id,
                local_source_owns_current_root,
                budget,
            )
            .await;
            if local_observation.as_ref().is_some_and(|source| {
                manual_rescan_source_snapshot_ready_for_current_roots(
                    &merge_expected_groups,
                    &merge_roots,
                    source,
                ) || manual_rescan_source_snapshot_ready_for_delivery(
                    &merge_expected_groups,
                    &merge_roots,
                    source,
                )
            }) {
                return local_observation;
            }
            grant_runtime_scope_observation
        }
    };
    let readiness = wait_roots_put_second_wave_readiness_evidence_with_optional_local_source(
        &context,
        roots,
        target_node_ids,
        source_status_probe_seed_node_ids.clone(),
        true,
        false,
        local_fast_observation,
        local_merge_observation,
        RootsPutControlReplayPolicy::ObserveOnly,
        manual_rescan_source_status_request_payload(),
        local_source_covers_current_roots,
    )
    .await
    .map_err(|err| ApiError {
        status: err.status,
        message: format!(
            "manual rescan current roots runtime-scope readiness failed: {}",
            err.message
        ),
    })?;
    let Some(readiness) = readiness else {
        return Ok(None);
    };
    if let Some(target_node_ids) = readiness.manual_rescan_delivery_target_node_ids {
        return Ok(Some(target_node_ids));
    }
    let current_roots_source_snapshot = readiness.source_snapshot.clone();
    let mut source_snapshot = readiness.source_snapshot;
    let target_proof_deadline =
        tokio::time::Instant::now() + MANUAL_RESCAN_SOURCE_STATUS_ROUTE_TIMEOUT;
    let mut target_hint_node_ids = BTreeSet::<String>::new();
    let mut target_probe_node_ids = BTreeSet::<String>::new();
    let mut target_proof_origin_snapshots = BTreeMap::<String, SourceObservabilitySnapshot>::new();
    let mut direct_target_probe_attempted = false;

    loop {
        let remaining =
            target_proof_deadline.saturating_duration_since(tokio::time::Instant::now());
        if remaining.is_zero() {
            break;
        }
        let mut local_source_snapshot = None::<SourceObservabilitySnapshot>;
        target_hint_node_ids = manual_rescan_source_status_probe_hint_node_ids_from_runtime_scope(
            roots,
            &source_snapshot,
        );
        target_probe_node_ids = manual_rescan_source_status_probe_target_node_ids(
            roots,
            &source_snapshot,
            &source_status_probe_seed_node_ids,
        );
        if local_source_owns_current_root {
            local_source_snapshot = manual_rescan_local_source_observation(
                state.source.clone(),
                state.runtime_boundary.clone(),
                state.node_id.clone(),
                true,
                Some(remaining.min(MANUAL_RESCAN_SOURCE_STATUS_ROUTE_TIMEOUT)),
            )
            .await;
            if let Some(local_snapshot) = local_source_snapshot.clone() {
                source_snapshot = merge_manual_rescan_source_status_origin_snapshots(
                    roots,
                    &mut target_proof_origin_snapshots,
                    [(state.node_id.0.clone(), local_snapshot)],
                );
                if let Some(target_node_ids) =
                    manual_rescan_delivery_target_node_ids_from_accumulated_source_status(
                        roots,
                        &target_proof_origin_snapshots,
                    )
                {
                    return Ok(Some(target_node_ids));
                }
            }
        }
        if let Some(boundary) = context
            .query_runtime_boundary
            .clone()
            .or_else(|| context.runtime_boundary.clone())
        {
            direct_target_probe_attempted = true;
            let scoped_target_probe_node_ids = if local_source_snapshot.is_some() {
                target_probe_node_ids
                    .iter()
                    .filter(|node_id| !runtime_node_identity_matches(node_id, &state.node_id.0))
                    .cloned()
                    .collect::<BTreeSet<_>>()
            } else {
                target_probe_node_ids.clone()
            };
            if !scoped_target_probe_node_ids.is_empty() {
                let remaining =
                    target_proof_deadline.saturating_duration_since(tokio::time::Instant::now());
                if remaining.is_zero() {
                    break;
                }
                let scoped_probe_timeout = remaining.min(MANUAL_RESCAN_SOURCE_STATUS_ROUTE_TIMEOUT);
                let mut scoped_probes = FuturesUnordered::new();
                for node_id in scoped_target_probe_node_ids.iter().cloned() {
                    let boundary = boundary.clone();
                    let origin_id = state.node_id.clone();
                    scoped_probes.push(async move {
                        let result =
                            collect_node_scoped_manual_rescan_source_status_origin_snapshot(
                                boundary,
                                origin_id,
                                scoped_probe_timeout,
                                &node_id,
                            )
                            .await;
                        (node_id, result)
                    });
                }
                while let Some((node_id, result)) = scoped_probes.next().await {
                    match result {
                        Ok(origin_snapshots) => {
                            source_snapshot = merge_manual_rescan_source_status_origin_snapshots(
                                roots,
                                &mut target_proof_origin_snapshots,
                                origin_snapshots,
                            );
                            if let Some(target_node_ids) =
                                manual_rescan_delivery_target_node_ids_from_accumulated_source_status(
                                    roots,
                                    &target_proof_origin_snapshots,
                                )
                            {
                                return Ok(Some(target_node_ids));
                            }
                        }
                        Err(err) => {
                            eprintln!(
                                "fs_meta_api: manual rescan scoped source-status target probe failed node={node_id} err={err}"
                            );
                        }
                    }
                }
            }

            let remaining =
                target_proof_deadline.saturating_duration_since(tokio::time::Instant::now());
            if remaining.is_zero() {
                break;
            }
            match collect_manual_rescan_source_status_origin_snapshots(
                boundary.clone(),
                state.node_id.clone(),
                remaining.min(MANUAL_RESCAN_SOURCE_STATUS_ROUTE_TIMEOUT),
                STATUS_ROUTE_COLLECT_IDLE_GRACE,
            )
            .await
            {
                Ok(origin_snapshots) => {
                    let origin_snapshots =
                        filter_manual_rescan_source_status_origin_snapshots_to_probe_targets(
                            origin_snapshots,
                            &target_probe_node_ids,
                        );
                    if origin_snapshots.is_empty() {
                        tokio::time::sleep(ROOTS_PUT_SOURCE_SECOND_WAVE_POLL_INTERVAL).await;
                        continue;
                    }
                    source_snapshot = merge_manual_rescan_source_status_origin_snapshots(
                        roots,
                        &mut target_proof_origin_snapshots,
                        origin_snapshots,
                    );
                    if let Some(target_node_ids) =
                        manual_rescan_delivery_target_node_ids_from_accumulated_source_status(
                            roots,
                            &target_proof_origin_snapshots,
                        )
                    {
                        return Ok(Some(target_node_ids));
                    }
                }
                Err(err) => {
                    eprintln!(
                        "fs_meta_api: manual rescan source-status origin target probe failed err={err}"
                    );
                }
            }
        } else {
            break;
        }
        tokio::time::sleep(ROOTS_PUT_SOURCE_SECOND_WAVE_POLL_INTERVAL).await;
    }

    let expected_roots = roots
        .iter()
        .map(|root| root.id.clone())
        .collect::<BTreeSet<_>>();
    let probe_state = if direct_target_probe_attempted {
        "direct-source-status-probe-incomplete"
    } else {
        "direct-source-status-probe-unavailable"
    };
    let target_proof_by_root =
        manual_rescan_target_node_ids_by_root_from_source_status_origin_snapshots(
            roots,
            &accumulated_manual_rescan_source_status_origin_snapshots(
                &target_proof_origin_snapshots,
            ),
        );
    let target_proof_debug = manual_rescan_target_proof_debug_from_source_status_origin_snapshots(
        roots,
        &accumulated_manual_rescan_source_status_origin_snapshots(&target_proof_origin_snapshots),
    );
    eprintln!(
        "fs_meta_api: manual rescan source-status target proof incomplete; evaluating bounded scoped-delivery fallback after runtime-scope readiness: expected_roots={expected_roots:?} target_proof_by_root={target_proof_by_root:?} target_proof_debug={target_proof_debug:?} probe_targets={target_probe_node_ids:?} runtime_hints={target_hint_node_ids:?} probe_state={probe_state} last_source={}",
        summarize_source_status_route_snapshot(&source_snapshot)
    );
    let runtime_scope_scoped_targets =
        manual_rescan_scoped_delivery_targets_from_runtime_scope_after_preflight(
            roots,
            &source_snapshot,
        );
    if !runtime_scope_scoped_targets.is_empty() {
        eprintln!(
            "fs_meta_api: manual rescan source-status target proof incomplete; using runtime-scope scoped delivery targets instead of generic source route: targets={runtime_scope_scoped_targets:?}"
        );
        return Ok(Some(runtime_scope_scoped_targets));
    }
    let coverage_gaps = manual_rescan_runtime_scope_coverage_gaps_by_root(roots, &source_snapshot);
    let route_activation_gaps =
        manual_rescan_runtime_scope_route_activation_gaps_by_root(roots, &source_snapshot);
    let route_readiness_gaps =
        manual_rescan_runtime_scope_route_readiness_gaps_by_root(roots, &source_snapshot);
    let grant_derived_current_roots =
        source_snapshot.lifecycle_state == "grant_derived_current_roots";
    if manual_rescan_generic_fallback_allowed_with_current_roots_evidence(
        roots,
        &current_roots_source_snapshot,
        &source_snapshot,
        &coverage_gaps,
        &route_activation_gaps,
        &route_readiness_gaps,
    ) {
        eprintln!(
            "fs_meta_api: manual rescan source-status target proof incomplete; current roots are live but no complete scoped activation cover exists, using generic source route fallback: route_activation_gaps={route_activation_gaps:?}"
        );
        return Ok(None);
    }
    if grant_derived_current_roots
        || !coverage_gaps.is_empty()
        || !route_activation_gaps.is_empty()
        || !route_readiness_gaps.is_empty()
    {
        run_status_source_repair_recovery_if_needed(state, true).await;
        let generic_fallback_blocker =
            manual_rescan_generic_fallback_blocker_with_current_roots_evidence(
                roots,
                &current_roots_source_snapshot,
                &source_snapshot,
                &coverage_gaps,
                &route_activation_gaps,
                &route_readiness_gaps,
            );
        return Err(ApiError::service_unavailable(format!(
            "manual rescan source-status target proof incomplete: expected_roots={expected_roots:?} grant_derived_current_roots={grant_derived_current_roots} coverage_gaps={coverage_gaps:?} route_activation_gaps={route_activation_gaps:?} route_readiness_gaps={route_readiness_gaps:?} generic_fallback_blocker={generic_fallback_blocker} probe_targets={target_probe_node_ids:?} runtime_hints={target_hint_node_ids:?} probe_state={probe_state}"
        )));
    }
    Ok(None)
}

async fn collect_manual_rescan_requests(
    boundary: std::sync::Arc<dyn ChannelIoSubset>,
    origin_id: NodeId,
    payload: bytes::Bytes,
) -> Result<Vec<Event>, CnxError> {
    exchange_host_adapter(boundary, origin_id, default_route_bindings())
        .call_collect(
            ROUTE_TOKEN_FS_META_INTERNAL,
            METHOD_SOURCE_RESCAN,
            payload,
            MANUAL_RESCAN_ROUTE_TIMEOUT,
            MANUAL_RESCAN_ROUTE_IDLE_GRACE,
        )
        .await
}

#[cfg(test)]
async fn collect_scoped_manual_rescan_requests(
    boundary: std::sync::Arc<dyn ChannelIoSubset>,
    origin_id: NodeId,
    payload: bytes::Bytes,
    node_ids: &BTreeSet<String>,
) -> Result<BTreeMap<String, usize>, CnxError> {
    let mut deliveries = BTreeMap::new();
    let mut collections = FuturesUnordered::new();
    for node_id in node_ids {
        let boundary = boundary.clone();
        let origin_id = origin_id.clone();
        let payload = payload.clone();
        let node_id = node_id.clone();
        collections.push(async move {
            let delivery_count =
                collect_scoped_manual_rescan_request(boundary, origin_id, payload, &node_id).await;
            (node_id, delivery_count)
        });
    }
    while let Some((node_id, delivery_count)) = collections.next().await {
        let delivery_count = delivery_count
            .map_err(|err| manual_rescan_scoped_source_delivery_error(&node_id, err))?;
        if delivery_count == 0 {
            return Err(CnxError::Internal(format!(
                "manual rescan scoped source delivery missing for node {node_id}"
            )));
        }
        deliveries.insert(node_id, delivery_count);
    }
    Ok(deliveries)
}

async fn collect_scoped_manual_rescan_requests_until_converged(
    boundary: std::sync::Arc<dyn ChannelIoSubset>,
    origin_id: NodeId,
    payload: bytes::Bytes,
    node_ids: &BTreeSet<String>,
    convergence_timeout: Duration,
) -> Result<BTreeMap<String, usize>, CnxError> {
    let deadline = tokio::time::Instant::now() + convergence_timeout;
    let mut deliveries = BTreeMap::new();
    let mut pending_node_ids = node_ids.clone();
    let mut last_pending_err = None::<CnxError>;

    while !pending_node_ids.is_empty() {
        let remaining = deadline.saturating_duration_since(tokio::time::Instant::now());
        if remaining.is_zero() {
            return Err(last_pending_err.unwrap_or_else(|| {
                CnxError::NotReady(format!(
                    "manual rescan scoped source delivery pending for nodes {pending_node_ids:?}: operation timed out"
                ))
            }));
        }
        let attempt_timeout = remaining.min(MANUAL_RESCAN_ROUTE_TIMEOUT);
        let mut collections = FuturesUnordered::new();
        for node_id in pending_node_ids.iter().cloned() {
            let boundary = boundary.clone();
            let origin_id = origin_id.clone();
            let payload = payload.clone();
            collections.push(async move {
                let delivery_count = collect_scoped_manual_rescan_request_with_timeout(
                    boundary,
                    origin_id,
                    payload,
                    &node_id,
                    attempt_timeout,
                )
                .await;
                (node_id, delivery_count)
            });
        }

        let mut delivered_this_round = BTreeSet::new();
        while let Some((node_id, delivery_count)) = collections.next().await {
            match delivery_count {
                Ok(delivery_count) if delivery_count > 0 => {
                    deliveries.insert(node_id.clone(), delivery_count);
                    delivered_this_round.insert(node_id);
                }
                Ok(_) => {
                    return Err(CnxError::Internal(format!(
                        "manual rescan scoped source delivery missing for node {node_id}"
                    )));
                }
                Err(err) if manual_rescan_scoped_source_delivery_error_is_pending(&err) => {
                    last_pending_err =
                        Some(manual_rescan_scoped_source_delivery_error(&node_id, err));
                }
                Err(err) => {
                    return Err(manual_rescan_scoped_source_delivery_error(&node_id, err));
                }
            }
        }

        for node_id in delivered_this_round {
            pending_node_ids.remove(&node_id);
        }
        if !pending_node_ids.is_empty() {
            tokio::time::sleep(
                ROOTS_PUT_SOURCE_SECOND_WAVE_POLL_INTERVAL
                    .min(deadline.saturating_duration_since(tokio::time::Instant::now())),
            )
            .await;
        }
    }

    Ok(deliveries)
}

async fn manual_rescan_scoped_delivery_confirmed_by_source_status(
    state: &ApiState,
    roots: &[RootSpec],
    target_node_ids: &BTreeSet<String>,
    requested_at_us: u64,
) -> bool {
    if roots.is_empty() || target_node_ids.is_empty() {
        return false;
    }
    let deadline = tokio::time::Instant::now() + MANUAL_RESCAN_ROUTE_TIMEOUT;
    let mut origin_snapshots = Vec::<(String, SourceObservabilitySnapshot)>::new();

    if let Some(local_snapshot) = manual_rescan_local_source_observation(
        state.source.clone(),
        state.runtime_boundary.clone(),
        state.node_id.clone(),
        true,
        Some(MANUAL_RESCAN_ROUTE_TIMEOUT),
    )
    .await
    {
        origin_snapshots.push((state.node_id.0.clone(), local_snapshot));
        if manual_rescan_source_status_origin_snapshots_prove_recent_scoped_delivery(
            roots,
            target_node_ids,
            requested_at_us,
            &origin_snapshots,
        ) {
            return true;
        }
    }

    let Some(boundary) = state
        .query_runtime_boundary
        .clone()
        .or_else(|| state.runtime_boundary.clone())
    else {
        return false;
    };

    let mut scoped_probes = FuturesUnordered::new();
    for node_id in target_node_ids.iter().cloned() {
        let boundary = boundary.clone();
        let origin_id = state.node_id.clone();
        let remaining = deadline
            .saturating_duration_since(tokio::time::Instant::now())
            .min(MANUAL_RESCAN_ROUTE_TIMEOUT);
        if remaining.is_zero() {
            break;
        }
        scoped_probes.push(async move {
            collect_node_scoped_manual_rescan_source_status_origin_snapshot(
                boundary, origin_id, remaining, &node_id,
            )
            .await
        });
    }
    while let Some(result) = scoped_probes.next().await {
        if let Ok(mut snapshots) = result {
            origin_snapshots.append(&mut snapshots);
            if manual_rescan_source_status_origin_snapshots_prove_recent_scoped_delivery(
                roots,
                target_node_ids,
                requested_at_us,
                &origin_snapshots,
            ) {
                return true;
            }
        }
    }

    let remaining = deadline.saturating_duration_since(tokio::time::Instant::now());
    if remaining.is_zero() {
        return false;
    }
    if let Ok(mut snapshots) = collect_manual_rescan_source_status_origin_snapshots(
        boundary,
        state.node_id.clone(),
        remaining.min(MANUAL_RESCAN_ROUTE_TIMEOUT),
        STATUS_ROUTE_COLLECT_IDLE_GRACE,
    )
    .await
    {
        origin_snapshots.append(&mut snapshots);
    }

    manual_rescan_source_status_origin_snapshots_prove_recent_scoped_delivery(
        roots,
        target_node_ids,
        requested_at_us,
        &origin_snapshots,
    )
}

fn manual_rescan_source_status_origin_snapshots_prove_recent_scoped_delivery(
    roots: &[RootSpec],
    target_node_ids: &BTreeSet<String>,
    requested_at_us: u64,
    origin_snapshots: &[(String, SourceObservabilitySnapshot)],
) -> bool {
    if origin_snapshots.is_empty() {
        return false;
    }
    let merged = merge_source_observability_snapshots(
        origin_snapshots
            .iter()
            .map(|(_, snapshot)| snapshot.clone())
            .collect(),
    );
    manual_rescan_source_status_snapshot_proves_recent_scoped_delivery(
        roots,
        target_node_ids,
        requested_at_us,
        &merged,
    )
}

fn manual_rescan_source_status_snapshot_proves_recent_scoped_delivery(
    roots: &[RootSpec],
    target_node_ids: &BTreeSet<String>,
    requested_at_us: u64,
    source: &SourceObservabilitySnapshot,
) -> bool {
    if source_observability_snapshot_is_degraded_worker_cache(source)
        || source_observability_snapshot_is_worker_status_cache(source)
        || !source_snapshot_declares_only_current_logical_roots(roots, source)
    {
        return false;
    }
    let request_floor_us = requested_at_us.saturating_sub(
        MANUAL_RESCAN_ROUTE_TIMEOUT
            .as_micros()
            .min(u128::from(u64::MAX)) as u64,
    );
    let scan_roots = roots.iter().filter(|root| root.scan).collect::<Vec<_>>();
    if scan_roots.is_empty() {
        return false;
    }
    scan_roots.iter().all(|root| {
        source.status.concrete_roots.iter().any(|concrete_root| {
            manual_rescan_concrete_root_proves_recent_scoped_delivery(
                source,
                &root.id,
                concrete_root,
                target_node_ids,
                request_floor_us,
            )
        })
    })
}

fn manual_rescan_concrete_root_proves_recent_scoped_delivery(
    source: &SourceObservabilitySnapshot,
    root_id: &str,
    concrete_root: &SourceConcreteRootHealthSnapshot,
    target_node_ids: &BTreeSet<String>,
    request_floor_us: u64,
) -> bool {
    if concrete_root.logical_root_id != root_id
        || !concrete_root.active
        || !concrete_root.is_group_primary
        || !concrete_root.scan_enabled
        || !source_concrete_root_allows_domain_target(concrete_root)
        || concrete_root.last_rescan_reason.as_deref() != Some("manual")
        || !concrete_root
            .last_rescan_requested_at_us
            .is_some_and(|requested_at_us| requested_at_us >= request_floor_us)
    {
        return false;
    }
    let Some(primary_node_id) =
        source_primary_runtime_node_id_from_ref(&concrete_root.object_ref, &source.grants)
    else {
        return false;
    };
    target_node_ids
        .iter()
        .any(|target_node_id| runtime_node_identity_matches(target_node_id, &primary_node_id))
}

#[cfg(test)]
async fn collect_scoped_manual_rescan_request(
    boundary: std::sync::Arc<dyn ChannelIoSubset>,
    origin_id: NodeId,
    payload: bytes::Bytes,
    node_id: &str,
) -> Result<usize, CnxError> {
    collect_scoped_manual_rescan_request_with_timeout(
        boundary,
        origin_id,
        payload,
        node_id,
        MANUAL_RESCAN_ROUTE_TIMEOUT,
    )
    .await
}

async fn collect_scoped_manual_rescan_request_with_timeout(
    boundary: std::sync::Arc<dyn ChannelIoSubset>,
    origin_id: NodeId,
    payload: bytes::Bytes,
    node_id: &str,
    delivery_timeout: Duration,
) -> Result<usize, CnxError> {
    let adapter = exchange_host_adapter(
        boundary,
        origin_id,
        source_rescan_route_bindings_for(node_id),
    );
    let deadline = tokio::time::Instant::now() + delivery_timeout;
    loop {
        let remaining = deadline.saturating_duration_since(tokio::time::Instant::now());
        if remaining.is_zero() {
            return Err(CnxError::Timeout);
        }
        let route = adapter.bound_route(ROUTE_TOKEN_FS_META_INTERNAL, METHOD_SOURCE_RESCAN)?;
        let collect_result = route
            .call_collect_until(
                payload.clone(),
                scoped_manual_rescan_delivery_attempt_timeout(remaining),
                scoped_manual_rescan_delivery_idle_after_first_timeout(remaining),
                manual_rescan_scoped_source_delivery_has_terminal_target_evidence,
            )
            .await;
        route.close();
        let events = match collect_result {
            Ok(events) => events,
            Err(CnxError::Timeout) => {
                continue;
            }
            Err(err) => return Err(err),
        };

        let mut target_count = 0;
        let mut target_pending = None::<String>;
        let mut target_rejected = None::<String>;
        let mut saw_scoped_evidence = false;
        for event in events {
            saw_scoped_evidence = true;
            if event.payload_bytes() == b"not-target" {
                continue;
            }
            if event.payload_bytes() == b"accepted" {
                target_count += 1;
            } else if manual_rescan_scoped_source_delivery_pending_payload(event.payload_bytes()) {
                target_pending.get_or_insert_with(|| {
                    String::from_utf8_lossy(event.payload_bytes()).into_owned()
                });
            } else {
                target_rejected.get_or_insert_with(|| {
                    String::from_utf8_lossy(event.payload_bytes()).into_owned()
                });
            }
        }
        if target_count > 0 {
            return Ok(target_count);
        }
        if let Some(message) = target_pending {
            return Err(CnxError::NotReady(format!(
                "manual rescan scoped source delivery pending for node {node_id}: {message}"
            )));
        }
        if let Some(message) = target_rejected {
            if manual_rescan_scoped_source_delivery_not_local_source_primary_payload(
                message.as_bytes(),
            ) {
                return Err(CnxError::NotReady(format!(
                    "manual rescan scoped source delivery pending for node {node_id}: {message}"
                )));
            }
            return Err(CnxError::Internal(format!(
                "manual rescan scoped source delivery rejected for node {node_id}: {message}"
            )));
        }
        if !saw_scoped_evidence {
            continue;
        }
    }
}

fn manual_rescan_scoped_source_delivery_has_terminal_target_evidence(events: &[Event]) -> bool {
    events.iter().any(|event| {
        let payload = event.payload_bytes();
        payload == b"accepted"
            || manual_rescan_scoped_source_delivery_pending_payload(payload)
            || (payload != b"not-target")
    })
}

fn manual_rescan_scoped_source_delivery_error_is_pending(err: &CnxError) -> bool {
    matches!(err, CnxError::Timeout | CnxError::NotReady(_))
}

fn scoped_manual_rescan_delivery_attempt_timeout(remaining: Duration) -> Duration {
    remaining.min(MANUAL_RESCAN_ROUTE_TIMEOUT)
}

fn scoped_manual_rescan_delivery_idle_after_first_timeout(remaining: Duration) -> Duration {
    scoped_manual_rescan_delivery_attempt_timeout(remaining)
}

fn manual_rescan_scoped_source_delivery_error(node_id: &str, err: CnxError) -> CnxError {
    match err {
        CnxError::Timeout => CnxError::NotReady(format!(
            "manual rescan scoped source delivery pending for node {node_id}: operation timed out"
        )),
        CnxError::NotReady(message) => CnxError::NotReady(format!(
            "manual rescan scoped source delivery pending for node {node_id}: {message}"
        )),
        err => CnxError::Internal(format!(
            "manual rescan scoped source delivery failed for node {node_id}: {err}"
        )),
    }
}

fn manual_rescan_scoped_source_route_api_error(err: CnxError) -> ApiError {
    match err {
        CnxError::NotReady(message) => ApiError::service_unavailable(format!(
            "manual rescan scoped source route pending: {message}"
        )),
        CnxError::Timeout => ApiError::service_unavailable(
            "manual rescan scoped source route pending: operation timed out",
        ),
        err => ApiError::internal(format!("manual rescan scoped source route failed: {err}")),
    }
}

fn manual_rescan_generic_source_route_api_error(err: CnxError) -> ApiError {
    match err {
        CnxError::Timeout => ApiError::service_unavailable(
            "manual rescan generic source route pending: operation timed out",
        ),
        CnxError::NotReady(message) => ApiError::service_unavailable(format!(
            "manual rescan generic source route pending: {message}"
        )),
        err => ApiError::internal(format!("manual rescan generic source route failed: {err}")),
    }
}

fn manual_rescan_scoped_source_delivery_pending_payload(payload: &[u8]) -> bool {
    if payload.starts_with(b"pending:") {
        return true;
    }
    let message = String::from_utf8_lossy(payload);
    message.contains("resource exhausted")
        && (message.contains("source worker unavailable") || message.contains("max channels"))
}

fn manual_rescan_scoped_source_delivery_not_local_source_primary_payload(payload: &[u8]) -> bool {
    let message = String::from_utf8_lossy(payload);
    message.contains("scoped source-rescan target has no local scheduled scan root")
}

