    #[async_trait::async_trait]
    impl ChannelIoSubset for DeniedControlRouteBoundary {
        async fn channel_send(
            &self,
            ctx: BoundaryContext,
            request: ChannelSendRequest,
        ) -> capanix_app_sdk::Result<()> {
            let route = request.channel_key.0.clone();
            let mut sent = match self.sent_routes.lock() {
                Ok(guard) => guard,
                Err(poisoned) => poisoned.into_inner(),
            };
            sent.push(route.clone());
            drop(sent);
            let mut sent_unit_ids = match self.sent_unit_ids.lock() {
                Ok(guard) => guard,
                Err(poisoned) => poisoned.into_inner(),
            };
            sent_unit_ids.push(ctx.unit_id.clone());
            drop(sent_unit_ids);
            if self.denied_routes.contains(&route) {
                return Err(CnxError::AccessDenied(
                    "pid Pid(4) is drained/fenced and cannot obtain new grant attachments".into(),
                ));
            }
            Ok(())
        }
    }

    #[async_trait::async_trait]
    impl ChannelIoSubset for ManualRescanRouteBoundary {
        async fn channel_send(
            &self,
            _ctx: BoundaryContext,
            request: ChannelSendRequest,
        ) -> capanix_app_sdk::Result<()> {
            let route = request.channel_key.0.clone();
            let mut sent = self
                .sent_routes
                .lock()
                .expect("manual rescan sent routes lock");
            sent.push(route.clone());
            drop(sent);
            if self.denied_routes.contains(&route) {
                return Err(CnxError::AccessDenied(
                    "pid Pid(4) is drained/fenced and cannot obtain new grant attachments".into(),
                ));
            }
            if let Some(correlation) = request
                .events
                .first()
                .and_then(|event| event.metadata().correlation_id)
            {
                self.correlations_by_channel
                    .lock()
                    .expect("manual rescan correlations lock")
                    .insert(route, correlation);
                *self
                    .last_correlation
                    .lock()
                    .expect("manual rescan correlation lock") = Some(correlation);
                *self
                    .reply_sent
                    .lock()
                    .expect("manual rescan reply state lock") = false;
            }
            Ok(())
        }

        async fn channel_recv(
            &self,
            _ctx: BoundaryContext,
            request: capanix_runtime_entry_sdk::advanced::boundary::ChannelRecvRequest,
        ) -> capanix_app_sdk::Result<Vec<Event>> {
            let request_channel = request
                .channel_key
                .0
                .strip_suffix(":reply")
                .unwrap_or(request.channel_key.0.as_str());
            if request_channel.contains("source-status") {
                let Some(snapshot) = self.source_status_snapshot.clone() else {
                    return Err(CnxError::Timeout);
                };
                let correlation = self
                    .correlations_by_channel
                    .lock()
                    .expect("manual rescan correlations lock")
                    .get(request_channel)
                    .copied()
                    .or(*self
                        .last_correlation
                        .lock()
                        .expect("manual rescan correlation lock"));
                let Some(correlation) = correlation else {
                    return Err(CnxError::Timeout);
                };
                return Ok(vec![source_status_event("node-a", correlation, snapshot)]);
            }

            let correlation = self
                .correlations_by_channel
                .lock()
                .expect("manual rescan correlations lock")
                .get(request_channel)
                .copied()
                .or(*self
                    .last_correlation
                    .lock()
                    .expect("manual rescan correlation lock"));
            let Some(correlation) = correlation else {
                return Err(CnxError::Timeout);
            };

            let mut reply_sent = self
                .reply_sent
                .lock()
                .expect("manual rescan reply state lock");
            if *reply_sent {
                return Err(CnxError::Timeout);
            }
            *reply_sent = true;
            Ok(vec![Event::new(
                EventMetadata {
                    origin_id: NodeId("node-a".into()),
                    timestamp_us: 0,
                    logical_ts: None,
                    correlation_id: Some(correlation),
                    ingress_auth: None,
                    trace: None,
                },
                bytes::Bytes::from_static(b"accepted"),
            )])
        }
    }

