    impl ChannelIoSubset for DelayedSourceStatusCollectBoundary {
        async fn channel_send(
            &self,
            _ctx: BoundaryContext,
            request: ChannelSendRequest,
        ) -> capanix_app_sdk::Result<()> {
            let correlation = request
                .events
                .first()
                .and_then(|event| event.metadata().correlation_id);
            let mut sent = self
                .sent_correlation
                .lock()
                .expect("delayed source-status sent correlation lock");
            *sent = correlation;
            self.correlation_notify.notify_waiters();
            Ok(())
        }

        async fn channel_recv(
            &self,
            _ctx: BoundaryContext,
            request: capanix_runtime_entry_sdk::advanced::boundary::ChannelRecvRequest,
        ) -> capanix_app_sdk::Result<Vec<Event>> {
            if request.channel_key.0 != self.reply_channel {
                return Err(CnxError::Timeout);
            }
            let correlation = wait_for_manual_rescan_test_correlation(
                &self.sent_correlation,
                &self.correlation_notify,
                "delayed source-status sent correlation lock",
            )
            .await;
            match self
                .recv_count
                .fetch_add(1, std::sync::atomic::Ordering::SeqCst)
            {
                0 => Ok(vec![source_status_event(
                    "node-d-29775487306465848395300865",
                    correlation,
                    self.fast_snapshot.clone(),
                )]),
                1 => {
                    let timeout = request
                        .timeout_ms
                        .map(Duration::from_millis)
                        .unwrap_or(self.delayed_reply_delay);
                    if self.delayed_reply_delay > timeout {
                        tokio::time::sleep(timeout).await;
                        return Err(CnxError::Timeout);
                    }
                    tokio::time::sleep(self.delayed_reply_delay).await;
                    Ok(vec![source_status_event(
                        "node-b-29775487306465848395300865",
                        correlation,
                        self.delayed_snapshot.clone(),
                    )])
                }
                _ => Err(CnxError::Timeout),
            }
        }
    }

    #[async_trait::async_trait]
    impl ChannelIoSubset for RoutedSourceStatusCollectBoundary {
        async fn channel_send(
            &self,
            ctx: BoundaryContext,
            request: ChannelSendRequest,
        ) -> capanix_app_sdk::Result<()> {
            if request.channel_key.0 != self.request_channel {
                return Ok(());
            }
            self.sent_unit_ids
                .lock()
                .expect("unit scoped source-status sent unit ids lock")
                .push(ctx.unit_id.clone());
            let correlation = request
                .events
                .first()
                .and_then(|event| event.metadata().correlation_id)
                .unwrap_or(1);
            let mut replies = self.replies.lock().await;
            match ctx.unit_id.as_deref() {
                // Routed collection via BoundRoute::call_collect uses default context and must
                // reach all active peer handlers, including query-peer-owned peers.
                None => {
                    replies.push(vec![
                        source_status_event(
                            "node-b-29775547640557521931862017",
                            correlation,
                            SourceObservabilitySnapshot {
                                scheduled_source_groups_by_node: BTreeMap::from([(
                                    "node-b".to_string(),
                                    vec!["nfs1".to_string(), "nfs2".to_string()],
                                )]),
                                scheduled_scan_groups_by_node: BTreeMap::from([(
                                    "node-b".to_string(),
                                    vec!["nfs1".to_string(), "nfs2".to_string()],
                                )]),
                                ..local_source_snapshot()
                            },
                        ),
                        source_status_event(
                            "node-c-29775547640557521931862017",
                            correlation,
                            SourceObservabilitySnapshot {
                                scheduled_source_groups_by_node: BTreeMap::from([(
                                    "node-c".to_string(),
                                    vec!["nfs1".to_string(), "nfs2".to_string()],
                                )]),
                                scheduled_scan_groups_by_node: BTreeMap::from([(
                                    "node-c".to_string(),
                                    vec!["nfs1".to_string(), "nfs2".to_string()],
                                )]),
                                ..local_source_snapshot()
                            },
                        ),
                        source_status_event(
                            "node-d-29775547640557521931862017",
                            correlation,
                            SourceObservabilitySnapshot {
                                scheduled_source_groups_by_node: BTreeMap::from([(
                                    "node-d".to_string(),
                                    vec!["nfs2".to_string()],
                                )]),
                                scheduled_scan_groups_by_node: BTreeMap::from([(
                                    "node-d".to_string(),
                                    vec!["nfs2".to_string()],
                                )]),
                                ..local_source_snapshot()
                            },
                        ),
                    ]);
                }
                // The current broken direct collector path uses unit-scoped raw boundary sends,
                // which in preserved exact evidence only yields the mixed local/query owner.
                Some(execution_units::QUERY_RUNTIME_UNIT_ID)
                | Some(execution_units::QUERY_PEER_RUNTIME_UNIT_ID) => {
                    replies.push(vec![source_status_event(
                        "node-d-29775547640557521931862017",
                        correlation,
                        SourceObservabilitySnapshot {
                            scheduled_source_groups_by_node: BTreeMap::from([(
                                "node-d".to_string(),
                                vec!["nfs2".to_string()],
                            )]),
                            scheduled_scan_groups_by_node: BTreeMap::from([(
                                "node-d".to_string(),
                                vec!["nfs2".to_string()],
                            )]),
                            ..local_source_snapshot()
                        },
                    )]);
                }
                _ => {}
            }
            Ok(())
        }

        async fn channel_recv(
            &self,
            ctx: BoundaryContext,
            request: capanix_runtime_entry_sdk::advanced::boundary::ChannelRecvRequest,
        ) -> capanix_app_sdk::Result<Vec<Event>> {
            if request.channel_key.0 != self.reply_channel {
                return Err(CnxError::Timeout);
            }
            self.recv_unit_ids
                .lock()
                .expect("routed source-status recv unit ids lock")
                .push(ctx.unit_id.clone());
            let mut replies = self.replies.lock().await;
            if replies.is_empty() {
                return Err(CnxError::Timeout);
            }
            Ok(replies.remove(0))
        }
    }

    #[async_trait::async_trait]
    impl ChannelIoSubset for NodeScopedSourceStatusCollectBoundary {
        async fn channel_send(
            &self,
            _ctx: BoundaryContext,
            request: ChannelSendRequest,
        ) -> capanix_app_sdk::Result<()> {
            let route = request.channel_key.0.clone();
            self.sent_routes
                .lock()
                .expect("node scoped source-status sent routes lock")
                .push(route.clone());
            if self.snapshots_by_request_channel.contains_key(&route)
                && let Some(correlation) = request
                    .events
                    .first()
                    .and_then(|event| event.metadata().correlation_id)
            {
                self.correlations_by_channel
                    .lock()
                    .expect("node scoped source-status correlations lock")
                    .insert(route, correlation);
                self.correlation_notify.notify_waiters();
            }
            Ok(())
        }

        async fn channel_recv(
            &self,
            _ctx: BoundaryContext,
            request: capanix_runtime_entry_sdk::advanced::boundary::ChannelRecvRequest,
        ) -> capanix_app_sdk::Result<Vec<Event>> {
            let reply_channel = request.channel_key.0;
            let request_channel = reply_channel
                .strip_suffix(":reply")
                .unwrap_or(reply_channel.as_str())
                .to_string();
            if !self
                .snapshots_by_request_channel
                .contains_key(&request_channel)
            {
                return Err(CnxError::Timeout);
            }
            let correlation = self
                .wait_for_source_status_correlation(&request_channel)
                .await;
            let first_recv = {
                let mut recv_batches = self
                    .recv_batches_by_channel
                    .lock()
                    .expect("node scoped source-status recv batches lock");
                let recv_count = recv_batches.entry(reply_channel).or_default();
                *recv_count += 1;
                *recv_count == 1
            };
            if !first_recv {
                return Err(CnxError::Timeout);
            }
            let (origin, snapshot) = self
                .snapshots_by_request_channel
                .get(&request_channel)
                .expect("node scoped source-status snapshot")
                .clone();
            Ok(vec![source_status_event(&origin, correlation, snapshot)])
        }
    }

